    19→## Sprint Backlog
    20→
    21→### Epic: ForgeRouter Service Architecture
    22→**Story Points: 8**
    23→
    24→#### SRV-001: Build ForgeRouter Service
    25→**Points: 5 | Priority: Critical**
    26→
    27→**Description:** Create the core service that handles participant routing, session assignment, and experiment launching.
    28→
    29→**Technical Requirements:**
    30→- Fastify-based microservice with high performance routing
    31→- JWT-based session token generation and validation
    32→- Participant ID management and session tracking
    33→- Integration with recruitment providers
    34→- Comprehensive logging and monitoring
    35→
    36→**Acceptance Criteria:**
    37→- [ ] Service handles participant URLs from recruitment platforms
    38→- [ ] Session assignment atomic and collision-free
    39→- [ ] JWT tokens generated with appropriate claims and expiration
    40→- [ ] Participant routing works with query parameters from different providers
    41→- [ ] Service scales to handle 1000+ concurrent participant assignments
    42→- [ ] Comprehensive API documentation and monitoring
    43→
    44→**ForgeRouter Implementation:**
    45→```typescript
    46→// @psyforge/forge-router
    47→import Fastify from 'fastify';
    48→import jwt from '@fastify/jwt';
    49→import { DatabaseManager } from './database';
    50→import { ExperimentAssigner } from './assignment';
    51→
    52→export class ForgeRouter {
    53→  private server: Fastify.FastifyInstance;
    54→  private db: DatabaseManager;
    55→  private assigner: ExperimentAssigner;
    56→
    57→  constructor() {
    58→    this.server = Fastify({ logger: true });
    59→    this.setupRoutes();
    60→    this.setupMiddleware();
    61→  }
    62→
    63→  private setupRoutes(): void {
    64→    // Main participant entry point
    65→    this.server.get('/router/:studyId', this.handleParticipantEntry.bind(this));
    66→    
    67→    // Health check and status endpoints
    68→    this.server.get('/health', this.healthCheck.bind(this));
    69→    this.server.get('/status/:sessionId', this.getSessionStatus.bind(this));
    70→  }
    71→
    72→  async handleParticipantEntry(request: FastifyRequest, reply: FastifyReply) {
    73→    const { studyId } = request.params;
    74→    const providerParams = request.query; // PROLIFIC_PID, MTURK_ID, etc.
    75→    
    76→    try {
    77→      // Start database transaction for atomic assignment
    78→      await this.db.transaction(async (tx) => {
    79→        // Load study configuration
    80→        const study = await this.loadStudy(studyId, tx);
    81→        
    82→        // Execute assignment logic (counter, latin square, etc.)
    83→        const assignment = await this.assigner.assignCondition(
    84→          study, 
    85→          providerParams, 
    86→          tx
    87→        );
    88→        
    89→        // Generate session JWT
    90→        const sessionToken = await this.generateSessionToken({
    91→          participantId: assignment.participantId,
    92→          studyId: studyId,
    93→          studyVersion: study.version,
    94→          conditionLevels: assignment.conditions,
    95→          provider: this.detectProvider(providerParams),
    96→          assignedAt: new Date().toISOString()
    97→        });
    98→        
    99→        // Redirect to experiment runner
   100→        const runnerUrl = `${study.runnerBaseUrl}?session=${sessionToken}`;
   101→        reply.redirect(302, runnerUrl);
   102→      });
   103→      
   104→    } catch (error) {
   105→      this.handleRoutingError(error, reply);
   106→    }
   107→  }
   108→
   109→  private async generateSessionToken(claims: SessionClaims): Promise<string> {
   110→    return this.server.jwt.sign(claims, {
   111→      expiresIn: '24h', // Reasonable time for experiment completion
   112→      issuer: 'psyforge-router',
   113→      audience: 'psyforge-runner'
   114→    });
   115→  }
   116→}
   117→
   118→export interface SessionClaims {
   119→  participantId: string;
   120→  studyId: string;
   121→  studyVersion: string;
   122→  conditionLevels: Record<string, any>;
   123→  provider: 'prolific' | 'mturk' | 'sona' | 'direct';
   124→  assignedAt: string;
   125→}
   126→```
   127→
   128→#### SRV-002: Global State DB & Transactional Logic
   129→**Points: 3 | Priority: Critical**
   130→
   131→**Description:** Implement database layer with ACID transactions for condition assignment and global counters.
   132→
   133→**Technical Requirements:**
   134→- PostgreSQL with SERIALIZABLE isolation level for critical sections
   135→- Global counter management with atomic increment operations
   136→- Study configuration storage and versioning
   137→- Participant session tracking and deduplication
   138→- Database migration and backup strategies
   139→
   140→**Acceptance Criteria:**
   141→- [ ] Counter increments are atomic and collision-free under load
   142→- [ ] Study configurations versioned and immutable once published
   143→- [ ] Participant deduplication prevents double-enrollment
   144→- [ ] Database transactions handle concurrent assignment requests
   145→- [ ] Migration system supports schema evolution
   146→- [ ] Backup and recovery procedures documented and tested
   147→
   148→**Database Schema:**
   149→```sql
   150→-- Studies and their configurations
   151→CREATE TABLE studies (
   152→  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
   153→  name VARCHAR(255) NOT NULL,
   154→  version VARCHAR(50) NOT NULL,
   155→  fzb_spec JSONB NOT NULL, -- Compiled experiment specification
   156→  assignment_rules JSONB NOT NULL, -- counter(), latinSquare(), etc.
   157→  recruitment_config JSONB,
   158→  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
   159→  published_at TIMESTAMP WITH TIME ZONE,
   160→  archived_at TIMESTAMP WITH TIME ZONE,
   161→  
   162→  UNIQUE(name, version)
   163→);
   164→
   165→-- Global counters for condition assignment
   166→CREATE TABLE global_counters (
   167→  study_id UUID REFERENCES studies(id),
   168→  counter_name VARCHAR(100),
   169→  current_value INTEGER DEFAULT 0,
   170→  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
   171→  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
   172→  
   173→  PRIMARY KEY(study_id, counter_name)
   174→);
   175→
   176→-- Participant sessions and assignments
   177→CREATE TABLE participant_sessions (
   178→  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
   179→  study_id UUID REFERENCES studies(id),
   180→  participant_id VARCHAR(255) NOT NULL, -- From provider (PROLIFIC_PID, etc.)
   181→  provider VARCHAR(50) NOT NULL,
   182→  condition_assignment JSONB NOT NULL,
   183→  session_token_hash VARCHAR(255),
   184→  status VARCHAR(50) DEFAULT 'assigned', -- assigned, started, completed, expired
   185→  assigned_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
   186→  started_at TIMESTAMP WITH TIME ZONE,
   187→  completed_at TIMESTAMP WITH TIME ZONE,
   188→  
   189→  UNIQUE(study_id, participant_id, provider) -- Prevent double enrollment
   190→);
   191→
   192→-- Atomic counter increment function
   193→CREATE OR REPLACE FUNCTION increment_counter(
   194→  p_study_id UUID,
   195→  p_counter_name VARCHAR(100)
   196→) RETURNS INTEGER AS $$
   197→DECLARE
   198→  new_value INTEGER;
   199→BEGIN
   200→  INSERT INTO global_counters (study_id, counter_name, current_value)
   201→  VALUES (p_study_id, p_counter_name, 1)
   202→  ON CONFLICT (study_id, counter_name)
   203→  DO UPDATE SET 
   204→    current_value = global_counters.current_value + 1,
   205→    updated_at = NOW()
   206→  RETURNING current_value INTO new_value;
   207→  
   208→  RETURN new_value;
   209→END;
   210→$$ LANGUAGE plpgsql;
   211→```
