   410→### Epic: Authentication & Security
   411→**Story Points: 6**
   412→
   413→#### SEC-001: OAuth2 PKCE Flow (Studio ↔ Keycloak)
   414→**Points: 4 | Priority: High**
   415→
   416→**Description:** Implement secure authentication flow for researcher access to Forge Studio.
   417→
   418→**Technical Requirements:**
   419→- OAuth2 Authorization Code flow with PKCE for security
   420→- Keycloak integration for identity management
   421→- JWT token handling with automatic refresh
   422→- Role-based access control (admin, researcher, viewer)
   423→- Multi-factor authentication support
   424→
   425→**Acceptance Criteria:**
   426→- [ ] OAuth2 PKCE flow implemented correctly and securely
   427→- [ ] Keycloak integration handles user authentication
   428→- [ ] JWT tokens automatically refreshed before expiration
   429→- [ ] Role-based permissions control access to features
   430→- [ ] MFA supported for enhanced security
   431→- [ ] Security audit passes all authentication tests
   432→
   433→**Authentication Implementation:**
   434→```typescript
   435→// @psyforge/auth
   436→export class AuthenticationManager {
   437→  private keycloakClient: KeycloakClient;
   438→  private tokenManager: TokenManager;
   439→  
   440→  constructor(config: AuthConfig) {
   441→    this.keycloakClient = new KeycloakClient(config.keycloak);
   442→    this.tokenManager = new TokenManager();
   443→  }
   444→  
   445→  // Initialize OAuth2 PKCE flow
   446→  async initiateLogin(): Promise<AuthorizationUrl> {
   447→    const codeVerifier = this.generateCodeVerifier();
   448→    const codeChallenge = await this.generateCodeChallenge(codeVerifier);
   449→    
   450→    // Store PKCE parameters
   451→    this.tokenManager.storePKCEParams(codeVerifier);
   452→    
   453→    const authUrl = this.keycloakClient.getAuthorizationUrl({
   454→      client_id: 'psyforge-studio',
   455→      redirect_uri: `${window.location.origin}/auth/callback`,
   456→      scope: 'openid profile email',
   457→      response_type: 'code',
   458→      code_challenge: codeChallenge,
   459→      code_challenge_method: 'S256'
   460→    });
   461→    
   462→    return authUrl;
   463→  }
   464→  
   465→  // Handle OAuth callback
   466→  async handleCallback(authorizationCode: string): Promise<AuthenticationResult> {
   467→    const codeVerifier = this.tokenManager.getPKCEVerifier();
   468→    
   469→    const tokens = await this.keycloakClient.exchangeCodeForTokens({
   470→      code: authorizationCode,
   471→      code_verifier: codeVerifier,
   472→      client_id: 'psyforge-studio',
   473→      redirect_uri: `${window.location.origin}/auth/callback`
   474→    });
   475→    
   476→    // Validate and store tokens
   477→    const userInfo = await this.validateTokens(tokens);
   478→    this.tokenManager.storeTokens(tokens);
   479→    
   480→    return {
   481→      user: userInfo,
   482→      permissions: this.extractPermissions(tokens.access_token),
   483→      expiresAt: tokens.expires_at
   484→    };
   485→  }
   486→  
   487→  // Automatic token refresh
   488→  async refreshTokensIfNeeded(): Promise<boolean> {
   489→    if (!this.tokenManager.needsRefresh()) {
   490→      return false;
   491→    }
   492→    
   493→    try {
   494→      const refreshToken = this.tokenManager.getRefreshToken();
   495→      const newTokens = await this.keycloakClient.refreshTokens(refreshToken);
   496→      
   497→      this.tokenManager.storeTokens(newTokens);
   498→      return true;
   499→    } catch (error) {
   500→      // Refresh failed, require re-authentication
   501→      this.tokenManager.clearTokens();
   502→      throw new AuthenticationRequiredError();
   503→    }
   504→  }
   505→}
   506→
   507→// Role-based access control
   508→export interface UserPermissions {
   509→  canCreateExperiments: boolean;
   510→  canPublishExperiments: boolean;
   511→  canAccessAnalytics: boolean;
   512→  canManageUsers: boolean;
   513→  maxParticipants: number;
   514→  allowedProviders: string[];
   515→}
   516→
   517→export function hasPermission(user: AuthenticatedUser, permission: keyof UserPermissions): boolean {
   518→  return user.permissions[permission] === true;
   519→}
   520→```
