import { z } from 'zod';

// Session claims stored in JWT
export const SessionClaimsSchema = z.object({
  participantId: z.string(),
  studyId: z.string(),
  studyVersion: z.string(),
  conditionLevels: z.record(z.any()),
  provider: z.enum(['prolific', 'mturk', 'sona', 'direct']),
  assignedAt: z.string(),
  // JWT standard claims
  iat: z.number().optional(),
  exp: z.number().optional(),
  iss: z.string().optional(),
  aud: z.string().optional()
});

export type SessionClaims = z.infer<typeof SessionClaimsSchema>;

// Study configuration
export const StudyConfigSchema = z.object({
  id: z.string().uuid(),
  name: z.string(),
  version: z.string(),
  runnerBaseUrl: z.string().url(),
  fzbSpec: z.object({
    experiment: z.any(), // Compiled experiment spec
    assignmentRules: z.array(z.object({
      type: z.enum(['counter', 'latinSquare', 'random', 'balanced']),
      name: z.string(),
      parameters: z.any().optional()
    }))
  }),
  recruitmentConfig: z.object({
    targetParticipants: z.number(),
    compensation: z.object({
      base: z.number(),
      currency: z.string(),
      bonusStructure: z.any().optional()
    }),
    estimatedDuration: z.number(), // minutes
    criteria: z.object({
      age: z.object({
        min: z.number(),
        max: z.number()
      }).optional(),
      language: z.array(z.string()).optional(),
      customScreening: z.array(z.any()).optional()
    }).optional()
  }).optional(),
  status: z.enum(['draft', 'published', 'active', 'completed', 'archived']),
  createdAt: z.date(),
  publishedAt: z.date().optional(),
  archivedAt: z.date().optional()
});

export type StudyConfig = z.infer<typeof StudyConfigSchema>;

// Participant assignment result
export const AssignmentResultSchema = z.object({
  participantId: z.string(),
  conditions: z.record(z.any()),
  assignmentNumber: z.number(),
  assignedAt: z.date()
});

export type AssignmentResult = z.infer<typeof AssignmentResultSchema>;

// Provider parameters from URL
export const ProviderParamsSchema = z.object({
  // Prolific
  PROLIFIC_PID: z.string().optional(),
  STUDY_ID: z.string().optional(),
  SESSION_ID: z.string().optional(),

  // MTurk
  workerId: z.string().optional(),
  assignmentId: z.string().optional(),
  hitId: z.string().optional(),

  // SONA
  survey_code: z.string().optional(),

  // Generic fallback
  participant_id: z.string().optional()
});

export type ProviderParams = z.infer<typeof ProviderParamsSchema>;

// Database transaction interface
export interface DatabaseTransaction {
  query<T = any>(sql: string, params?: any[]): Promise<T[]>;
  queryOne<T = any>(sql: string, params?: any[]): Promise<T | null>;
  execute(sql: string, params?: any[]): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

// Error types
export class RouterError extends Error {
  constructor(
    message: string,
    public code: string,
    public statusCode: number = 500
  ) {
    super(message);
    this.name = 'RouterError';
  }
}

export class StudyNotFoundError extends RouterError {
  constructor(studyId: string) {
    super(`Study not found: ${studyId}`, 'STUDY_NOT_FOUND', 404);
  }
}

export class AssignmentError extends RouterError {
  constructor(message: string) {
    super(message, 'ASSIGNMENT_ERROR', 400);
  }
}

export class DuplicateEnrollmentError extends RouterError {
  constructor(participantId: string, studyId: string) {
    super(
      `Participant ${participantId} already enrolled in study ${studyId}`,
      'DUPLICATE_ENROLLMENT',
      409
    );
  }
}

