import postgres from 'postgres';
import { DatabaseTransaction, StudyConfig, AssignmentResult } from '../types.js';

export interface DatabaseConfig {
  host: string;
  port: number;
  database: string;
  username: string;
  password: string;
  max?: number;
  ssl?: boolean | object;
}

export class DatabaseManager {
  private sql: postgres.Sql;

  constructor(config: DatabaseConfig) {
    this.sql = postgres({
      host: config.host,
      port: config.port,
      database: config.database,
      username: config.username,
      password: config.password,
      max: config.max || 10,
      ssl: config.ssl || false
    });
  }

  async transaction<T>(
    callback: (tx: DatabaseTransaction) => Promise<T>
  ): Promise<T> {
    return this.sql.begin(async (sql) => {
      const tx: DatabaseTransaction = {
        query: async (query, params) => sql.unsafe(query, params),
        queryOne: async (query, params) => {
          const results = await sql.unsafe(query, params);
          return results[0] || null;
        },
        execute: async (query, params) => {
          await sql.unsafe(query, params);
        },
        commit: async () => {
          // Handled by postgres library
        },
        rollback: async () => {
          throw new Error('Transaction rollback');
        }
      };

      return callback(tx);
    });
  }

  async getStudy(studyId: string): Promise<StudyConfig | null> {
    const result = await this.sql`
      SELECT 
        id,
        name,
        version,
        runner_base_url as "runnerBaseUrl",
        fzb_spec as "fzbSpec",
        recruitment_config as "recruitmentConfig",
        status,
        created_at as "createdAt",
        published_at as "publishedAt",
        archived_at as "archivedAt"
      FROM studies
      WHERE id = ${studyId}
      AND status IN ('published', 'active')
    `;

    if (result.length === 0) return null;

    const study = result[0];
    return {
      ...study,
      createdAt: new Date(study.createdAt),
      publishedAt: study.publishedAt ? new Date(study.publishedAt) : undefined,
      archivedAt: study.archivedAt ? new Date(study.archivedAt) : undefined
    };
  }

  async checkDuplicateEnrollment(
    studyId: string,
    participantId: string,
    provider: string
  ): Promise<boolean> {
    const result = await this.sql`
      SELECT COUNT(*) as count
      FROM participant_sessions
      WHERE study_id = ${studyId}
      AND participant_id = ${participantId}
      AND provider = ${provider}
    `;

    return parseInt(result[0].count) > 0;
  }

  async createParticipantSession(
    studyId: string,
    participantId: string,
    provider: string,
    assignment: AssignmentResult,
    sessionTokenHash: string
  ): Promise<string> {
    const result = await this.sql`
      INSERT INTO participant_sessions (
        study_id,
        participant_id,
        provider,
        condition_assignment,
        session_token_hash,
        status,
        assigned_at
      ) VALUES (
        ${studyId},
        ${participantId},
        ${provider},
        ${JSON.stringify(assignment.conditions)},
        ${sessionTokenHash},
        'assigned',
        ${assignment.assignedAt}
      )
      RETURNING id
    `;

    return result[0].id;
  }

  async incrementCounter(
    studyId: string,
    counterName: string,
    tx?: DatabaseTransaction
  ): Promise<number> {
    const query = `
      INSERT INTO global_counters (study_id, counter_name, current_value)
      VALUES ($1, $2, 1)
      ON CONFLICT (study_id, counter_name)
      DO UPDATE SET 
        current_value = global_counters.current_value + 1,
        updated_at = NOW()
      RETURNING current_value
    `;

    const result = tx
      ? await tx.queryOne<{ current_value: number }>(query, [studyId, counterName])
      : await this.sql.unsafe(query, [studyId, counterName]).then(r => r[0]);

    return result!.current_value;
  }

  async updateSessionStatus(
    sessionId: string,
    status: 'started' | 'completed' | 'expired'
  ): Promise<void> {
    const statusField = status === 'started' ? 'started_at' : 
                       status === 'completed' ? 'completed_at' : null;

    if (statusField) {
      await this.sql`
        UPDATE participant_sessions
        SET 
          status = ${status},
          ${this.sql(statusField)} = NOW()
        WHERE id = ${sessionId}
      `;
    } else {
      await this.sql`
        UPDATE participant_sessions
        SET status = ${status}
        WHERE id = ${sessionId}
      `;
    }
  }

  async close(): Promise<void> {
    await this.sql.end();
  }
}

