import { 
  StudyConfig, 
  AssignmentResult, 
  ProviderParams, 
  DatabaseTransaction,
  AssignmentError 
} from '../types.js';
import { DatabaseManager } from '../database/DatabaseManager.js';

export interface AssignmentRule {
  type: 'counter' | 'latinSquare' | 'random' | 'balanced';
  name: string;
  parameters?: any;
}

export class ExperimentAssigner {
  constructor(private db: DatabaseManager) {}

  async assignCondition(
    study: StudyConfig,
    providerParams: ProviderParams,
    tx: DatabaseTransaction
  ): Promise<AssignmentResult> {
    // Extract participant ID from provider params
    const participantId = this.extractParticipantId(providerParams);
    if (!participantId) {
      throw new AssignmentError('No participant ID found in request');
    }

    // Get assignment rules from study config
    const rules = study.fzbSpec.assignmentRules || [];
    if (rules.length === 0) {
      throw new AssignmentError('No assignment rules defined for study');
    }

    // Process each assignment rule
    const conditions: Record<string, any> = {};
    let assignmentNumber = 0;

    for (const rule of rules) {
      const value = await this.processRule(study.id, rule, tx);
      conditions[rule.name] = value;

      // Track the primary assignment number (usually from first counter)
      if (rule.type === 'counter' && assignmentNumber === 0) {
        assignmentNumber = value;
      }
    }

    return {
      participantId,
      conditions,
      assignmentNumber,
      assignedAt: new Date()
    };
  }

  private async processRule(
    studyId: string,
    rule: AssignmentRule,
    tx: DatabaseTransaction
  ): Promise<any> {
    switch (rule.type) {
      case 'counter':
        return this.processCounterRule(studyId, rule, tx);

      case 'latinSquare':
        return this.processLatinSquareRule(studyId, rule, tx);

      case 'random':
        return this.processRandomRule(rule);

      case 'balanced':
        return this.processBalancedRule(studyId, rule, tx);

      default:
        throw new AssignmentError(`Unknown assignment rule type: ${rule.type}`);
    }
  }

  private async processCounterRule(
    studyId: string,
    rule: AssignmentRule,
    tx: DatabaseTransaction
  ): Promise<number> {
    // Increment counter atomically
    const counterName = rule.name || 'default';
    return this.db.incrementCounter(studyId, counterName, tx);
  }

  private async processLatinSquareRule(
    studyId: string,
    rule: AssignmentRule,
    tx: DatabaseTransaction
  ): Promise<any> {
    const params = rule.parameters || {};
    const numConditions = params.numConditions || 4;

    // Get current counter value
    const counterName = `${rule.name}_counter`;
    const participantNumber = await this.db.incrementCounter(studyId, counterName, tx);

    // Calculate Latin Square assignment
    // For a simple Latin Square, we rotate conditions based on participant number
    const row = (participantNumber - 1) % numConditions;
    const conditions = [];

    for (let i = 0; i < numConditions; i++) {
      conditions.push((row + i) % numConditions);
    }

    return {
      row,
      sequence: conditions,
      participantNumber
    };
  }

  private processRandomRule(rule: AssignmentRule): any {
    const params = rule.parameters || {};
    const options = params.options || ['A', 'B'];
    const weights = params.weights || options.map(() => 1);

    // Weighted random selection
    const totalWeight = weights.reduce((sum: number, w: number) => sum + w, 0);
    let random = Math.random() * totalWeight;

    for (let i = 0; i < options.length; i++) {
      random -= weights[i];
      if (random <= 0) {
        return options[i];
      }
    }

    return options[options.length - 1];
  }

  private async processBalancedRule(
    studyId: string,
    rule: AssignmentRule,
    tx: DatabaseTransaction
  ): Promise<any> {
    const params = rule.parameters || {};
    const conditions = params.conditions || ['A', 'B'];

    // Get counts for each condition
    const counts = await Promise.all(
      conditions.map(async (condition: string) => {
        const counterName = `${rule.name}_${condition}`;
        const query = `
          SELECT current_value 
          FROM global_counters 
          WHERE study_id = $1 AND counter_name = $2
        `;
        const result = await tx.queryOne<{ current_value: number }>(
          query, 
          [studyId, counterName]
        );
        return {
          condition,
          count: result?.current_value || 0
        };
      })
    );

    // Find condition with lowest count
    const minCount = Math.min(...counts.map(c => c.count));
    const eligibleConditions = counts.filter(c => c.count === minCount);

    // Randomly select from conditions with lowest count
    const selected = eligibleConditions[
      Math.floor(Math.random() * eligibleConditions.length)
    ];

    // Increment counter for selected condition
    await this.db.incrementCounter(
      studyId, 
      `${rule.name}_${selected.condition}`, 
      tx
    );

    return selected.condition;
  }

  private extractParticipantId(params: ProviderParams): string | null {
    return params.PROLIFIC_PID ||
           params.workerId ||
           params.survey_code ||
           params.participant_id ||
           null;
  }

  detectProvider(params: ProviderParams): 'prolific' | 'mturk' | 'sona' | 'direct' {
    if (params.PROLIFIC_PID) return 'prolific';
    if (params.workerId) return 'mturk';
    if (params.survey_code) return 'sona';
    return 'direct';
  }
}

