import Fastify, { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import fastifyJWT from '@fastify/jwt';
import fastifyCors from '@fastify/cors';
import fastifyHelmet from '@fastify/helmet';
import fastifyRateLimit from '@fastify/rate-limit';
import crypto from 'crypto';

import { DatabaseManager } from './database/DatabaseManager.js';
import { ExperimentAssigner } from './assignment/ExperimentAssigner.js';
import {
  SessionClaims,
  ProviderParams,
  RouterError,
  StudyNotFoundError,
  DuplicateEnrollmentError,
  ProviderParamsSchema
} from './types.js';

export interface ForgeRouterConfig {
  database: {
    host: string;
    port: number;
    database: string;
    username: string;
    password: string;
  };
  jwt: {
    secret: string;
    issuer?: string;
    audience?: string;
  };
  server?: {
    host?: string;
    port?: number;
    logger?: boolean;
  };
  cors?: {
    origin?: string | string[] | boolean;
  };
  rateLimit?: {
    max?: number;
    timeWindow?: string;
  };
}

export class ForgeRouter {
  private server: FastifyInstance;
  private db: DatabaseManager;
  private assigner: ExperimentAssigner;
  private config: ForgeRouterConfig;

  constructor(config: ForgeRouterConfig) {
    this.config = config;

    // Initialize database
    this.db = new DatabaseManager(config.database);
    this.assigner = new ExperimentAssigner(this.db);

    // Initialize Fastify server
    this.server = Fastify({
      logger: config.server?.logger || true
    });

    this.setupPlugins();
    this.setupRoutes();
  }

  private async setupPlugins(): Promise<void> {
    // JWT plugin for token generation
    await this.server.register(fastifyJWT, {
      secret: this.config.jwt.secret,
      sign: {
        issuer: this.config.jwt.issuer || 'psyforge-router',
        audience: this.config.jwt.audience || 'psyforge-runner',
        expiresIn: '24h'
      }
    });

    // CORS for cross-origin requests
    await this.server.register(fastifyCors, {
      origin: this.config.cors?.origin || true,
      credentials: true
    });

    // Security headers
    await this.server.register(fastifyHelmet, {
      contentSecurityPolicy: false // We'll handle CSP separately
    });

    // Rate limiting
    await this.server.register(fastifyRateLimit, {
      max: this.config.rateLimit?.max || 100,
      timeWindow: this.config.rateLimit?.timeWindow || '1 minute'
    });
  }

  private setupRoutes(): void {
    // Main participant entry point
    this.server.get<{
      Params: { studyId: string };
      Querystring: ProviderParams;
    }>('/router/:studyId', {
      schema: {
        params: {
          type: 'object',
          properties: {
            studyId: { type: 'string', format: 'uuid' }
          },
          required: ['studyId']
        },
        querystring: ProviderParamsSchema
      }
    }, this.handleParticipantEntry.bind(this));

    // Health check endpoint
    this.server.get('/health', async (request, reply) => {
      return { status: 'healthy', timestamp: new Date().toISOString() };
    });

    // Session status endpoint
    this.server.get<{
      Params: { sessionId: string };
    }>('/status/:sessionId', async (request, reply) => {
      return this.getSessionStatus(request.params.sessionId);
    });

    // Error handler
    this.server.setErrorHandler((error, request, reply) => {
      if (error instanceof RouterError) {
        reply.status(error.statusCode).send({
          error: error.code,
          message: error.message
        });
      } else {
        this.server.log.error(error);
        reply.status(500).send({
          error: 'INTERNAL_ERROR',
          message: 'An unexpected error occurred'
        });
      }
    });
  }

  private async handleParticipantEntry(
    request: FastifyRequest<{
      Params: { studyId: string };
      Querystring: ProviderParams;
    }>,
    reply: FastifyReply
  ): Promise<void> {
    const { studyId } = request.params;
    const providerParams = request.query;

    try {
      // Transaction for atomic assignment
      const result = await this.db.transaction(async (tx) => {
        // Load study configuration
        const study = await this.db.getStudy(studyId);
        if (!study) {
          throw new StudyNotFoundError(studyId);
        }

        // Extract participant ID and detect provider
        const participantId = this.extractParticipantId(providerParams);
        if (!participantId) {
          throw new RouterError(
            'No participant ID found in request',
            'MISSING_PARTICIPANT_ID',
            400
          );
        }

        const provider = this.assigner.detectProvider(providerParams);

        // Check for duplicate enrollment
        const isDuplicate = await this.db.checkDuplicateEnrollment(
          studyId,
          participantId,
          provider
        );

        if (isDuplicate) {
          throw new DuplicateEnrollmentError(participantId, studyId);
        }

        // Assign condition
        const assignment = await this.assigner.assignCondition(
          study,
          providerParams,
          tx
        );

        // Generate session JWT
        const sessionClaims: SessionClaims = {
          participantId: assignment.participantId,
          studyId: studyId,
          studyVersion: study.version,
          conditionLevels: assignment.conditions,
          provider,
          assignedAt: assignment.assignedAt.toISOString()
        };

        const sessionToken = this.server.jwt.sign(sessionClaims);

        // Hash token for storage
        const tokenHash = crypto
          .createHash('sha256')
          .update(sessionToken)
          .digest('hex');

        // Create participant session record
        const sessionId = await this.db.createParticipantSession(
          studyId,
          participantId,
          provider,
          assignment,
          tokenHash
        );

        // Build redirect URL
        const redirectUrl = new URL(study.runnerBaseUrl);
        redirectUrl.searchParams.set('session', sessionToken);

        // Preserve any provider-specific parameters
        if (provider === 'prolific' && providerParams.SESSION_ID) {
          redirectUrl.searchParams.set('PROLIFIC_SESSION_ID', providerParams.SESSION_ID);
        }

        return {
          redirectUrl: redirectUrl.toString(),
          sessionId
        };
      });

      // Log successful assignment
      this.server.log.info({
        studyId,
        sessionId: result.sessionId,
        provider: this.assigner.detectProvider(providerParams),
        participantId: this.extractParticipantId(providerParams)
      }, 'Participant assigned successfully');

      // Redirect to experiment
      reply.redirect(302, result.redirectUrl);

    } catch (error) {
      throw error; // Let error handler deal with it
    }
  }

  private extractParticipantId(params: ProviderParams): string | null {
    return params.PROLIFIC_PID ||
           params.workerId ||
           params.survey_code ||
           params.participant_id ||
           null;
  }

  private async getSessionStatus(sessionId: string): Promise<any> {
    // Implementation for checking session status
    // This would query the database for session information
    return {
      sessionId,
      status: 'active',
      // Additional session details
    };
  }

  async start(): Promise<void> {
    const host = this.config.server?.host || '0.0.0.0';
    const port = this.config.server?.port || 3000;

    try {
      await this.server.listen({ port, host });
      this.server.log.info(`ForgeRouter listening on ${host}:${port}`);
    } catch (err) {
      this.server.log.error(err);
      process.exit(1);
    }
  }

  async stop(): Promise<void> {
    await this.server.close();
    await this.db.close();
  }
}

