-- ForgeRouter Database Schema
-- PostgreSQL 14+

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Studies and their configurations
CREATE TABLE studies (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name VARCHAR(255) NOT NULL,
  version VARCHAR(50) NOT NULL,
  runner_base_url TEXT NOT NULL,
  fzb_spec JSONB NOT NULL, -- Compiled experiment specification
  recruitment_config JSONB,
  status VARCHAR(50) NOT NULL DEFAULT 'draft',
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  published_at TIMESTAMP WITH TIME ZONE,
  archived_at TIMESTAMP WITH TIME ZONE,

  CONSTRAINT studies_status_check CHECK (status IN ('draft', 'published', 'active', 'completed', 'archived')),
  UNIQUE(name, version)
);

-- Index for active study lookups
CREATE INDEX idx_studies_status ON studies(status) WHERE status IN ('published', 'active');
CREATE INDEX idx_studies_name_version ON studies(name, version);

-- Global counters for condition assignment
CREATE TABLE global_counters (
  study_id UUID REFERENCES studies(id) ON DELETE CASCADE,
  counter_name VARCHAR(100),
  current_value INTEGER DEFAULT 0,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),

  PRIMARY KEY(study_id, counter_name)
);

-- Index for counter lookups
CREATE INDEX idx_global_counters_study ON global_counters(study_id);

-- Participant sessions and assignments
CREATE TABLE participant_sessions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  study_id UUID REFERENCES studies(id) ON DELETE CASCADE,
  participant_id VARCHAR(255) NOT NULL,
  provider VARCHAR(50) NOT NULL,
  condition_assignment JSONB NOT NULL,
  session_token_hash VARCHAR(255),
  status VARCHAR(50) DEFAULT 'assigned',
  assigned_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  started_at TIMESTAMP WITH TIME ZONE,
  completed_at TIMESTAMP WITH TIME ZONE,
  expired_at TIMESTAMP WITH TIME ZONE,

  CONSTRAINT sessions_status_check CHECK (status IN ('assigned', 'started', 'completed', 'expired', 'error')),
  CONSTRAINT sessions_provider_check CHECK (provider IN ('prolific', 'mturk', 'sona', 'direct')),
  UNIQUE(study_id, participant_id, provider) -- Prevent double enrollment
);

-- Indexes for session lookups
CREATE INDEX idx_sessions_study ON participant_sessions(study_id);
CREATE INDEX idx_sessions_participant ON participant_sessions(participant_id, provider);
CREATE INDEX idx_sessions_status ON participant_sessions(status);
CREATE INDEX idx_sessions_token_hash ON participant_sessions(session_token_hash);

-- Session events for tracking participant progress
CREATE TABLE session_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  session_id UUID REFERENCES participant_sessions(id) ON DELETE CASCADE,
  event_type VARCHAR(50) NOT NULL,
  event_data JSONB,
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Index for event queries
CREATE INDEX idx_session_events_session ON session_events(session_id);
CREATE INDEX idx_session_events_type ON session_events(event_type);
CREATE INDEX idx_session_events_created ON session_events(created_at);

-- Recruitment provider integrations
CREATE TABLE recruitment_integrations (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  study_id UUID REFERENCES studies(id) ON DELETE CASCADE,
  provider VARCHAR(50) NOT NULL,
  external_study_id VARCHAR(255) NOT NULL,
  provider_config JSONB,
  status VARCHAR(50) DEFAULT 'pending',
  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),
  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW(),

  CONSTRAINT integrations_provider_check CHECK (provider IN ('prolific', 'mturk', 'sona')),
  CONSTRAINT integrations_status_check CHECK (status IN ('pending', 'active', 'completed', 'error'))
);

-- Index for integration lookups
CREATE INDEX idx_integrations_study ON recruitment_integrations(study_id);
CREATE INDEX idx_integrations_external ON recruitment_integrations(provider, external_study_id);

-- Atomic counter increment function
CREATE OR REPLACE FUNCTION increment_counter(
  p_study_id UUID,
  p_counter_name VARCHAR(100)
) RETURNS INTEGER AS $$
DECLARE
  new_value INTEGER;
BEGIN
  INSERT INTO global_counters (study_id, counter_name, current_value)
  VALUES (p_study_id, p_counter_name, 1)
  ON CONFLICT (study_id, counter_name)
  DO UPDATE SET 
    current_value = global_counters.current_value + 1,
    updated_at = NOW()
  RETURNING current_value INTO new_value;

  RETURN new_value;
END;
$$ LANGUAGE plpgsql;

-- Function to check session expiration
CREATE OR REPLACE FUNCTION check_session_expiration(
  p_session_id UUID,
  p_max_duration INTERVAL DEFAULT '24 hours'
) RETURNS BOOLEAN AS $$
DECLARE
  session_record RECORD;
BEGIN
  SELECT assigned_at, status INTO session_record
  FROM participant_sessions
  WHERE id = p_session_id;

  IF session_record IS NULL THEN
    RETURN TRUE; -- Session not found, consider expired
  END IF;

  IF session_record.status IN ('completed', 'expired') THEN
    RETURN TRUE; -- Already finished
  END IF;

  IF NOW() - session_record.assigned_at > p_max_duration THEN
    -- Mark as expired
    UPDATE participant_sessions
    SET status = 'expired', expired_at = NOW()
    WHERE id = p_session_id;

    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$$ LANGUAGE plpgsql;

-- Trigger to update timestamps
CREATE OR REPLACE FUNCTION update_updated_at_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER update_global_counters_updated_at 
  BEFORE UPDATE ON global_counters
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

CREATE TRIGGER update_recruitment_integrations_updated_at 
  BEFORE UPDATE ON recruitment_integrations
  FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();

