import { describe, it, expect, beforeEach, vi } from 'vitest';
import { ExperimentAssigner } from '../assignment/ExperimentAssigner.js';
import { DatabaseManager } from '../database/DatabaseManager.js';
import { StudyConfig, DatabaseTransaction } from '../types.js';

// Mock database manager
vi.mock('../database/DatabaseManager.js');

describe('ExperimentAssigner', () => {
  let assigner: ExperimentAssigner;
  let mockDb: DatabaseManager;
  let mockTx: DatabaseTransaction;

  beforeEach(() => {
    mockDb = {
      incrementCounter: vi.fn().mockResolvedValue(1)
    } as any;

    mockTx = {
      query: vi.fn(),
      queryOne: vi.fn(),
      execute: vi.fn(),
      commit: vi.fn(),
      rollback: vi.fn()
    };

    assigner = new ExperimentAssigner(mockDb);
  });

  describe('assignCondition', () => {
    const mockStudy: StudyConfig = {
      id: '123e4567-e89b-12d3-a456-426614174000',
      name: 'Test Study',
      version: '1.0.0',
      runnerBaseUrl: 'https://example.com/run',
      fzbSpec: {
        experiment: {},
        assignmentRules: [
          {
            type: 'counter',
            name: 'participantNumber',
            parameters: {}
          }
        ]
      },
      status: 'active',
      createdAt: new Date()
    };

    it('should assign condition using counter rule', async () => {
      const providerParams = { PROLIFIC_PID: 'test123' };
      mockDb.incrementCounter = vi.fn().mockResolvedValue(5);

      const result = await assigner.assignCondition(mockStudy, providerParams, mockTx);

      expect(result).toEqual({
        participantId: 'test123',
        conditions: { participantNumber: 5 },
        assignmentNumber: 5,
        assignedAt: expect.any(Date)
      });
      expect(mockDb.incrementCounter).toHaveBeenCalledWith(
        mockStudy.id,
        'participantNumber',
        mockTx
      );
    });

    it('should handle latin square assignment', async () => {
      const studyWithLatinSquare = {
        ...mockStudy,
        fzbSpec: {
          experiment: {},
          assignmentRules: [
            {
              type: 'latinSquare',
              name: 'conditionOrder',
              parameters: { numConditions: 4 }
            }
          ]
        }
      };

      mockDb.incrementCounter = vi.fn().mockResolvedValue(3);
      const result = await assigner.assignCondition(
        studyWithLatinSquare,
        { PROLIFIC_PID: 'test123' },
        mockTx
      );

      expect(result.conditions.conditionOrder).toEqual({
        row: 2, // (3-1) % 4 = 2
        sequence: [2, 3, 0, 1],
        participantNumber: 3
      });
    });

    it('should handle random assignment', async () => {
      const studyWithRandom = {
        ...mockStudy,
        fzbSpec: {
          experiment: {},
          assignmentRules: [
            {
              type: 'random',
              name: 'group',
              parameters: {
                options: ['control', 'experimental'],
                weights: [1, 1]
              }
            }
          ]
        }
      };

      const result = await assigner.assignCondition(
        studyWithRandom,
        { PROLIFIC_PID: 'test123' },
        mockTx
      );

      expect(['control', 'experimental']).toContain(result.conditions.group);
    });

    it('should handle balanced assignment', async () => {
      const studyWithBalanced = {
        ...mockStudy,
        fzbSpec: {
          experiment: {},
          assignmentRules: [
            {
              type: 'balanced',
              name: 'condition',
              parameters: { conditions: ['A', 'B', 'C'] }
            }
          ]
        }
      };

      // Mock counter queries to return different counts
      mockTx.queryOne = vi.fn()
        .mockResolvedValueOnce({ current_value: 5 })  // A has 5
        .mockResolvedValueOnce({ current_value: 3 })  // B has 3
        .mockResolvedValueOnce({ current_value: 4 }); // C has 4

      mockDb.incrementCounter = vi.fn().mockResolvedValue(4);

      const result = await assigner.assignCondition(
        studyWithBalanced,
        { PROLIFIC_PID: 'test123' },
        mockTx
      );

      // Should assign to B (lowest count)
      expect(result.conditions.condition).toBe('B');
      expect(mockDb.incrementCounter).toHaveBeenCalledWith(
        mockStudy.id,
        'condition_B',
        mockTx
      );
    });

    it('should throw error for missing participant ID', async () => {
      await expect(
        assigner.assignCondition(mockStudy, {}, mockTx)
      ).rejects.toThrow('No participant ID found in request');
    });

    it('should throw error for unknown assignment rule', async () => {
      const studyWithUnknown = {
        ...mockStudy,
        fzbSpec: {
          experiment: {},
          assignmentRules: [
            {
              type: 'unknown' as any,
              name: 'test',
              parameters: {}
            }
          ]
        }
      };

      await expect(
        assigner.assignCondition(studyWithUnknown, { PROLIFIC_PID: 'test' }, mockTx)
      ).rejects.toThrow('Unknown assignment rule type: unknown');
    });
  });

  describe('detectProvider', () => {
    it('should detect Prolific provider', () => {
      expect(assigner.detectProvider({ PROLIFIC_PID: 'test' })).toBe('prolific');
    });

    it('should detect MTurk provider', () => {
      expect(assigner.detectProvider({ workerId: 'test' })).toBe('mturk');
    });

    it('should detect SONA provider', () => {
      expect(assigner.detectProvider({ survey_code: 'test' })).toBe('sona');
    });

    it('should default to direct provider', () => {
      expect(assigner.detectProvider({ participant_id: 'test' })).toBe('direct');
      expect(assigner.detectProvider({})).toBe('direct');
    });
  });
});

