import { z } from 'zod';

// Common types for all recruitment providers
export const StudyConfigSchema = z.object({
  name: z.string(),
  description: z.string(),
  studyUrl: z.string().url(),
  completionCode: z.string(),
  targetParticipants: z.number().positive(),
  estimatedDuration: z.number().positive(), // in minutes
  compensation: z.object({
    base: z.number().positive(),
    currency: z.string(),
    bonusStructure: z.object({
      type: z.enum(['performance', 'completion', 'fixed']),
      amount: z.number().positive()
    }).optional()
  }),
  criteria: z.object({
    age: z.object({
      min: z.number().min(18),
      max: z.number().max(100)
    }).optional(),
    language: z.array(z.string()).optional(),
    country: z.array(z.string()).optional(),
    excludePreviousParticipants: z.boolean().optional(),
    customScreening: z.array(z.object({
      question: z.string(),
      acceptedAnswers: z.array(z.string())
    })).optional()
  }).optional()
});

export type StudyConfig = z.infer<typeof StudyConfigSchema>;

// Screening criteria
export interface ScreeningCriteria {
  age?: {
    min: number;
    max: number;
  };
  language?: string[];
  country?: string[];
  excludePreviousParticipants?: boolean;
  customScreening?: Array<{
    question: string;
    acceptedAnswers: string[];
  }>;
}

// Provider-specific external IDs
export type ExternalStudyId = string;

// Participant submission for payment approval
export interface ParticipantSubmission {
  participantId: string;
  completionCode?: string;
  completedAt: Date;
  dataQuality?: 'good' | 'poor' | 'rejected';
}

// Payment information
export interface PaymentInfo {
  participantId: string;
  amount: number;
  currency: string;
  reason?: string;
}

// Study status on external platform
export type ExternalStudyStatus = 
  | 'draft'
  | 'awaiting_review'
  | 'active'
  | 'paused'
  | 'completed'
  | 'cancelled';

// Provider capabilities
export interface ProviderCapabilities {
  name: string;
  supportedCountries: string[];
  supportedLanguages: string[];
  minCompensation: { [currency: string]: number };
  maxCompensation: { [currency: string]: number };
  minParticipants: number;
  maxParticipants: number;
  screeningFeatures: string[];
  paymentMethods: string[];
}

// Base recruitment provider interface
export interface RecruitmentProvider {
  readonly name: string;

  // Study lifecycle management
  createStudy(config: StudyConfig): Promise<ExternalStudyId>;
  updateStudy(externalId: ExternalStudyId, config: Partial<StudyConfig>): Promise<void>;
  publishStudy(externalId: ExternalStudyId): Promise<void>;
  pauseStudy(externalId: ExternalStudyId): Promise<void>;
  resumeStudy(externalId: ExternalStudyId): Promise<void>;
  completeStudy(externalId: ExternalStudyId): Promise<void>;
  deleteStudy(externalId: ExternalStudyId): Promise<void>;

  // Study status and info
  getStudyStatus(externalId: ExternalStudyId): Promise<ExternalStudyStatus>;
  getStudyInfo(externalId: ExternalStudyId): Promise<any>;
  getParticipantCount(externalId: ExternalStudyId): Promise<number>;

  // Participant management
  approveSubmission(externalId: ExternalStudyId, submission: ParticipantSubmission): Promise<void>;
  rejectSubmission(externalId: ExternalStudyId, submission: ParticipantSubmission, reason: string): Promise<void>;
  bonusPayment(externalId: ExternalStudyId, payment: PaymentInfo): Promise<void>;

  // Provider info
  getCapabilities(): Promise<ProviderCapabilities>;
}

// Errors
export class RecruitmentError extends Error {
  constructor(
    message: string,
    public code: string,
    public provider: string,
    public details?: any
  ) {
    super(message);
    this.name = 'RecruitmentError';
  }
}

export class ProviderAPIError extends RecruitmentError {
  constructor(
    provider: string,
    message: string,
    public statusCode?: number,
    details?: any
  ) {
    super(message, 'PROVIDER_API_ERROR', provider, details);
  }
}

export class InvalidConfigError extends RecruitmentError {
  constructor(provider: string, message: string, details?: any) {
    super(message, 'INVALID_CONFIG', provider, details);
  }
}

export class StudyNotFoundError extends RecruitmentError {
  constructor(provider: string, externalId: string) {
    super(`Study not found: ${externalId}`, 'STUDY_NOT_FOUND', provider, { externalId });
  }
}

