import axios, { AxiosInstance, AxiosError } from 'axios';
import {
  RecruitmentProvider,
  StudyConfig,
  ExternalStudyId,
  ExternalStudyStatus,
  ParticipantSubmission,
  PaymentInfo,
  ProviderCapabilities,
  ProviderAPIError,
  InvalidConfigError,
  StudyNotFoundError
} from '../types.js';

// Prolific-specific types
interface ProlificStudy {
  id?: string;
  name: string;
  internal_name: string;
  description: string;
  external_study_url: string;
  prolific_id_option: 'question' | 'url_parameters' | 'not_required';
  completion_option: 'url' | 'code' | 'redirect';
  completion_code?: string;
  completion_url?: string;
  total_available_places: number;
  reward: number; // in pence for GBP
  estimated_completion_time: number; // in minutes
  maximum_allowed_time?: number;
  device_compatibility: string[];
  peripheral_requirements: string[];
  eligibility_requirements: ProlificEligibilityRequirement[];
  project?: string;
  submission_config?: {
    can_participants_return: boolean;
    automatically_approve_submissions: boolean;
  };
}

interface ProlificEligibilityRequirement {
  _cls: string;
  [key: string]: any;
}

interface ProlificSubmission {
  participant_id: string;
  status: string;
  started_at: string;
  completed_at?: string;
}

export class ProlificProvider implements RecruitmentProvider {
  readonly name = 'prolific';
  private api: AxiosInstance;
  private projectId?: string;

  constructor(
    apiKey: string,
    options: {
      sandbox?: boolean;
      projectId?: string;
    } = {}
