    if (criteria?.language && criteria.language.length > 0) {
      requirements.push({
        _cls: 'web.eligibility.models.FluentLanguageEligibilityRequirement',
        language: this.mapLanguageCode(criteria.language[0])
      });
    }

    if (criteria?.country && criteria.country.length > 0) {
      requirements.push({
        _cls: 'web.eligibility.models.CurrentCountryOfResidenceEligibilityRequirement',
        country: criteria.country
      });
    }

    if (criteria?.excludePreviousParticipants) {
      requirements.push({
        _cls: 'web.eligibility.models.ParticipantGroupEligibilityRequirement',
        participant_group_id: 'exclude_previous'
      });
    }

    return requirements;
  }

