    // Map common language codes to Prolific's format
    const languageMap: { [key: string]: string } = {
      en: 'en',
      de: 'de',
      es: 'es',
      fr: 'fr',
      it: 'it',
      pt: 'pt',
      nl: 'nl',
      pl: 'pl',
      da: 'da',
