import { RecruitmentProvider, RecruitmentError } from './types.js';

type ProviderFactory = () => RecruitmentProvider;

export class RecruitmentProviderRegistry {
  private providers = new Map<string, ProviderFactory>();
  private instances = new Map<string, RecruitmentProvider>();

  /**
   * Register a recruitment provider factory
   */
  register(name: string, factory: ProviderFactory): void {
    if (this.providers.has(name)) {
      throw new Error(`Provider '${name}' is already registered`);
    }
    this.providers.set(name, factory);
  }

  /**
   * Unregister a recruitment provider
   */
  unregister(name: string): boolean {
    this.instances.delete(name);
    return this.providers.delete(name);
  }

  /**
   * Get a provider instance (singleton pattern)
   */
  get(name: string): RecruitmentProvider {
    // Return existing instance if available
    if (this.instances.has(name)) {
      return this.instances.get(name)!;
    }

    // Create new instance from factory
    const factory = this.providers.get(name);
    if (!factory) {
      throw new RecruitmentError(
        `Unknown recruitment provider: ${name}`,
        'PROVIDER_NOT_FOUND',
        name
      );
    }

    const instance = factory();
    this.instances.set(name, instance);
    return instance;
  }

  /**
   * Create a new provider instance (non-singleton)
   */
  create(name: string): RecruitmentProvider {
    const factory = this.providers.get(name);
    if (!factory) {
      throw new RecruitmentError(
        `Unknown recruitment provider: ${name}`,
        'PROVIDER_NOT_FOUND',
        name
      );
    }
    return factory();
  }

  /**
   * Check if a provider is registered
   */
  has(name: string): boolean {
    return this.providers.has(name);
  }

  /**
   * Get list of registered provider names
   */
  list(): string[] {
    return Array.from(this.providers.keys());
  }

  /**
   * Clear all instances (useful for testing)
   */
  clearInstances(): void {
    this.instances.clear();
  }
}

// Global registry instance
export const recruitmentProviders = new RecruitmentProviderRegistry();

