import { describe, it, expect, beforeEach, vi } from 'vitest';
import axios from 'axios';
import { ProlificProvider } from '../providers/ProlificProvider.js';
import { StudyConfig } from '../types.js';

// Mock axios
vi.mock('axios');

describe('ProlificProvider', () => {
  let provider: ProlificProvider;
  let mockAxios: any;

  beforeEach(() => {
    // Create mock axios instance
    mockAxios = {
      post: vi.fn(),
      get: vi.fn(),
      patch: vi.fn(),
      interceptors: {
        response: {
          use: vi.fn()
        }
      }
    };

    // Mock axios.create to return our mock instance
    (axios.create as any) = vi.fn(() => mockAxios);

    provider = new ProlificProvider('test-api-key', { sandbox: true });
  });

  describe('createStudy', () => {
    const studyConfig: StudyConfig = {
      name: 'Test Study',
      description: 'A test study for unit testing',
      studyUrl: 'https://example.com/study',
      completionCode: 'TEST123',
      targetParticipants: 50,
      estimatedDuration: 30,
      compensation: {
        base: 750, // £7.50 in pence
        currency: 'GBP'
      },
      criteria: {
        age: { min: 18, max: 65 },
        language: ['en'],
        country: ['UK', 'US']
      }
    };

    it('should create a study successfully', async () => {
      const mockStudyId = 'prolific-study-123';
      mockAxios.post.mockResolvedValueOnce({
        data: { id: mockStudyId }
      });

      const result = await provider.createStudy(studyConfig);

      expect(result).toBe(mockStudyId);
      expect(mockAxios.post).toHaveBeenCalledWith('/studies/', expect.objectContaining({
        name: 'Test Study',
        description: 'A test study for unit testing',
        external_study_url: 'https://example.com/study',
        completion_code: 'TEST123',
        total_available_places: 50,
        reward: 750,
        estimated_completion_time: 30,
        eligibility_requirements: expect.arrayContaining([
          expect.objectContaining({
            _cls: 'web.eligibility.models.AgeRangeEligibilityRequirement',
            min_age: 18,
            max_age: 65
          })
        ])
      }));
    });

    it('should handle API errors', async () => {
      mockAxios.post.mockRejectedValueOnce(new Error('API Error'));

      await expect(provider.createStudy(studyConfig)).rejects.toThrow('API Error');
    });
  });

  describe('publishStudy', () => {
    it('should publish a study', async () => {
      mockAxios.post.mockResolvedValueOnce({ data: {} });

      await provider.publishStudy('study-123');

      expect(mockAxios.post).toHaveBeenCalledWith('/studies/study-123/transition/', {
        to: 'PUBLISH'
      });
    });
  });

  describe('approveSubmission', () => {
    it('should approve a participant submission', async () => {
      mockAxios.post.mockResolvedValueOnce({ data: {} });

      await provider.approveSubmission('study-123', {
        participantId: 'participant-456',
        completedAt: new Date(),
        dataQuality: 'good'
      });

      expect(mockAxios.post).toHaveBeenCalledWith('/submissions/participant-456/transition/', {
        to: 'APPROVE'
      });
    });
  });

  describe('bonusPayment', () => {
    it('should send bonus payment', async () => {
      mockAxios.post.mockResolvedValueOnce({ data: {} });

      await provider.bonusPayment('study-123', {
        participantId: 'participant-456',
        amount: 200, // £2.00 in pence
        currency: 'GBP',
        reason: 'Great performance'
      });

      expect(mockAxios.post).toHaveBeenCalledWith('/bonuses/', {
        study_id: 'study-123',
        participant_id: 'participant-456',
        amount: 200,
        reason: 'Great performance'
      });
    });
  });

  describe('getStudyStatus', () => {
    it('should map Prolific status to standard status', async () => {
      mockAxios.get.mockResolvedValueOnce({
        data: { status: 'ACTIVE' }
      });

      const status = await provider.getStudyStatus('study-123');

      expect(status).toBe('active');
      expect(mockAxios.get).toHaveBeenCalledWith('/studies/study-123/');
    });

    it('should handle different status mappings', async () => {
      const statusMappings = [
        { prolific: 'UNPUBLISHED', expected: 'draft' },
        { prolific: 'PAUSED', expected: 'paused' },
        { prolific: 'COMPLETED', expected: 'completed' }
      ];

      for (const mapping of statusMappings) {
        mockAxios.get.mockResolvedValueOnce({
          data: { status: mapping.prolific }
        });

        const status = await provider.getStudyStatus('study-123');
        expect(status).toBe(mapping.expected);
      }
    });
  });

  describe('getCapabilities', () => {
    it('should return provider capabilities', async () => {
      const capabilities = await provider.getCapabilities();

      expect(capabilities).toEqual({
        name: 'prolific',
        supportedCountries: expect.arrayContaining(['US', 'UK', 'CA']),
        supportedLanguages: expect.arrayContaining(['en', 'de', 'es']),
        minCompensation: expect.objectContaining({
          GBP: 500,
          USD: 650
        }),
        maxCompensation: expect.objectContaining({
          GBP: 5000,
          USD: 6500
        }),
        minParticipants: 1,
        maxParticipants: 10000,
        screeningFeatures: expect.arrayContaining(['age', 'gender', 'country']),
        paymentMethods: ['prolific_balance', 'paypal']
      });
    });
  });
});

