import { z } from 'zod';

// OAuth2 configuration
export const AuthConfigSchema = z.object({
  keycloak: z.object({
    url: z.string().url(),
    realm: z.string(),
    clientId: z.string()
  }),
  redirectUri: z.string().url().optional(),
  scope: z.string().default('openid profile email'),
  autoRefresh: z.boolean().default(true),
  refreshBuffer: z.number().default(60) // seconds before expiry to refresh
});

export type AuthConfig = z.infer<typeof AuthConfigSchema>;

// Token response from Keycloak
export const TokenResponseSchema = z.object({
  access_token: z.string(),
  id_token: z.string(),
  refresh_token: z.string().optional(),
  token_type: z.string(),
  expires_in: z.number(),
  scope: z.string()
});

export type TokenResponse = z.infer<typeof TokenResponseSchema>;

// User information from ID token
export const UserInfoSchema = z.object({
  sub: z.string(), // Subject (user ID)
  email: z.string().email().optional(),
  email_verified: z.boolean().optional(),
  name: z.string().optional(),
  given_name: z.string().optional(),
  family_name: z.string().optional(),
  preferred_username: z.string().optional(),
  // Keycloak roles
  realm_access: z.object({
    roles: z.array(z.string())
  }).optional(),
  resource_access: z.record(z.object({
    roles: z.array(z.string())
  })).optional()
});

export type UserInfo = z.infer<typeof UserInfoSchema>;

// User permissions for Psycho-Forge
export interface UserPermissions {
  canCreateExperiments: boolean;
  canPublishExperiments: boolean;
  canAccessAnalytics: boolean;
  canManageUsers: boolean;
  canManageRecruitment: boolean;
  maxParticipants: number;
  allowedProviders: string[];
  quotaLimits: {
    experimentsPerMonth?: number;
    participantsPerMonth?: number;
    storageGB?: number;
  };
}

// Authenticated user with permissions
export interface AuthenticatedUser {
  id: string;
  email?: string;
  name?: string;
  username?: string;
  roles: string[];
  permissions: UserPermissions;
}

// Authentication result
export interface AuthenticationResult {
  user: AuthenticatedUser;
  tokens: {
    accessToken: string;
    idToken: string;
    refreshToken?: string;
    expiresAt: number; // Unix timestamp
  };
}

// PKCE parameters
export interface PKCEParams {
  codeVerifier: string;
  codeChallenge: string;
  state: string;
}

// Authorization URL
export interface AuthorizationUrl {
  url: string;
  state: string;
}

// Token storage interface
export interface TokenStorage {
  getTokens(): Promise<AuthenticationResult['tokens'] | null>;
  setTokens(tokens: AuthenticationResult['tokens']): Promise<void>;
  clearTokens(): Promise<void>;

  getPKCEParams(): Promise<PKCEParams | null>;
  setPKCEParams(params: PKCEParams): Promise<void>;
  clearPKCEParams(): Promise<void>;
}

// Errors
export class AuthError extends Error {
  constructor(
    message: string,
    public code: string,
    public details?: any
  ) {
    super(message);
    this.name = 'AuthError';
  }
}

export class AuthenticationRequiredError extends AuthError {
  constructor() {
    super('Authentication required', 'AUTH_REQUIRED');
  }
}

export class TokenExpiredError extends AuthError {
  constructor() {
    super('Token expired', 'TOKEN_EXPIRED');
  }
}

export class InvalidTokenError extends AuthError {
  constructor(reason?: string) {
    super(`Invalid token${reason ? `: ${reason}` : ''}`, 'INVALID_TOKEN');
  }
}

export class AuthorizationError extends AuthError {
  constructor(message: string) {
    super(message, 'AUTHORIZATION_ERROR');
  }
}

