import { jwtDecode } from 'jose';
import {
  AuthenticationResult,
  TokenStorage,
  PKCEParams,
  InvalidTokenError,
  TokenExpiredError
} from './types.js';

/**
 * In-memory token storage (for browser environments)
 */
export class InMemoryTokenStorage implements TokenStorage {
  private tokens: AuthenticationResult['tokens'] | null = null;
  private pkceParams: PKCEParams | null = null;

  async getTokens(): Promise<AuthenticationResult['tokens'] | null> {
    return this.tokens;
  }

  async setTokens(tokens: AuthenticationResult['tokens']): Promise<void> {
    this.tokens = tokens;
  }

  async clearTokens(): Promise<void> {
    this.tokens = null;
  }

  async getPKCEParams(): Promise<PKCEParams | null> {
    return this.pkceParams;
  }

  async setPKCEParams(params: PKCEParams): Promise<void> {
    this.pkceParams = params;
  }

  async clearPKCEParams(): Promise<void> {
    this.pkceParams = null;
  }
}

/**
 * LocalStorage token storage (for browser environments)
 */
export class LocalStorageTokenStorage implements TokenStorage {
  private readonly prefix = 'psyforge_auth_';

  async getTokens(): Promise<AuthenticationResult['tokens'] | null> {
    const data = localStorage.getItem(`${this.prefix}tokens`);
    return data ? JSON.parse(data) : null;
  }

  async setTokens(tokens: AuthenticationResult['tokens']): Promise<void> {
    localStorage.setItem(`${this.prefix}tokens`, JSON.stringify(tokens));
  }

  async clearTokens(): Promise<void> {
    localStorage.removeItem(`${this.prefix}tokens`);
  }

  async getPKCEParams(): Promise<PKCEParams | null> {
    const data = localStorage.getItem(`${this.prefix}pkce`);
    return data ? JSON.parse(data) : null;
  }

  async setPKCEParams(params: PKCEParams): Promise<void> {
    localStorage.setItem(`${this.prefix}pkce`, JSON.stringify(params));
  }

  async clearPKCEParams(): Promise<void> {
    localStorage.removeItem(`${this.prefix}pkce`);
  }
}

/**
 * Token management with automatic refresh
 */
export class TokenManager {
  private storage: TokenStorage;
  private refreshTimer?: NodeJS.Timeout | number;
  private refreshBuffer: number;

  constructor(
    storage?: TokenStorage,
    refreshBuffer: number = 60 // seconds before expiry
  ) {
    this.storage = storage || new InMemoryTokenStorage();
    this.refreshBuffer = refreshBuffer;
  }

  /**
   * Store tokens and set up refresh timer
   */
  async storeTokens(tokens: AuthenticationResult['tokens']): Promise<void> {
    await this.storage.setTokens(tokens);
    this.scheduleTokenRefresh(tokens);
  }

  /**
   * Get current tokens
   */
  async getTokens(): Promise<AuthenticationResult['tokens'] | null> {
    const tokens = await this.storage.getTokens();
    if (!tokens) return null;

    // Check if tokens are expired
    if (this.isTokenExpired(tokens)) {
      await this.storage.clearTokens();
      throw new TokenExpiredError();
    }

    return tokens;
  }

  /**
   * Get access token
   */
  async getAccessToken(): Promise<string | null> {
    const tokens = await this.getTokens();
    return tokens?.accessToken || null;
  }

  /**
   * Get refresh token
   */
  async getRefreshToken(): Promise<string | null> {
    const tokens = await this.storage.getTokens();
    return tokens?.refreshToken || null;
  }

  /**
   * Clear all tokens
   */
  async clearTokens(): Promise<void> {
    this.cancelRefreshTimer();
    await this.storage.clearTokens();
  }

  /**
   * Store PKCE parameters
   */
  async storePKCEParams(params: PKCEParams): Promise<void> {
    await this.storage.setPKCEParams(params);
  }

  /**
   * Get PKCE parameters
   */
  async getPKCEParams(): Promise<PKCEParams | null> {
    return this.storage.getPKCEParams();
  }

  /**
   * Clear PKCE parameters
   */
  async clearPKCEParams(): Promise<void> {
    await this.storage.clearPKCEParams();
  }

  /**
   * Check if tokens need refresh
   */
  needsRefresh(tokens?: AuthenticationResult['tokens']): boolean {
    if (!tokens) return true;

    const now = Math.floor(Date.now() / 1000);
    const expiresAt = Math.floor(tokens.expiresAt / 1000);
    const refreshAt = expiresAt - this.refreshBuffer;

    return now >= refreshAt;
  }

  /**
   * Check if token is expired
   */
  private isTokenExpired(tokens: AuthenticationResult['tokens']): boolean {
    const now = Date.now();
    return now >= tokens.expiresAt;
  }

  /**
   * Decode JWT token without verification (client-side only)
   */
  decodeToken<T = any>(token: string): T {
    try {
      return jwtDecode(token) as T;
    } catch (error) {
      throw new InvalidTokenError('Failed to decode token');
    }
  }

  /**
   * Extract expiration time from access token
   */
  getTokenExpiration(accessToken: string): number {
    const decoded = this.decodeToken<{ exp?: number }>(accessToken);
    if (!decoded.exp) {
      throw new InvalidTokenError('Token missing expiration');
    }
    return decoded.exp * 1000; // Convert to milliseconds
  }

  /**
   * Schedule automatic token refresh
   */
  private scheduleTokenRefresh(tokens: AuthenticationResult['tokens']): void {
    this.cancelRefreshTimer();

    const now = Date.now();
    const expiresAt = tokens.expiresAt;
    const refreshAt = expiresAt - (this.refreshBuffer * 1000);
    const delay = Math.max(0, refreshAt - now);

    if (delay > 0) {
      this.refreshTimer = setTimeout(() => {
        // Emit refresh needed event or callback
        this.onRefreshNeeded();
      }, delay);
    }
  }

  /**
   * Cancel refresh timer
   */
  private cancelRefreshTimer(): void {
    if (this.refreshTimer) {
      clearTimeout(this.refreshTimer as any);
      this.refreshTimer = undefined;
    }
  }

  /**
   * Override this method to handle refresh
   */
  protected onRefreshNeeded(): void {
    // Override in subclass or provide callback
  }

  /**
   * Set refresh callback
   */
  setRefreshCallback(callback: () => void): void {
    this.onRefreshNeeded = callback;
  }
}

