import axios, { AxiosInstance } from 'axios';
import {
  TokenResponse,
  TokenResponseSchema,
  UserInfo,
  UserInfoSchema,
  AuthError
} from './types.js';

export interface KeycloakConfig {
  url: string;
  realm: string;
  clientId: string;
}

export interface TokenExchangeParams {
  code: string;
  codeVerifier: string;
  redirectUri: string;
}

export interface RefreshTokenParams {
  refreshToken: string;
}

export class KeycloakClient {
  private api: AxiosInstance;
  private config: KeycloakConfig;
  private openidConfig?: OpenIDConfiguration;

  constructor(config: KeycloakConfig) {
    this.config = config;
    this.api = axios.create({
      baseURL: `${config.url}/realms/${config.realm}`,
      timeout: 30000,
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      }
    });
  }

  /**
   * Get OpenID configuration
   */
  async getOpenIDConfiguration(): Promise<OpenIDConfiguration> {
    if (this.openidConfig) {
      return this.openidConfig;
    }

    try {
      const response = await this.api.get('/.well-known/openid-configuration');
      this.openidConfig = response.data;
      return this.openidConfig;
    } catch (error) {
      throw new AuthError(
        'Failed to fetch OpenID configuration',
        'OPENID_CONFIG_ERROR',
        error
      );
    }
  }

  /**
   * Get authorization endpoint URL
   */
  async getAuthorizationEndpoint(): Promise<string> {
    const config = await this.getOpenIDConfiguration();
    return config.authorization_endpoint;
  }

  /**
   * Exchange authorization code for tokens
   */
  async exchangeCodeForTokens(params: TokenExchangeParams): Promise<TokenResponse> {
    const config = await this.getOpenIDConfiguration();

    const data = new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: this.config.clientId,
      code: params.code,
      code_verifier: params.codeVerifier,
      redirect_uri: params.redirectUri
    });

    try {
      const response = await axios.post(config.token_endpoint, data.toString(), {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      });

      return TokenResponseSchema.parse(response.data);
    } catch (error: any) {
      if (axios.isAxiosError(error) && error.response) {
        throw new AuthError(
          error.response.data.error_description || 'Token exchange failed',
          error.response.data.error || 'TOKEN_EXCHANGE_ERROR',
          error.response.data
        );
      }
      throw new AuthError('Token exchange failed', 'TOKEN_EXCHANGE_ERROR', error);
    }
  }

  /**
   * Refresh access token
   */
  async refreshTokens(refreshToken: string): Promise<TokenResponse> {
    const config = await this.getOpenIDConfiguration();

    const data = new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: this.config.clientId,
      refresh_token: refreshToken
    });

    try {
      const response = await axios.post(config.token_endpoint, data.toString(), {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      });

      return TokenResponseSchema.parse(response.data);
    } catch (error: any) {
      if (axios.isAxiosError(error) && error.response) {
        throw new AuthError(
          error.response.data.error_description || 'Token refresh failed',
          error.response.data.error || 'TOKEN_REFRESH_ERROR',
          error.response.data
        );
      }
      throw new AuthError('Token refresh failed', 'TOKEN_REFRESH_ERROR', error);
    }
  }

  /**
   * Get user info from access token
   */
  async getUserInfo(accessToken: string): Promise<UserInfo> {
    const config = await this.getOpenIDConfiguration();

    try {
      const response = await axios.get(config.userinfo_endpoint, {
        headers: {
          'Authorization': `Bearer ${accessToken}`
        }
      });

      return UserInfoSchema.parse(response.data);
    } catch (error: any) {
      if (axios.isAxiosError(error) && error.response) {
        throw new AuthError(
          'Failed to fetch user info',
          'USERINFO_ERROR',
          error.response.data
        );
      }
      throw new AuthError('Failed to fetch user info', 'USERINFO_ERROR', error);
    }
  }

  /**
   * Logout user
   */
  async logout(idToken: string, postLogoutRedirectUri?: string): Promise<string> {
    const config = await this.getOpenIDConfiguration();

    const url = new URL(config.end_session_endpoint);
    url.searchParams.set('id_token_hint', idToken);
    url.searchParams.set('client_id', this.config.clientId);

    if (postLogoutRedirectUri) {
      url.searchParams.set('post_logout_redirect_uri', postLogoutRedirectUri);
    }

    return url.toString();
  }
}

// OpenID Connect Discovery Configuration
interface OpenIDConfiguration {
  issuer: string;
  authorization_endpoint: string;
  token_endpoint: string;
  userinfo_endpoint: string;
  end_session_endpoint: string;
  jwks_uri: string;
  response_types_supported: string[];
  grant_types_supported: string[];
  subject_types_supported: string[];
  id_token_signing_alg_values_supported: string[];
  scopes_supported: string[];
  token_endpoint_auth_methods_supported: string[];
  claims_supported: string[];
  code_challenge_methods_supported: string[];
}

