import { KeycloakClient } from './KeycloakClient.js';
import { TokenManager } from './TokenManager.js';
import {
  generateCodeVerifier,
  generateCodeChallenge,
  generateState,
  buildAuthorizationUrl,
  parseCallbackUrl
} from './pkce.js';
import {
  AuthConfig,
  AuthenticationResult,
  AuthenticatedUser,
  UserPermissions,
  AuthorizationUrl,
  TokenResponse,
  UserInfo,
  AuthError,
  AuthenticationRequiredError,
  AuthorizationError,
  InvalidTokenError
} from './types.js';

export class AuthenticationManager {
  private keycloak: KeycloakClient;
  private tokenManager: TokenManager;
  private config: AuthConfig;

  constructor(config: AuthConfig, tokenManager?: TokenManager) {
    this.config = config;
    this.keycloak = new KeycloakClient(config.keycloak);
    this.tokenManager = tokenManager || new TokenManager();

    // Set up automatic token refresh
    if (config.autoRefresh) {
      this.tokenManager.setRefreshCallback(() => {
        this.refreshTokens().catch(console.error);
      });
    }
  }

  /**
   * Initialize OAuth2 PKCE flow
   */
  async initiateLogin(additionalParams?: Record<string, string>): Promise<AuthorizationUrl> {
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    const state = generateState();

    // Store PKCE parameters
    await this.tokenManager.storePKCEParams({
      codeVerifier,
      codeChallenge,
      state
    });

    // Get authorization endpoint
    const authEndpoint = await this.keycloak.getAuthorizationEndpoint();

    // Build authorization URL
    const redirectUri = this.config.redirectUri || window.location.origin + '/auth/callback';
    const url = buildAuthorizationUrl({
      baseUrl: authEndpoint,
      clientId: this.config.keycloak.clientId,
      redirectUri,
      scope: this.config.scope,
      codeChallenge,
      state,
      additionalParams
    });

    return { url, state };
  }

  /**
   * Handle OAuth callback
   */
  async handleCallback(callbackUrl: string): Promise<AuthenticationResult> {
    const params = parseCallbackUrl(callbackUrl);

    // Check for errors
    if (params.error) {
      throw new AuthorizationError(
        params.error_description || `Authorization failed: ${params.error}`
      );
    }

    // Validate required parameters
    if (!params.code || !params.state) {
      throw new AuthorizationError('Missing authorization code or state');
    }

    // Get stored PKCE parameters
    const pkceParams = await this.tokenManager.getPKCEParams();
    if (!pkceParams) {
      throw new AuthorizationError('PKCE parameters not found');
    }

    // Validate state (CSRF protection)
    if (params.state !== pkceParams.state) {
      throw new AuthorizationError('Invalid state parameter');
    }

    // Exchange code for tokens
    const redirectUri = this.config.redirectUri || window.location.origin + '/auth/callback';
    const tokens = await this.keycloak.exchangeCodeForTokens({
      code: params.code,
      codeVerifier: pkceParams.codeVerifier,
      redirectUri
    });

    // Clear PKCE parameters
    await this.tokenManager.clearPKCEParams();

    // Process tokens and get user info
    const result = await this.processTokenResponse(tokens);

    // Store tokens
    await this.tokenManager.storeTokens(result.tokens);

    return result;
  }

  /**
   * Get current authenticated user
   */
  async getCurrentUser(): Promise<AuthenticatedUser | null> {
    const tokens = await this.tokenManager.getTokens();
    if (!tokens) {
      return null;
    }

    try {
      const userInfo = await this.keycloak.getUserInfo(tokens.accessToken);
      return this.mapUserInfo(userInfo, tokens.accessToken);
    } catch (error) {
      // Token might be invalid
      await this.tokenManager.clearTokens();
      return null;
    }
  }

  /**
   * Check if user is authenticated
   */
  async isAuthenticated(): Promise<boolean> {
    try {
      const tokens = await this.tokenManager.getTokens();
      return tokens !== null;
    } catch {
      return false;
    }
  }

  /**
   * Get access token for API calls
   */
  async getAccessToken(): Promise<string> {
    const token = await this.tokenManager.getAccessToken();
    if (!token) {
      throw new AuthenticationRequiredError();
    }
    return token;
  }

  /**
   * Refresh tokens if needed
   */
  async refreshTokensIfNeeded(): Promise<boolean> {
    const tokens = await this.tokenManager.getTokens();
    if (!tokens || !this.tokenManager.needsRefresh(tokens)) {
      return false;
    }

    return this.refreshTokens();
  }

  /**
   * Force refresh tokens
   */
  async refreshTokens(): Promise<boolean> {
    const refreshToken = await this.tokenManager.getRefreshToken();
    if (!refreshToken) {
      throw new AuthenticationRequiredError();
    }

    try {
      const tokens = await this.keycloak.refreshTokens(refreshToken);
      const result = await this.processTokenResponse(tokens);
      await this.tokenManager.storeTokens(result.tokens);
      return true;
    } catch (error) {
      // Refresh failed, clear tokens
      await this.tokenManager.clearTokens();
      throw new AuthenticationRequiredError();
    }
  }

  /**
   * Logout user
   */
  async logout(postLogoutRedirectUri?: string): Promise<string> {
    const tokens = await this.tokenManager.getTokens();

    // Clear local tokens
    await this.tokenManager.clearTokens();

    if (tokens?.idToken) {
      // Get Keycloak logout URL
      return this.keycloak.logout(tokens.idToken, postLogoutRedirectUri);
    }

    // Return to home if no ID token
    return postLogoutRedirectUri || '/';
  }

  /**
   * Process token response and extract user info
   */
  private async processTokenResponse(tokens: TokenResponse): Promise<AuthenticationResult> {
    // Decode ID token to get user info
    const idTokenPayload = this.tokenManager.decodeToken<UserInfo>(tokens.id_token);

    // Calculate expiration time
    const expiresAt = Date.now() + (tokens.expires_in * 1000);

    // Map user info
    const user = this.mapUserInfo(idTokenPayload, tokens.access_token);

    return {
      user,
      tokens: {
        accessToken: tokens.access_token,
        idToken: tokens.id_token,
        refreshToken: tokens.refresh_token,
        expiresAt
      }
    };
  }

  /**
   * Map Keycloak user info to application user
   */
  private mapUserInfo(userInfo: UserInfo, accessToken: string): AuthenticatedUser {
    // Decode access token for additional claims
    const accessTokenPayload = this.tokenManager.decodeToken<any>(accessToken);

    // Extract roles
    const realmRoles = userInfo.realm_access?.roles || [];
    const clientRoles = userInfo.resource_access?.[this.config.keycloak.clientId]?.roles || [];
    const allRoles = [...new Set([...realmRoles, ...clientRoles])];

    // Map roles to permissions
    const permissions = this.mapRolesToPermissions(allRoles);

    return {
      id: userInfo.sub,
      email: userInfo.email,
      name: userInfo.name || userInfo.preferred_username,
      username: userInfo.preferred_username,
      roles: allRoles,
      permissions
    };
  }

  /**
   * Map user roles to application permissions
   */
  private mapRolesToPermissions(roles: string[]): UserPermissions {
    const hasRole = (role: string) => roles.includes(role);

    return {
      canCreateExperiments: hasRole('researcher') || hasRole('admin'),
      canPublishExperiments: hasRole('researcher') || hasRole('admin'),
      canAccessAnalytics: hasRole('researcher') || hasRole('admin') || hasRole('viewer'),
      canManageUsers: hasRole('admin'),
      canManageRecruitment: hasRole('researcher') || hasRole('admin'),
      maxParticipants: hasRole('admin') ? Infinity : hasRole('researcher') ? 1000 : 100,
      allowedProviders: hasRole('admin') || hasRole('researcher') 
        ? ['prolific', 'mturk', 'sona', 'direct']
        : ['direct'],
      quotaLimits: {
        experimentsPerMonth: hasRole('admin') ? undefined : hasRole('researcher') ? 50 : 5,
        participantsPerMonth: hasRole('admin') ? undefined : hasRole('researcher') ? 5000 : 500,
        storageGB: hasRole('admin') ? undefined : hasRole('researcher') ? 100 : 10
      }
    };
  }

  /**
   * Check if user has specific permission
   */
  async hasPermission(permission: keyof UserPermissions): Promise<boolean> {
    const user = await this.getCurrentUser();
    if (!user) return false;

    const value = user.permissions[permission];
    return typeof value === 'boolean' ? value : false;
  }

  /**
   * Check if user has specific role
   */
  async hasRole(role: string): Promise<boolean> {
    const user = await this.getCurrentUser();
    return user ? user.roles.includes(role) : false;
  }
}

