describe('PKCE utilities', () => {
  describe('generateCodeVerifier', () => {
    it('should generate a code verifier of correct length', () => {
      const verifier = generateCodeVerifier();
      expect(verifier).toMatch(/^[A-Za-z0-9_-]+$/);
      expect(verifier.length).toBeGreaterThanOrEqual(43);
      expect(verifier.length).toBeLessThanOrEqual(128);
    });

    it('should generate unique verifiers', () => {
      const verifier1 = generateCodeVerifier();
      const verifier2 = generateCodeVerifier();
      expect(verifier1).not.toBe(verifier2);
    });
  });

  describe('generateCodeChallenge', () => {
    it('should generate a valid code challenge', async () => {
      const verifier = 'test-verifier-string';
      const challenge = await generateCodeChallenge(verifier);

      expect(challenge).toMatch(/^[A-Za-z0-9_-]+$/);
      expect(challenge).not.toContain('+');
      expect(challenge).not.toContain('/');
      expect(challenge).not.toContain('=');
    });

    it('should generate consistent challenges for same verifier', async () => {
      const verifier = 'test-verifier-string';
      const challenge1 = await generateCodeChallenge(verifier);
      const challenge2 = await generateCodeChallenge(verifier);

      expect(challenge1).toBe(challenge2);
    });
  });

  describe('generateState', () => {
    it('should generate a state parameter', () => {
      const state = generateState();
      expect(state).toMatch(/^[A-Za-z0-9_-]+$/);
      expect(state.length).toBeGreaterThan(0);
    });

    it('should generate unique states', () => {
      const state1 = generateState();
      const state2 = generateState();
      expect(state1).not.toBe(state2);
    });
  });

  describe('buildAuthorizationUrl', () => {
    it('should build a valid authorization URL', () => {
      const params = {
        baseUrl: 'https://auth.example.com/authorize',
        clientId: 'test-client',
        redirectUri: 'https://app.example.com/callback',
        scope: 'openid profile email',
        codeChallenge: 'test-challenge',
        state: 'test-state'
      };

      const url = buildAuthorizationUrl(params);
      const urlObj = new URL(url);

      expect(urlObj.origin).toBe('https://auth.example.com');
      expect(urlObj.pathname).toBe('/authorize');
      expect(urlObj.searchParams.get('client_id')).toBe('test-client');
      expect(urlObj.searchParams.get('redirect_uri')).toBe('https://app.example.com/callback');
      expect(urlObj.searchParams.get('response_type')).toBe('code');
      expect(urlObj.searchParams.get('scope')).toBe('openid profile email');
      expect(urlObj.searchParams.get('state')).toBe('test-state');
      expect(urlObj.searchParams.get('code_challenge')).toBe('test-challenge');
      expect(urlObj.searchParams.get('code_challenge_method')).toBe('S256');
    });

    it('should include additional parameters', () => {
      const params = {
        baseUrl: 'https://auth.example.com/authorize',
        clientId: 'test-client',
        redirectUri: 'https://app.example.com/callback',
        scope: 'openid',
        codeChallenge: 'challenge',
        state: 'state',
        additionalParams: {
          prompt: 'login',
          max_age: '3600'
        }
      };

      const url = buildAuthorizationUrl(params);
      const urlObj = new URL(url);

      expect(urlObj.searchParams.get('prompt')).toBe('login');
      expect(urlObj.searchParams.get('max_age')).toBe('3600');
    });
  });

  describe('parseCallbackUrl', () => {
    it('should parse successful callback', () => {
      const url = 'https://app.example.com/callback?code=auth-code&state=test-state';
      const params = parseCallbackUrl(url);

      expect(params.code).toBe('auth-code');
      expect(params.state).toBe('test-state');
      expect(params.error).toBeUndefined();
    });

    it('should parse error callback', () => {
      const url = 'https://app.example.com/callback?error=access_denied&error_description=User+denied+access';
      const params = parseCallbackUrl(url);

      expect(params.code).toBeUndefined();
      expect(params.error).toBe('access_denied');
      expect(params.error_description).toBe('User denied access');
    });

    it('should handle missing parameters', () => {
      const url = 'https://app.example.com/callback';
      const params = parseCallbackUrl(url);

      expect(params.code).toBeUndefined();
      expect(params.state).toBeUndefined();
      expect(params.error).toBeUndefined();
    });
  });
});

