import { Container, Graphics, Text } from 'pixi.js';
import { BaseComponent, ComponentProps } from '../base/BaseComponent.js';
import { ComponentResponse } from '../../types.js';
import { EventEmitter } from 'eventemitter3';

export interface TrailsBProps extends ComponentProps {
  npoints?: number;
  radius?: number;
  fontSize?: number;
  fillColor?: string;
  strokeColor?: string;
  strokeWidth?: number;
  correctColor?: string;
  errorColor?: string;
  completedColor?: string;
  minDistance?: number;
}

interface TrailNode {
  x: number;
  y: number;
  label: string;
  index: number;
  sequenceIndex: number;
  circle: Container;
  visited: boolean;
  isNumber: boolean;
}

export class TrailsB extends BaseComponent<TrailsBProps> {
  private nodes: TrailNode[] = [];
  private currentSequenceIndex = 0;
  private pathGraphics: Graphics;
  private startTime: number = 0;
  private errors: number = 0;
  private emitter = new EventEmitter();
  private expectingNumber = true;

  constructor(props: TrailsBProps = {}) {
    super({
      npoints: 24, // 12 numbers + 12 letters
      radius: 30,
      fontSize: 20,
      fillColor: '#ffffff',
      strokeColor: '#000000',
      strokeWidth: 2,
      correctColor: '#ffff00',
      errorColor: '#ff0000',
      completedColor: '#00ff00',
      minDistance: 80,
      ...props
    });

    this.pathGraphics = new Graphics();
    this.container.addChild(this.pathGraphics);
    this.generateNodes();
  }

  private generateNodes(): void {
    const { npoints, minDistance } = this.props;
    const positions: { x: number; y: number }[] = [];

    // Generate random positions ensuring minimum distance
    const margin = 50;
    const maxAttempts = 1000;

    for (let i = 0; i < npoints; i++) {
      let placed = false;
      let attempts = 0;

      while (!placed && attempts < maxAttempts) {
        const x = margin + Math.random() * (this.props.width! - 2 * margin);
        const y = margin + Math.random() * (this.props.height! - 2 * margin);

        // Check distance from all existing positions
        let validPosition = true;
        for (const pos of positions) {
          const distance = Math.sqrt((x - pos.x) ** 2 + (y - pos.y) ** 2);
          if (distance < minDistance) {
            validPosition = false;
            break;
          }
        }

        if (validPosition) {
          positions.push({ x, y });
          placed = true;
        }
        attempts++;
      }
    }

    // Shuffle positions
    for (let i = positions.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [positions[i], positions[j]] = [positions[j], positions[i]];
    }

    // Create nodes with alternating numbers and letters
    const numPairs = npoints / 2;
    let nodeIndex = 0;

    // Add numbers (1, 2, 3, ...)
    for (let i = 0; i < numPairs; i++) {
      const pos = positions[nodeIndex++];
      const label = (i + 1).toString();
      const node = this.createNode(pos.x, pos.y, label, nodeIndex - 1, i * 2, true);
      this.nodes.push(node);
      this.container.addChild(node.circle);
    }

    // Add letters (A, B, C, ...)
    for (let i = 0; i < numPairs; i++) {
      const pos = positions[nodeIndex++];
      const label = String.fromCharCode(65 + i); // A=65 in ASCII
      const node = this.createNode(pos.x, pos.y, label, nodeIndex - 1, i * 2 + 1, false);
      this.nodes.push(node);
      this.container.addChild(node.circle);
    }
  }

  private createNode(
    x: number, 
    y: number, 
    label: string, 
    index: number, 
    sequenceIndex: number,
    isNumber: boolean
  ): TrailNode {
    const { radius, fontSize, fillColor, strokeColor, strokeWidth } = this.props;

    const nodeContainer = new Container();
    nodeContainer.x = x;
    nodeContainer.y = y;

    // Create circle
    const circle = new Graphics();
    circle.beginFill(fillColor);
    circle.lineStyle(strokeWidth, strokeColor);
    circle.drawCircle(0, 0, radius);
    circle.endFill();

    // Create text label
    const text = new Text(label, {
      fontSize,
      fill: '#000000',
      align: 'center'
    });
    text.anchor.set(0.5);

    nodeContainer.addChild(circle);
    nodeContainer.addChild(text);

    // Make interactive
    nodeContainer.eventMode = 'static';
    nodeContainer.cursor = 'pointer';

    // Handle clicks
    nodeContainer.on('pointerdown', () => this.handleNodeClick(index));

    return {
      x,
      y,
      label,
      index,
      sequenceIndex,
      circle: nodeContainer,
      visited: false,
      isNumber
    };
  }

  private handleNodeClick(clickedIndex: number): void {
    const { correctColor, errorColor, completedColor } = this.props;
    const clickedNode = this.nodes[clickedIndex];

    if (clickedNode.visited) {
      return; // Already visited
    }

    // Check if this is the correct next node in the sequence
    const isCorrectType = clickedNode.isNumber === this.expectingNumber;
    const isCorrectSequence = clickedNode.sequenceIndex === this.currentSequenceIndex;

    if (isCorrectType && isCorrectSequence) {
      // Correct click
      clickedNode.visited = true;

      // Update node appearance
      const circle = clickedNode.circle.children[0] as Graphics;
      circle.clear();
      const isLastNode = this.currentSequenceIndex === this.props.npoints - 1;
      circle.beginFill(isLastNode ? completedColor : correctColor);
      circle.lineStyle(this.props.strokeWidth, this.props.strokeColor);
      circle.drawCircle(0, 0, this.props.radius);
      circle.endFill();

      // Draw path from previous node
      if (this.currentSequenceIndex > 0) {
        const prevNode = this.nodes.find(n => n.sequenceIndex === this.currentSequenceIndex - 1)!;
        this.drawPath(prevNode.x, prevNode.y, clickedNode.x, clickedNode.y);
      }

      // Emit trail move event
      this.emitter.emit('trail_move', {
        from: this.currentSequenceIndex > 0 ? this.currentSequenceIndex - 1 : null,
        to: clickedNode.sequenceIndex,
        label: clickedNode.label,
        correct: true
      });

      // Update state
      this.currentSequenceIndex++;
      this.expectingNumber = !this.expectingNumber;

      // Check if completed
      if (this.currentSequenceIndex === this.props.npoints) {
        this.handleCompletion();
      }
    } else {
      // Incorrect click
      this.errors++;

      // Flash error color
      const circle = clickedNode.circle.children[0] as Graphics;
      const originalFill = clickedNode.visited ? correctColor : this.props.fillColor;

      circle.clear();
      circle.beginFill(errorColor);
      circle.lineStyle(this.props.strokeWidth, this.props.strokeColor);
      circle.drawCircle(0, 0, this.props.radius);
      circle.endFill();

      // Restore original color after delay
      setTimeout(() => {
        circle.clear();
        circle.beginFill(originalFill);
        circle.lineStyle(this.props.strokeWidth, this.props.strokeColor);
        circle.drawCircle(0, 0, this.props.radius);
        circle.endFill();
      }, 500);

      // Emit error event
      const expectedNode = this.nodes.find(n => 
        n.sequenceIndex === this.currentSequenceIndex && 
        n.isNumber === this.expectingNumber
      );

      this.emitter.emit('trail_error', {
        expected: expectedNode?.label,
        clicked: clickedNode.label,
        expectedType: this.expectingNumber ? 'number' : 'letter'
      });
    }
  }

  private drawPath(x1: number, y1: number, x2: number, y2: number): void {
    this.pathGraphics.lineStyle(3, 0x000000);
    this.pathGraphics.moveTo(x1, y1);
    this.pathGraphics.lineTo(x2, y2);
  }

  private handleCompletion(): void {
    const completionTime = Date.now() - this.startTime;

    // Emit completion event
    this.emitter.emit('trail_completed', {
      time: completionTime,
      errors: this.errors,
      npoints: this.props.npoints
    });

    // Emit signal for trial completion
    this.emit('signal', {
      id: 'trail_completed',
      data: {
        time: completionTime,
        errors: this.errors
      }
    });
  }

  mount(): void {
    super.mount();
    this.startTime = Date.now();
  }

  reset(): void {
    super.reset();
    this.currentSequenceIndex = 0;
    this.expectingNumber = true;
    this.errors = 0;
    this.pathGraphics.clear();

    // Reset all nodes
    this.nodes.forEach(node => {
      node.visited = false;
      const circle = node.circle.children[0] as Graphics;
      circle.clear();
      circle.beginFill(this.props.fillColor);
      circle.lineStyle(this.props.strokeWidth, this.props.strokeColor);
      circle.drawCircle(0, 0, this.props.radius);
      circle.endFill();
    });
  }

  async collectResponse(): Promise<ComponentResponse> {
    return new Promise((resolve) => {
      this.emitter.once('trail_completed', (data) => {
        resolve({
          rt: data.time,
          response: {
            completed: true,
            errors: this.errors,
            totalTime: data.time
          },
          timestamp: Date.now()
        });
      });
    });
  }

  on(event: string, handler: (...args: any[]) => void): void {
    this.emitter.on(event, handler);
  }

  off(event: string, handler: (...args: any[]) => void): void {
    this.emitter.off(event, handler);
  }
}

