    29→  tags: string[];
    30→  userData: Record<string, unknown>;
    31→}
    32→
    33→export abstract class BaseComponent {
    34→  public readonly id: string;
    35→  public readonly type: string;
    36→  protected transform: Transform;
    37→  protected metadata: ComponentMetadata;
    38→  protected isInitialized = false;
    39→  protected isDisposed = false;
    40→  protected children: BaseComponent[] = [];
    41→  protected parent?: BaseComponent;
    42→
    43→  constructor(id: string, type: string) {
    44→    this.id = id;
    45→    this.type = type;
    46→    this.transform = {
    47→      position: { x: 0, y: 0 },
