    49→      scale: { x: 1, y: 1 },
    50→      opacity: 1,
    51→      visible: true,
    52→    };
    53→    this.metadata = {
    54→      id,
    55→      type,
    56→      version: '1.0.0',
    57→      created: Date.now(),
    58→      tags: [],
    59→      userData: {},
    60→    };
    61→  }
    62→
    63→  // Lifecycle methods - must be implemented by subclasses
    64→  abstract onInit(context: ComponentContext): Promise<void>;
    65→  abstract onFrame(deltaTime: number, context: ComponentContext): void;
    66→  abstract onDispose(context: ComponentContext): Promise<void>;
    67→
    68→  // Input handling - optional override
    69→  onInput(_event: Event, _context: ComponentContext): boolean {
    70→    // Return true if event was handled, false to pass to parent
    71→    return false;
    72→  }
    73→
    74→  // Fluent API for common transformations
    75→  position(x: number, y: number, z?: number): this {
    76→    this.transform.position = { x, y, z };
    77→    return this;
    78→  }
    79→
    80→  rotate(degrees: number): this {
    81→    this.transform.rotation = degrees;
    82→    return this;
    83→  }
    84→
    85→  scale(x: number, y?: number): this {
    86→    this.transform.scale = { x, y: y ?? x };
    87→    return this;
    88→  }
    89→
    90→  opacity(alpha: number): this {
    91→    this.transform.opacity = Math.max(0, Math.min(1, alpha));
    92→    return this;
    93→  }
    94→
    95→  visible(isVisible: boolean): this {
    96→    this.transform.visible = isVisible;
    97→    return this;
    98→  }
    99→
   100→  // Hierarchy management
   101→  addChild(child: BaseComponent): this {
   102→    if (child.parent) {
   103→      child.parent.removeChild(child);
   104→    }
   105→    this.children.push(child);
   106→    child.parent = this;
   107→    return this;
   108→  }
   109→
   110→  removeChild(child: BaseComponent): boolean {
   111→    const index = this.children.indexOf(child);
   112→    if (index !== -1) {
   113→      this.children.splice(index, 1);
   114→      child.parent = undefined;
   115→      return true;
   116→    }
   117→    return false;
   118→  }
   119→
   120→  getChildren(): ReadonlyArray<BaseComponent> {
   121→    return this.children;
   122→  }
   123→  
   124→  getParent(): BaseComponent | undefined {
   125→    return this.parent;
   126→  }
   127→
   128→  // Metadata management
   129→  tag(...tags: string[]): this {
   130→    this.metadata.tags.push(...tags);
   131→    return this;
   132→  }
   133→
   134→  setUserData(key: string, value: unknown): this {
   135→    this.metadata.userData[key] = value;
   136→    return this;
   137→  }
   138→
   139→  getUserData<T>(key: string): T | undefined {
   140→    return this.metadata.userData[key] as T;
   141→  }
   142→
   143→  // Component lifecycle management
   144→  async initialize(context: ComponentContext): Promise<void> {
   145→    if (this.isInitialized || this.isDisposed) {
   146→      return;
   147→    }
   148→
   149→    await this.onInit(context);
   150→    
   151→    // Initialize children
   152→    for (const child of this.children) {
   153→      await child.initialize(context);
   154→    }
   155→
   156→    this.isInitialized = true;
   157→  }
   158→
   159→  update(deltaTime: number, context: ComponentContext): void {
   160→    if (!this.isInitialized || this.isDisposed || !this.transform.visible) {
   161→      return;
   162→    }
   163→
   164→    this.onFrame(deltaTime, context);
   165→
   166→    // Update children
   167→    for (const child of this.children) {
   168→      child.update(deltaTime, context);
   169→    }
   170→  }
   171→
   172→  handleInput(event: Event, context: ComponentContext): boolean {
   173→    if (!this.isInitialized || this.isDisposed || !this.transform.visible) {
   174→      return false;
   175→    }
   176→
   177→    // Try children first (reverse order for proper z-order)
   178→    for (let i = this.children.length - 1; i >= 0; i--) {
   179→      if (this.children[i].handleInput(event, context)) {
   180→        return true;
   181→      }
   182→    }
   183→
   184→    // Try this component
   185→    return this.onInput(event, context);
   186→  }
   187→
   188→  async dispose(context: ComponentContext): Promise<void> {
   189→    if (this.isDisposed) {
   190→      return;
   191→    }
   192→
   193→    // Dispose children first
   194→    for (const child of this.children) {
   195→      await child.dispose(context);
   196→    }
   197→
   198→    await this.onDispose(context);
   199→    this.isDisposed = true;
   200→  }
   201→
   202→  // Getters for transform properties
   203→  get worldPosition(): { x: number; y: number; z?: number } {
   204→    if (!this.parent) {
   205→      return this.transform.position;
   206→    }
   207→    
   208→    const parentPos = this.parent.worldPosition;
   209→    return {
   210→      x: parentPos.x + this.transform.position.x,
   211→      y: parentPos.y + this.transform.position.y,
   212→      z: (parentPos.z ?? 0) + (this.transform.position.z ?? 0),
   213→    };
   214→  }
   215→
   216→  get worldOpacity(): number {
   217→    if (!this.parent) {
   218→      return this.transform.opacity;
   219→    }
   220→    return this.parent.worldOpacity * this.transform.opacity;
   221→  }
   222→
   223→  // Serialization support
   224→  serialize(): Record<string, unknown> {
   225→    return {
   226→      id: this.id,
   227→      type: this.type,
   228→      transform: this.transform,
   229→      metadata: this.metadata,
   230→      children: this.children.map(child => child.serialize()),
   231→    };
   232→  }
   233→
   234→  // Query methods for finding components
   235→  findChildById(id: string): BaseComponent | undefined {
   236→    for (const child of this.children) {
   237→      if (child.id === id) {
   238→        return child;
   239→      }
   240→      const found = child.findChildById(id);
   241→      if (found) {
   242→        return found;
   243→      }
   244→    }
   245→    return undefined;
   246→  }
   247→
   248→  findChildrenByType(type: string): BaseComponent[] {
   249→    const results: BaseComponent[] = [];
   250→    for (const child of this.children) {
   251→      if (child.type === type) {
   252→        results.push(child);
   253→      }
   254→      results.push(...child.findChildrenByType(type));
   255→    }
   256→    return results;
   257→  }
   258→
   259→  findChildrenByTag(tag: string): BaseComponent[] {
   260→    const results: BaseComponent[] = [];
   261→    for (const child of this.children) {
   262→      if (child.metadata.tags.includes(tag)) {
   263→        results.push(child);
   264→      }
   265→      results.push(...child.findChildrenByTag(tag));
   266→    }
   267→    return results;
   268→  }
   269→}

