import * as PIXI from 'pixi.js';
import { BaseComponent, type ComponentContext } from '../BaseComponent.js';
import type { PrecisionTimestamp } from '@psyforge/timing';

export interface TrailsAOptions {
  npoints?: number;
  radius?: number;
  fontSize?: number;
  fillColor?: number;
  strokeColor?: number;
  strokeWidth?: number;
  correctColor?: number;
  errorColor?: number;
  completedColor?: number;
  minDistance?: number;
  width?: number;
  height?: number;
}

interface TrailNode {
  x: number;
  y: number;
  label: string;
  index: number;
  circle: PIXI.Container;
  visited: boolean;
}

export class TrailsAComponent extends BaseComponent {
  private options: Required<TrailsAOptions>;
  private app?: PIXI.Application;
  private container: PIXI.Container;
  private nodes: TrailNode[] = [];
  private currentIndex = 0;
  private pathGraphics: PIXI.Graphics;
  private startTime?: PrecisionTimestamp;
  private errors = 0;
  private onCompleteCallback?: (data: any) => void;
  private isActive = false;

  constructor(id: string, options: TrailsAOptions = {}) {
    super(id, 'TrailsA');

    this.options = {
      npoints: 25,
      radius: 30,
      fontSize: 20,
      fillColor: 0xffffff,
      strokeColor: 0x000000,
      strokeWidth: 2,
      correctColor: 0xffff00,
      errorColor: 0xff0000,
      completedColor: 0x00ff00,
      minDistance: 80,
      width: 800,
      height: 600,
      ...options
    };

    this.container = new PIXI.Container();
    this.pathGraphics = new PIXI.Graphics();
    this.container.addChild(this.pathGraphics);
  }

  async onInit(context: ComponentContext): Promise<void> {
    // Get PIXI app from context or create one
    this.app = await this.getOrCreateApp(context);

    // Generate the trail nodes
    this.generateNodes();

    // Add container to stage
    this.app.stage.addChild(this.container);

    // Apply transform
    this.container.position.set(this.transform.position.x, this.transform.position.y);
    this.container.alpha = this.transform.opacity;
    this.container.rotation = this.transform.rotation * (Math.PI / 180);

    // Make canvas interactive
    if (context.canvas) {
      context.canvas.style.pointerEvents = 'auto';
    }
  }

  onFrame(_deltaTime: number, _context: ComponentContext): void {
    // Update container transform if needed
    if (this.container) {
      this.container.position.set(this.transform.position.x, this.transform.position.y);
      this.container.alpha = this.transform.opacity;
      this.container.visible = this.transform.visible;
    }
  }

  async onDispose(_context: ComponentContext): Promise<void> {
    // Clean up PIXI resources
    if (this.app && this.container) {
      this.app.stage.removeChild(this.container);
      this.container.destroy({ children: true });
    }

    this.nodes = [];
    this.isActive = false;
  }

  private async getOrCreateApp(context: ComponentContext): Promise<PIXI.Application> {
    // Check if PIXI app already exists
    if ((window as any).__psyforgePixiApp) {
      return (window as any).__psyforgePixiApp;
    }

    const app = new PIXI.Application();

    await app.init({
      width: this.options.width,
      height: this.options.height,
      antialias: true,
      resolution: window.devicePixelRatio || 1,
      autoDensity: true,
      backgroundColor: 0xf0f0f0,
      canvas: context.canvas,
    });

    app.stage.sortableChildren = true;

    if (!context.canvas) {
      document.body.appendChild(app.canvas);
      app.canvas.style.position = 'fixed';
      app.canvas.style.top = '0';
      app.canvas.style.left = '0';
    }

    (window as any).__psyforgePixiApp = app;

    return app;
  }

  private generateNodes(): void {
    const { npoints, minDistance, width, height } = this.options;
    const positions: { x: number; y: number }[] = [];

    const margin = 50;
    const maxAttempts = 1000;

    // Generate random positions
    for (let i = 0; i < npoints; i++) {
      let placed = false;
      let attempts = 0;

      while (!placed && attempts < maxAttempts) {
        const x = margin + Math.random() * (width - 2 * margin);
        const y = margin + Math.random() * (height - 2 * margin);

        let validPosition = true;
        for (const pos of positions) {
          const distance = Math.sqrt((x - pos.x) ** 2 + (y - pos.y) ** 2);
          if (distance < minDistance) {
            validPosition = false;
            break;
          }
        }

        if (validPosition) {
          positions.push({ x, y });
          placed = true;
        }
        attempts++;
      }
    }

    // Create nodes with sequential numbers
    positions.forEach((pos, index) => {
      const node = this.createNode(pos.x, pos.y, (index + 1).toString(), index);
      this.nodes.push(node);
      this.container.addChild(node.circle);
    });
  }

  private createNode(x: number, y: number, label: string, index: number): TrailNode {
    const { radius, fontSize, fillColor, strokeColor, strokeWidth } = this.options;

    const nodeContainer = new PIXI.Container();
    nodeContainer.x = x;
    nodeContainer.y = y;

    // Create circle
    const circle = new PIXI.Graphics();
    circle.circle(0, 0, radius);
    circle.fill(fillColor);
    circle.stroke({ width: strokeWidth, color: strokeColor });

    // Create text label
    const text = new PIXI.Text({
      text: label,
      style: {
        fontSize,
        fill: 0x000000,
        align: 'center'
      }
    });
    text.anchor.set(0.5);

    nodeContainer.addChild(circle);
    nodeContainer.addChild(text);

    // Make interactive
    nodeContainer.eventMode = 'static';
    nodeContainer.cursor = 'pointer';

    // Handle clicks
    nodeContainer.on('pointerdown', () => this.handleNodeClick(index));

    return {
      x,
      y,
      label,
      index,
      circle: nodeContainer,
      visited: false
    };
  }

  private handleNodeClick(clickedIndex: number): void {
    if (!this.isActive) return;

    const { correctColor, errorColor, completedColor } = this.options;
    const clickedNode = this.nodes[clickedIndex];

    if (clickedNode.visited) return;

    if (clickedIndex === this.currentIndex) {
      // Correct click
      clickedNode.visited = true;

      // Update appearance
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
      circle.circle(0, 0, this.options.radius);
      circle.fill(clickedIndex === this.nodes.length - 1 ? completedColor : correctColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });

      // Draw path
      if (this.currentIndex > 0) {
        const prevNode = this.nodes[this.currentIndex - 1];
        this.drawPath(prevNode.x, prevNode.y, clickedNode.x, clickedNode.y);
      }

      this.currentIndex++;

      // Check completion
      if (this.currentIndex === this.nodes.length) {
        this.handleCompletion();
      }
    } else {
      // Incorrect click
      this.errors++;

      // Flash error
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
      circle.circle(0, 0, this.options.radius);
      circle.fill(errorColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });

      // Restore after delay
      setTimeout(() => {
        circle.clear();
        circle.circle(0, 0, this.options.radius);
        circle.fill(clickedNode.visited ? correctColor : this.options.fillColor);
        circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });
      }, 500);
    }
  }

  private drawPath(x1: number, y1: number, x2: number, y2: number): void {
    this.pathGraphics.moveTo(x1, y1);
    this.pathGraphics.lineTo(x2, y2);
    this.pathGraphics.stroke({ width: 3, color: 0x000000 });
  }

  private handleCompletion(): void {
    this.isActive = false;
    const completionTime = this.startTime ? Date.now() - this.startTime.timestamp : 0;

    const data = {
      time: completionTime,
      errors: this.errors,
