export class TrailsAComponent extends BaseComponent {
  private options: Required<TrailsAOptions>;
  private app?: PIXI.Application;
  private container: PIXI.Container;
  private nodes: TrailNode[] = [];
  private currentIndex = 0;
  private pathGraphics: PIXI.Graphics;
  private startTime?: PrecisionTimestamp;
  private errors = 0;
  private onCompleteCallback?: (data: any) => void;
  private isActive = false;

  constructor(id: string, options: TrailsAOptions = {}) {
    super(id, 'TrailsA');

    this.options = {
