    x: number, 
    y: number, 
    label: string, 
    index: number, 
    sequenceIndex: number,
    isNumber: boolean
  ): TrailNode {
    const { radius, fontSize, fillColor, strokeColor, strokeWidth } = this.options;

    const nodeContainer = new PIXI.Container();
    nodeContainer.x = x;
    nodeContainer.y = y;

