    if (!this.isActive) return;

    const { correctColor, errorColor, completedColor } = this.options;
    const clickedNode = this.nodes[clickedIndex];

    if (clickedNode.visited) return;

    // Check if correct
    const isCorrectType = clickedNode.isNumber === this.expectingNumber;
    const isCorrectSequence = clickedNode.sequenceIndex === this.currentSequenceIndex;

    if (isCorrectType && isCorrectSequence) {
      // Correct click
      clickedNode.visited = true;

      // Update appearance
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
      const isLastNode = this.currentSequenceIndex === this.options.npoints - 1;
      circle.circle(0, 0, this.options.radius);
      circle.fill(isLastNode ? completedColor : correctColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });

      // Draw path
      if (this.currentSequenceIndex > 0) {
        const prevNode = this.nodes.find(n => n.sequenceIndex === this.currentSequenceIndex - 1)!;
        this.drawPath(prevNode.x, prevNode.y, clickedNode.x, clickedNode.y);
      }

      // Update state
      this.currentSequenceIndex++;
      this.expectingNumber = !this.expectingNumber;

      // Check completion
      if (this.currentSequenceIndex === this.options.npoints) {
        this.handleCompletion();
      }
    } else {
      // Incorrect click
      this.errors++;

      // Flash error
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
