        circle.circle(0, 0, this.options.radius);
        circle.fill(clickedNode.visited ? correctColor : this.options.fillColor);
        circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });
      }, 500);
    }
  }

  private drawPath(x1: number, y1: number, x2: number, y2: number): void {
    this.pathGraphics.moveTo(x1, y1);
    this.pathGraphics.lineTo(x2, y2);
    this.pathGraphics.stroke({ width: 3, color: 0x000000 });
  }

  private handleCompletion(): void {
    this.isActive = false;
    const completionTime = this.startTime ? Date.now() - this.startTime.timestamp : 0;

    const data = {
      time: completionTime,
      errors: this.errors,
      npoints: this.options.npoints
    };

    if (this.onCompleteCallback) {
      this.onCompleteCallback(data);
    }
  }

  // Public API
  start(context: ComponentContext): void {
    this.startTime = context.clock.now();
    this.isActive = true;
    this.currentSequenceIndex = 0;
    this.expectingNumber = true;
    this.errors = 0;
  }

  reset(): void {
    this.currentSequenceIndex = 0;
    this.expectingNumber = true;
    this.errors = 0;
    this.isActive = false;
    this.pathGraphics.clear();

    // Reset all nodes
    this.nodes.forEach(node => {
      node.visited = false;
      const circle = node.circle.children[0] as PIXI.Graphics;
      circle.clear();
      circle.circle(0, 0, this.options.radius);
      circle.fill(this.options.fillColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });
    });
  }

  onComplete(callback: (data: any) => void): void {
    this.onCompleteCallback = callback;
  }

  getErrors(): number {
    return this.errors;
  }

  isCompleted(): boolean {
    return this.currentSequenceIndex === this.options.npoints;
  }

  getCurrentExpectedLabel(): string {
    const node = this.nodes.find(n => 
      n.sequenceIndex === this.currentSequenceIndex && 
      n.isNumber === this.expectingNumber
    );
    return node ? node.label : '';
  }
}

