  }

  private generateNodes(): void {
    const { npoints, minDistance, width, height } = this.options;
    const positions: { x: number; y: number }[] = [];

    const margin = 50;
    const maxAttempts = 1000;

    // Generate random positions
    for (let i = 0; i < npoints; i++) {
      let placed = false;
      let attempts = 0;

      while (!placed && attempts < maxAttempts) {
        const x = margin + Math.random() * (width - 2 * margin);
        const y = margin + Math.random() * (height - 2 * margin);

        let validPosition = true;
        for (const pos of positions) {
          const distance = Math.sqrt((x - pos.x) ** 2 + (y - pos.y) ** 2);
          if (distance < minDistance) {
            validPosition = false;
            break;
          }
        }

        if (validPosition) {
          positions.push({ x, y });
          placed = true;
        }
        attempts++;
      }
    }

    // Shuffle positions
    for (let i = positions.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [positions[i], positions[j]] = [positions[j], positions[i]];
    }

    // Create nodes with alternating numbers and letters
    const numPairs = npoints / 2;
    let nodeIndex = 0;

    // Add numbers (1, 2, 3, ...)
    for (let i = 0; i < numPairs; i++) {
      const pos = positions[nodeIndex++];
      const label = (i + 1).toString();
      const node = this.createNode(pos.x, pos.y, label, nodeIndex - 1, i * 2, true);
      this.nodes.push(node);
      this.container.addChild(node.circle);
    }

    // Add letters (A, B, C, ...)
    for (let i = 0; i < numPairs; i++) {
      const pos = positions[nodeIndex++];
      const label = String.fromCharCode(65 + i); // A=65 in ASCII
      const node = this.createNode(pos.x, pos.y, label, nodeIndex - 1, i * 2 + 1, false);
      this.nodes.push(node);
      this.container.addChild(node.circle);
    }
  }

  private createNode(
    x: number, 
    y: number, 
    label: string, 
    index: number, 
    sequenceIndex: number,
    isNumber: boolean
  ): TrailNode {
    const { radius, fontSize, fillColor, strokeColor, strokeWidth } = this.options;

    const nodeContainer = new PIXI.Container();
    nodeContainer.x = x;
    nodeContainer.y = y;

    // Create circle
    const circle = new PIXI.Graphics();
    circle.circle(0, 0, radius);
    circle.fill(fillColor);
    circle.stroke({ width: strokeWidth, color: strokeColor });

    // Create text label
    const text = new PIXI.Text({
      text: label,
      style: {
        fontSize,
        fill: 0x000000,
        align: 'center'
      }
    });
    text.anchor.set(0.5);

    nodeContainer.addChild(circle);
    nodeContainer.addChild(text);

    // Make interactive
    nodeContainer.eventMode = 'static';
    nodeContainer.cursor = 'pointer';

    // Handle clicks
    nodeContainer.on('pointerdown', () => this.handleNodeClick(index));

    return {
      x,
      y,
      label,
      index,
      sequenceIndex,
      circle: nodeContainer,
      visited: false,
      isNumber
    };
  }

  private handleNodeClick(clickedIndex: number): void {
    if (!this.isActive) return;

    const { correctColor, errorColor, completedColor } = this.options;
    const clickedNode = this.nodes[clickedIndex];

    if (clickedNode.visited) return;

    // Check if correct
    const isCorrectType = clickedNode.isNumber === this.expectingNumber;
    const isCorrectSequence = clickedNode.sequenceIndex === this.currentSequenceIndex;

    if (isCorrectType && isCorrectSequence) {
      // Correct click
      clickedNode.visited = true;

      // Update appearance
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
      const isLastNode = this.currentSequenceIndex === this.options.npoints - 1;
      circle.circle(0, 0, this.options.radius);
      circle.fill(isLastNode ? completedColor : correctColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });

      // Draw path
      if (this.currentSequenceIndex > 0) {
        const prevNode = this.nodes.find(n => n.sequenceIndex === this.currentSequenceIndex - 1)!;
        this.drawPath(prevNode.x, prevNode.y, clickedNode.x, clickedNode.y);
      }

      // Update state
      this.currentSequenceIndex++;
      this.expectingNumber = !this.expectingNumber;

      // Check completion
      if (this.currentSequenceIndex === this.options.npoints) {
        this.handleCompletion();
      }
    } else {
      // Incorrect click
      this.errors++;

      // Flash error
      const circle = clickedNode.circle.children[0] as PIXI.Graphics;
      circle.clear();
      circle.circle(0, 0, this.options.radius);
      circle.fill(errorColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });

      // Restore after delay
      setTimeout(() => {
        circle.clear();
        circle.circle(0, 0, this.options.radius);
        circle.fill(clickedNode.visited ? correctColor : this.options.fillColor);
        circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });
      }, 500);
    }
  }

  private drawPath(x1: number, y1: number, x2: number, y2: number): void {
    this.pathGraphics.moveTo(x1, y1);
    this.pathGraphics.lineTo(x2, y2);
    this.pathGraphics.stroke({ width: 3, color: 0x000000 });
  }

  private handleCompletion(): void {
    this.isActive = false;
    const completionTime = this.startTime ? Date.now() - this.startTime.timestamp : 0;

    const data = {
      time: completionTime,
      errors: this.errors,
      npoints: this.options.npoints
    };

    if (this.onCompleteCallback) {
      this.onCompleteCallback(data);
    }
  }

  // Public API
  start(context: ComponentContext): void {
    this.startTime = context.clock.now();
    this.isActive = true;
    this.currentSequenceIndex = 0;
    this.expectingNumber = true;
    this.errors = 0;
  }

  reset(): void {
    this.currentSequenceIndex = 0;
    this.expectingNumber = true;
    this.errors = 0;
    this.isActive = false;
    this.pathGraphics.clear();

    // Reset all nodes
    this.nodes.forEach(node => {
      node.visited = false;
      const circle = node.circle.children[0] as PIXI.Graphics;
      circle.clear();
      circle.circle(0, 0, this.options.radius);
      circle.fill(this.options.fillColor);
      circle.stroke({ width: this.options.strokeWidth, color: this.options.strokeColor });
    });
  }

  onComplete(callback: (data: any) => void): void {
    this.onCompleteCallback = callback;
  }

  getErrors(): number {
    return this.errors;
  }

  isCompleted(): boolean {
    return this.currentSequenceIndex === this.options.npoints;
  }

  getCurrentExpectedLabel(): string {
    const node = this.nodes.find(n => 
      n.sequenceIndex === this.currentSequenceIndex && 
      n.isNumber === this.expectingNumber
    );
    return node ? node.label : '';
  }
}

