import { describe, it, expect, vi, beforeEach } from 'vitest';
import { TrailsAComponent } from '../TrailsA.js';
import type { ComponentContext } from '../../BaseComponent.js';
import { PrecisionClock } from '@psyforge/timing';
import { DeviceManager } from '@psyforge/devices';
import { Scheduler } from '@psyforge/scheduling';

// Mock PIXI
vi.mock('pixi.js', () => ({
  Application: vi.fn().mockImplementation(() => ({
    init: vi.fn().mockResolvedValue(undefined),
    stage: {
      addChild: vi.fn(),
      removeChild: vi.fn(),
      sortableChildren: true
    },
    canvas: document.createElement('canvas'),
    renderer: {
      resize: vi.fn()
    }
  })),
  Container: vi.fn().mockImplementation(() => ({
    position: { set: vi.fn() },
    alpha: 1,
    rotation: 0,
    visible: true,
    addChild: vi.fn(),
    removeChild: vi.fn(),
    children: [],
    destroy: vi.fn(),
    x: 0,
    y: 0,
    eventMode: 'static',
    cursor: 'pointer',
    on: vi.fn()
  })),
  Graphics: vi.fn().mockImplementation(() => ({
    circle: vi.fn(),
    fill: vi.fn(),
    stroke: vi.fn(),
    clear: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    children: []
  })),
