   354→
   355→// Helper function to generate counterbalanced Stroop conditions
   356→function generateStroopConditions(
   357→  numTrials: number, 
   358→  trialType: 'practice' | 'test',
   359→  blockNumber: number
   360→): StroopCondition[] {
   361→  const words = Object.keys(COLOR_MAP);
   362→  const conditions: StroopCondition[] = [];
   363→  
   364→  // Ensure equal distribution of congruent and incongruent trials
   365→  const halfTrials = Math.floor(numTrials / 2);
   366→  
   367→  // Generate congruent trials
   368→  for (let i = 0; i < halfTrials; i++) {
   369→    const wordIndex = i % words.length;
   370→    const word = words[wordIndex];
   371→    conditions.push({
   372→      word,
   373→      color: word,
   374→      colorHex: COLOR_MAP[word as keyof typeof COLOR_MAP],
   375→      congruent: true,
   376→      trialType,
   377→      blockNumber,
   378→      trialNumber: i + 1
   379→    });
   380→  }
   381→  
   382→  // Generate incongruent trials
   383→  for (let i = 0; i < numTrials - halfTrials; i++) {
   384→    const wordIndex = i % words.length;
   385→    const colorIndex = (wordIndex + 1 + Math.floor(i / words.length)) % words.length;
   386→    const word = words[wordIndex];
   387→    const color = words[colorIndex];
   388→    
   389→    conditions.push({
   390→      word,
   391→      color,
   392→      colorHex: COLOR_MAP[color as keyof typeof COLOR_MAP],
   393→      congruent: false,
   394→      trialType,
   395→      blockNumber,
   396→      trialNumber: halfTrials + i + 1
   397→    });
   398→  }
   399→  
   400→  // Shuffle conditions for randomization
   401→  return shuffleArray(conditions);
   402→}
   403→
   404→// Helper function to add a Stroop trial to the experiment
   405→function addStroopTrial(
   406→  experimentBuilder: any,
   407→  condition: StroopCondition,
   408→  index: number
   409→) {
   410→  // Fixation cross
   411→  experimentBuilder.trial()
   412→    .stimulus(() => new TextStimulusPixi(
   413→      `fixation-${condition.trialType}-${index}`,
   414→      '+',
   415→      {
   416→        fontSize: 48,
   417→        color: '#FFFFFF',
   418→        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
   419→      }
   420→    ))
   421→    .duration(500);
   422→  
   423→  // Stroop stimulus with response collection
   424→  experimentBuilder.trial()
   425→    .stimulus(() => new TextStimulusPixi(
   426→      `stroop-${condition.trialType}-${index}`,
   427→      condition.word,
   428→      {
   429→        fontSize: 72,
   430→        fontWeight: 'bold',
   431→        color: condition.colorHex,
   432→        position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
   433→      }
   434→    ))
   435→    .response('keyboard', {
   436→      keys: ['r', 'g', 'b', 'y'],
   437→      timeout: 3000,
