/**
 * Core Trial abstraction for the simplified ForgeScript API
 * 
 * A Trial represents a single unit of an experiment with:
 * - Stimuli to present
 * - Response to collect
 * - Data to record
 * 
 * The Trial lifecycle is managed automatically:
 * 1. Show stimuli in sequence
 * 2. Collect response
 * 3. Record data with automatic RT and accuracy
 * 4. Clean up and proceed
 */

import { Stimulus } from './Stimulus';
import { Response } from './Response';

export interface TrialData {
  [key: string]: any;
}

export interface TrialOptions {
  /**
   * Unique identifier for this trial
   */
  id?: string;

  /**
   * Stimuli to present in this trial
   * Can be a single stimulus or an array presented in sequence
   */
  stimuli: Stimulus | Stimulus[];

  /**
   * Response to collect
   */
  response: Response;

  /**
   * Custom data to record for this trial
   * RT, response, and accuracy are added automatically
   */
  data?: TrialData;

  /**
   * Inter-trial interval in milliseconds
   * @default 0
   */
  iti?: number;
}

export class Trial {
  public readonly id: string;
  public readonly stimuli: Stimulus[];
  public readonly response: Response;
  public readonly data: TrialData;
  public readonly iti: number;

  constructor(options: TrialOptions) {
    this.id = options.id || `trial-${Date.now()}-${Math.random()}`;
    this.stimuli = Array.isArray(options.stimuli) ? options.stimuli : [options.stimuli];
    this.response = options.response;
    this.data = options.data || {};
    this.iti = options.iti || 0;
  }

  /**
   * Create a copy of this trial with modified properties
   * Supports immutable updates
   */
  with(updates: Partial<TrialOptions>): Trial {
    return new Trial({
      id: updates.id ?? this.id,
      stimuli: updates.stimuli ?? this.stimuli,
      response: updates.response ?? this.response,
      data: updates.data ?? this.data,
      iti: updates.iti ?? this.iti
    });
  }

  /**
   * Get the total duration of all stimuli in this trial
   */
  getStimulusDuration(): number {
    return this.stimuli.reduce((total, stim) => total + (stim.duration || 0), 0);
  }

  /**
   * Validate that this trial is properly configured
   */
  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (this.stimuli.length === 0) {
      errors.push('Trial must have at least one stimulus');
    }

    if (!this.response) {
      errors.push('Trial must have a response configuration');
    }

    // Validate each stimulus
    this.stimuli.forEach((stim, i) => {
      const stimValidation = stim.validate();
      if (!stimValidation.valid) {
        errors.push(...stimValidation.errors.map(e => `Stimulus ${i}: ${e}`));
      }
    });

    // Validate response
    const responseValidation = this.response.validate();
    if (!responseValidation.valid) {
      errors.push(...responseValidation.errors.map(e => `Response: ${e}`));
    }

    return {
      valid: errors.length === 0,
      errors
    };
  }

  /**
   * Convert to a plain object for serialization
   */
  toJSON(): object {
    return {
      id: this.id,
      stimuli: this.stimuli.map(s => s.toJSON()),
      response: this.response.toJSON(),
      data: this.data,
      iti: this.iti
    };
  }

  /**
   * Create a Trial from a plain object
   */
  static fromJSON(json: any): Trial {
    return new Trial({
      id: json.id,
      stimuli: json.stimuli.map((s: any) => Stimulus.fromJSON(s)),
      response: Response.fromJSON(json.response),
      data: json.data,
      iti: json.iti
    });
  }
}

