/**
 * Base Stimulus class for the simplified ForgeScript API
 * 
 * Provides common functionality for all stimulus types with:
 * - Simple positioning (no manual x/y calculations)
 * - Automatic timing
 * - Consistent styling interface
 */

export type Position = 'center' | 'top' | 'bottom' | 'left' | 'right' | 
                      'top-left' | 'top-right' | 'bottom-left' | 'bottom-right';

export interface StimulusOptions {
  /**
   * Unique identifier for this stimulus
   */
  id?: string;

  /**
   * Position on screen using semantic positioning
   * @default 'center'
   */
  position?: Position;

  /**
   * Duration to display in milliseconds
   * If not specified, waits for response
   */
  duration?: number;

  /**
   * CSS class name for custom styling
   */
  className?: string;

  /**
   * Inline styles
   */
  style?: Record<string, any>;
}

export abstract class Stimulus {
  public readonly id: string;
  public readonly position: Position;
  public readonly duration?: number;
  public readonly className?: string;
  public readonly style?: Record<string, any>;

  constructor(options: StimulusOptions) {
    this.id = options.id || `stim-${Date.now()}-${Math.random()}`;
    this.position = options.position || 'center';
    this.duration = options.duration;
    this.className = options.className;
    this.style = options.style;
  }

  /**
   * Get the absolute x,y coordinates for this position
   * @param containerWidth Width of the container
   * @param containerHeight Height of the container
   */
  getCoordinates(containerWidth: number, containerHeight: number): { x: number; y: number } {
    const margin = 50; // Default margin from edges

    switch (this.position) {
      case 'center':
        return { x: containerWidth / 2, y: containerHeight / 2 };
      case 'top':
        return { x: containerWidth / 2, y: margin };
      case 'bottom':
        return { x: containerWidth / 2, y: containerHeight - margin };
      case 'left':
        return { x: margin, y: containerHeight / 2 };
      case 'right':
        return { x: containerWidth - margin, y: containerHeight / 2 };
      case 'top-left':
        return { x: margin, y: margin };
      case 'top-right':
        return { x: containerWidth - margin, y: margin };
      case 'bottom-left':
        return { x: margin, y: containerHeight - margin };
      case 'bottom-right':
        return { x: containerWidth - margin, y: containerHeight - margin };
      default:
        return { x: containerWidth / 2, y: containerHeight / 2 };
    }
  }

  /**
   * Validate this stimulus configuration
   */
  abstract validate(): { valid: boolean; errors: string[] };

  /**
   * Convert to plain object for serialization
   */
  abstract toJSON(): object;

  /**
   * Create stimulus from plain object
   */
  static fromJSON(json: any): Stimulus {
    // This will be overridden by a factory method that knows about all stimulus types
    throw new Error('Use specific stimulus type fromJSON methods');
  }
}

/**
 * Text stimulus
 */
export interface TextOptions extends StimulusOptions {
  /**
   * Text content to display
   */
  content: string;

  /**
   * Font size in pixels
   * @default 24
   */
  fontSize?: number;

  /**
   * Font family
   * @default 'Arial, sans-serif'
   */
  fontFamily?: string;

  /**
   * Text color
   * @default '#000000'
   */
  color?: string;

  /**
   * Font weight
   * @default 'normal'
   */
  fontWeight?: 'normal' | 'bold' | 'lighter' | 'bolder' | number;
}

export class Text extends Stimulus {
  public readonly content: string;
  public readonly fontSize: number;
  public readonly fontFamily: string;
  public readonly color: string;
  public readonly fontWeight: string | number;

  constructor(options: TextOptions) {
    super(options);
    this.content = options.content;
    this.fontSize = options.fontSize || 24;
    this.fontFamily = options.fontFamily || 'Arial, sans-serif';
    this.color = options.color || '#000000';
    this.fontWeight = options.fontWeight || 'normal';
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.content) {
      errors.push('Text stimulus must have content');
    }

    if (this.fontSize <= 0) {
      errors.push('Font size must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'text',
      id: this.id,
      position: this.position,
      duration: this.duration,
      className: this.className,
      style: this.style,
      content: this.content,
      fontSize: this.fontSize,
      fontFamily: this.fontFamily,
      color: this.color,
      fontWeight: this.fontWeight
    };
  }
}

/**
 * Fixation cross stimulus
 */
export interface FixationCrossOptions extends StimulusOptions {
  /**
   * Size of the cross in pixels
   * @default 30
   */
  size?: number;

  /**
   * Line thickness in pixels
   * @default 3
   */
  thickness?: number;

  /**
   * Color of the cross
   * @default '#000000'
   */
  color?: string;
}

export class FixationCross extends Stimulus {
  public readonly size: number;
  public readonly thickness: number;
  public readonly color: string;

  constructor(options: FixationCrossOptions = {}) {
    super(options);
    this.size = options.size || 30;
    this.thickness = options.thickness || 3;
    this.color = options.color || '#000000';
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (this.size <= 0) {
      errors.push('Fixation cross size must be positive');
    }

    if (this.thickness <= 0) {
      errors.push('Fixation cross thickness must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'fixation',
      id: this.id,
      position: this.position,
      duration: this.duration,
      className: this.className,
      style: this.style,
      size: this.size,
      thickness: this.thickness,
      color: this.color
    };
  }
}

/**
 * Image stimulus
 */
export interface ImageOptions extends StimulusOptions {
  /**
   * URL or path to the image
   */
  src: string;

  /**
   * Width in pixels (if not specified, uses natural width)
   */
  width?: number;

  /**
   * Height in pixels (if not specified, uses natural height)
   */
  height?: number;

  /**
   * Alt text for accessibility
   */
  alt?: string;
}

export class Image extends Stimulus {
  public readonly src: string;
  public readonly width?: number;
  public readonly height?: number;
  public readonly alt?: string;

  constructor(options: ImageOptions) {
    super(options);
    this.src = options.src;
    this.width = options.width;
    this.height = options.height;
    this.alt = options.alt;
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.src) {
      errors.push('Image stimulus must have a source');
    }

