/**
 * Response collection abstractions for the simplified ForgeScript API
 * 
 * Handles all response types with:
 * - Automatic RT measurement
 * - Built-in timeout handling
 * - Accuracy calculation when correct response is specified
 */

export interface ResponseOptions {
  /**
   * Maximum time to wait for response in milliseconds
   * If not specified, waits indefinitely
   */
  timeout?: number;

  /**
   * The correct response for accuracy calculation
   */
  correct?: any;

  /**
   * Custom data to record with this response
   */
  data?: Record<string, any>;
}

export abstract class Response {
  public readonly timeout?: number;
  public readonly correct?: any;
  public readonly data?: Record<string, any>;

  constructor(options: ResponseOptions) {
    this.timeout = options.timeout;
    this.correct = options.correct;
    this.data = options.data;
  }

  /**
   * Check if a response is correct
   */
  isCorrect(response: any): boolean {
    if (this.correct === undefined) {
      return true; // No correct response defined
    }
    return response === this.correct;
  }

  /**
   * Validate this response configuration
   */
  abstract validate(): { valid: boolean; errors: string[] };

  /**
   * Convert to plain object for serialization
   */
  abstract toJSON(): object;

  /**
   * Create response from plain object
   */
  static fromJSON(json: any): Response {
    throw new Error('Use specific response type fromJSON methods');
  }
}

/**
 * Keyboard response
 */
export interface KeypressOptions extends ResponseOptions {
  /**
   * Valid keys to accept
   * Can be single characters ('a', 'b') or special keys ('space', 'enter')
   */
  validKeys: string[];

  /**
   * Whether to capture the first valid keypress only
   * @default true
   */
  captureFirst?: boolean;
}

export class KeypressResponse extends Response {
  public readonly validKeys: string[];
  public readonly captureFirst: boolean;

  constructor(options: KeypressOptions) {
    super(options);
    this.validKeys = options.validKeys;
    this.captureFirst = options.captureFirst !== false;
  }

  /**
   * Check if a key is valid
   */
  isValidKey(key: string): boolean {
    return this.validKeys.includes(key);
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.validKeys || this.validKeys.length === 0) {
      errors.push('Keypress response must have at least one valid key');
    }

    if (this.timeout !== undefined && this.timeout <= 0) {
      errors.push('Timeout must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'keypress',
      validKeys: this.validKeys,
      captureFirst: this.captureFirst,
      timeout: this.timeout,
      correct: this.correct,
      data: this.data
    };
  }
}

/**
 * Mouse click response
 */
export interface MouseOptions extends ResponseOptions {
  /**
   * Valid mouse buttons to accept
   * @default ['left']
   */
  validButtons?: ('left' | 'right' | 'middle')[];

  /**
   * Target areas that can be clicked
   * If not specified, any click is valid
   */
  targets?: string[]; // Stimulus IDs
}

export class MouseResponse extends Response {
  public readonly validButtons: ('left' | 'right' | 'middle')[];
  public readonly targets?: string[];

  constructor(options: MouseOptions) {
    super(options);
    this.validButtons = options.validButtons || ['left'];
    this.targets = options.targets;
  }

  /**
   * Check if a mouse button is valid
   */
  isValidButton(button: 'left' | 'right' | 'middle'): boolean {
    return this.validButtons.includes(button);
  }

  /**
   * Check if a target is valid
   */
  isValidTarget(targetId: string): boolean {
    if (!this.targets) return true; // Any target is valid
    return this.targets.includes(targetId);
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.validButtons || this.validButtons.length === 0) {
      errors.push('Mouse response must have at least one valid button');
    }

    if (this.timeout !== undefined && this.timeout <= 0) {
      errors.push('Timeout must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'mouse',
      validButtons: this.validButtons,
      targets: this.targets,
      timeout: this.timeout,
      correct: this.correct,
      data: this.data
    };
  }
}

/**
 * Touch response (for mobile/tablet)
 */
export interface TouchOptions extends ResponseOptions {
  /**
   * Target areas that can be touched
   * If not specified, any touch is valid
   */
  targets?: string[]; // Stimulus IDs

  /**
   * Whether to accept multi-touch gestures
   * @default false
   */
  multiTouch?: boolean;
}

export class TouchResponse extends Response {
  public readonly targets?: string[];
  public readonly multiTouch: boolean;

  constructor(options: TouchOptions) {
    super(options);
    this.targets = options.targets;
    this.multiTouch = options.multiTouch || false;
  }

  /**
   * Check if a target is valid
   */
  isValidTarget(targetId: string): boolean {
    if (!this.targets) return true; // Any target is valid
    return this.targets.includes(targetId);
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (this.timeout !== undefined && this.timeout <= 0) {
      errors.push('Timeout must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'touch',
      targets: this.targets,
      multiTouch: this.multiTouch,
      timeout: this.timeout,
      correct: this.correct,
      data: this.data
    };
  }
}

/**
 * No response (for passive viewing trials)
 */
export class NoResponse extends Response {
  constructor(options: ResponseOptions = {}) {
    super(options);
  }

  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (!this.timeout) {
      errors.push('NoResponse must have a timeout specified');
    }

    if (this.timeout !== undefined && this.timeout <= 0) {
      errors.push('Timeout must be positive');
    }

    return { valid: errors.length === 0, errors };
  }

  toJSON(): object {
    return {
      type: 'none',
      timeout: this.timeout,
      data: this.data
    };
  }
}

/**
 * Factory to create response from JSON
 */
export function createResponseFromJSON(json: any): Response {
  switch (json.type) {
    case 'keypress':
      return new KeypressResponse(json);
    case 'mouse':
      return new MouseResponse(json);
    case 'touch':
      return new TouchResponse(json);
    case 'none':
      return new NoResponse(json);
    default:
      throw new Error(`Unknown response type: ${json.type}`);
  }
}

// Override the static fromJSON method
Response.fromJSON = createResponseFromJSON;

