/**
 * TrialList container for the simplified ForgeScript API
 * 
 * Manages collections of trials with:
 * - Built-in randomization strategies
 * - Block support
 * - Progress tracking
 * - Factorial design generation
 */

import { Trial, TrialOptions } from './Trial';

export interface TrialListOptions {
  /**
   * The trials in this list
   */
  trials: Trial[];

  /**
   * Randomization strategy
   * @default 'shuffle'
   */
  randomization?: 'none' | 'shuffle' | 'latin-square' | 'custom';

  /**
   * Random seed for reproducible randomization
   */
  seed?: number;

  /**
   * Custom randomization function
   */
  customRandomizer?: (trials: Trial[]) => Trial[];
}

export class TrialList {
  private _trials: Trial[];
  private _currentIndex: number = 0;
  public readonly randomization: string;
  public readonly seed?: number;

  constructor(options: TrialListOptions) {
    this.randomization = options.randomization || 'shuffle';
    this.seed = options.seed;

    // Apply randomization
    switch (this.randomization) {
      case 'none':
        this._trials = [...options.trials];
        break;
      case 'shuffle':
        this._trials = this.shuffle(options.trials, this.seed);
        break;
      case 'latin-square':
        this._trials = this.latinSquare(options.trials);
        break;
      case 'custom':
        if (!options.customRandomizer) {
          throw new Error('Custom randomization requires customRandomizer function');
        }
        this._trials = options.customRandomizer(options.trials);
        break;
      default:
        this._trials = [...options.trials];
    }
  }

  /**
   * Get all trials
   */
  get trials(): ReadonlyArray<Trial> {
    return this._trials;
  }

  /**
   * Get current trial index
   */
  get currentIndex(): number {
    return this._currentIndex;
  }

  /**
   * Get total number of trials
   */
  get length(): number {
    return this._trials.length;
  }

  /**
   * Get progress as a percentage
   */
  get progress(): number {
    if (this._trials.length === 0) return 100;
    return (this._currentIndex / this._trials.length) * 100;
  }

  /**
   * Get the current trial
   */
  get current(): Trial | null {
    if (this._currentIndex >= this._trials.length) return null;
    return this._trials[this._currentIndex];
  }

  /**
   * Move to the next trial
   */
  next(): Trial | null {
    this._currentIndex++;
    return this.current;
  }

  /**
   * Reset to the beginning
   */
  reset(): void {
    this._currentIndex = 0;
  }

  /**
   * Fisher-Yates shuffle with optional seed
   */
  private shuffle(trials: Trial[], seed?: number): Trial[] {
    const shuffled = [...trials];
    let rng = seed ? this.seededRandom(seed) : Math.random;

    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(rng() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }

    return shuffled;
  }

  /**
   * Latin square randomization
   */
  private latinSquare(trials: Trial[]): Trial[] {
    // Simple implementation - more sophisticated version would handle
    // multiple factors and ensure proper counterbalancing
    const n = trials.length;
    const square: Trial[] = [];

    for (let i = 0; i < n; i++) {
      const row = (i + Math.floor(Math.random() * n)) % n;
      square.push(trials[row]);
    }

    return square;
  }

  /**
   * Seeded random number generator
   */
  private seededRandom(seed: number): () => number {
    return () => {
      const x = Math.sin(seed++) * 10000;
      return x - Math.floor(x);
    };
  }

  /**
   * Create a trial list from a factorial design
   */
  static fromFactors<T extends Record<string, any[]>>(options: {
    factors: T;
    template: (combination: { [K in keyof T]: T[K][number] }) => Trial;
    repetitions?: number;
    randomization?: TrialListOptions['randomization'];
    seed?: number;
  }): TrialList {
    const { factors, template, repetitions = 1 } = options;

    // Generate all combinations
    const combinations = TrialList.generateCombinations(factors);

    // Create trials from combinations
    const trials: Trial[] = [];
    for (let rep = 0; rep < repetitions; rep++) {
      for (const combination of combinations) {
        trials.push(template(combination));
      }
    }

    return new TrialList({
      trials,
      randomization: options.randomization,
      seed: options.seed
    });
  }

  /**
   * Generate all combinations of factor levels
   */
  private static generateCombinations<T extends Record<string, any[]>>(
    factors: T
  ): Array<{ [K in keyof T]: T[K][number] }> {
    const keys = Object.keys(factors) as Array<keyof T>;
    const values = keys.map(k => factors[k]);

    // Base case
    if (values.length === 0) return [{}] as any;

    // Recursive case
    const [first, ...rest] = values;
    const [firstKey, ...restKeys] = keys;

    const restCombinations = TrialList.generateCombinations(
      Object.fromEntries(restKeys.map((k, i) => [k, rest[i]])) as any
    );

    const combinations: Array<{ [K in keyof T]: T[K][number] }> = [];

    for (const value of first) {
      for (const restCombo of restCombinations) {
        combinations.push({
          [firstKey]: value,
          ...restCombo
        } as any);
      }
    }

    return combinations;
  }

  /**
   * Split into blocks
   */
  splitIntoBlocks(blocksCount: number): TrialList[] {
    const trialsPerBlock = Math.ceil(this._trials.length / blocksCount);
    const blocks: TrialList[] = [];

    for (let i = 0; i < blocksCount; i++) {
      const start = i * trialsPerBlock;
      const end = Math.min(start + trialsPerBlock, this._trials.length);
      const blockTrials = this._trials.slice(start, end);

      blocks.push(new TrialList({
        trials: blockTrials,
        randomization: 'none' // Already randomized
      }));
    }

    return blocks;
  }

  /**
   * Add trials to this list
   */
  add(...trials: Trial[]): TrialList {
    return new TrialList({
      trials: [...this._trials, ...trials],
      randomization: 'none' // Preserve existing order
    });
  }

  /**
   * Filter trials
   */
  filter(predicate: (trial: Trial, index: number) => boolean): TrialList {
    return new TrialList({
      trials: this._trials.filter(predicate),
      randomization: 'none' // Preserve existing order
    });
  }

  /**
   * Map trials
   */
  map(mapper: (trial: Trial, index: number) => Trial): TrialList {
    return new TrialList({
      trials: this._trials.map(mapper),
      randomization: 'none' // Preserve existing order
    });
  }

  /**
   * Validate all trials
   */
  validate(): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    if (this._trials.length === 0) {
      errors.push('TrialList must contain at least one trial');
    }

    // Validate each trial
    this._trials.forEach((trial, i) => {
      const validation = trial.validate();
      if (!validation.valid) {
        errors.push(...validation.errors.map(e => `Trial ${i}: ${e}`));
      }
    });

    return {
      valid: errors.length === 0,
      errors
    };
  }

  /**
   * Convert to JSON
   */
  toJSON(): object {
    return {
      trials: this._trials.map(t => t.toJSON()),
      randomization: this.randomization,
      seed: this.seed,
      currentIndex: this._currentIndex
    };
  }

  /**
   * Create from JSON
   */
  static fromJSON(json: any): TrialList {
    const list = new TrialList({
      trials: json.trials.map((t: any) => Trial.fromJSON(t)),
      randomization: json.randomization,
      seed: json.seed
    });

    // Restore progress
    if (json.currentIndex !== undefined) {
      list._currentIndex = json.currentIndex;
    }

    return list;
  }
}

