/**
 * Simple Stroop Task using the new simplified ForgeScript API
 * 
 * Compare this to complete-stroop-task.ts (535 lines)
 * This achieves the same functionality in ~50 lines!
 */

import { 
  experiment,
  TrialList,
  Trial,
  Text,
  FixationCross,
  KeypressResponse
} from '../src/api';

// Define our color mappings
const COLORS = {
  red: '#FF0000',
  green: '#00FF00',
  blue: '#0000FF',
  yellow: '#FFFF00'
};

// Create the experiment
const exp = experiment({
  title: 'Simple Stroop Task v2',
  screen: {
    backgroundColor: '#333333'
  }
});

// Generate trials using the factorial design helper
const trials = TrialList.fromFactors({
  factors: {
    word: ['RED', 'GREEN', 'BLUE', 'YELLOW'],
    color: ['red', 'green', 'blue', 'yellow']
  },
  template: ({ word, color }) => new Trial({
    stimuli: [
      new FixationCross({ duration: 500 }),
      new Text({
        content: word,
        color: COLORS[color as keyof typeof COLORS],
        fontSize: 72,
        fontWeight: 'bold',
        position: 'center'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['r', 'g', 'b', 'y'],
      timeout: 3000,
      correct: color.charAt(0) // First letter of color
    }),
    data: {
      word,
      color,
      congruent: word.toLowerCase() === color
    },
    iti: 200
  }),
  repetitions: 5, // 5 × 4 × 4 = 80 trials
  randomization: 'shuffle'
});

// Add instruction trials
const instructions = new Trial({
  stimuli: new Text({
    content: `Stroop Task

You will see color words in different colors.
Press the key for the COLOR, not the word:

R = Red    G = Green    B = Blue    Y = Yellow

Press SPACE to begin`,
    fontSize: 24,
    position: 'center'
  }),
  response: new KeypressResponse({
    validKeys: ['space']
  })
});

// Create practice trials (subset of main trials)
const practiceTrials = TrialList.fromFactors({
  factors: {
    word: ['RED', 'BLUE'],
    color: ['red', 'blue']
  },
  template: ({ word, color }) => new Trial({
    stimuli: [
      new FixationCross({ duration: 500 }),
      new Text({
        content: word,
        color: COLORS[color as keyof typeof COLORS],
        fontSize: 72,
        fontWeight: 'bold'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['r', 'b'],
      timeout: 3000,
      correct: color.charAt(0)
    }),
    data: {
      word,
      color,
      congruent: word.toLowerCase() === color,
      phase: 'practice'
    }
  }),
  repetitions: 2 // 8 practice trials
});

// Run the experiment
async function run() {
  // Show instructions
  await exp.run(instructions);

  // Run practice
  console.log('Starting practice trials...');
  const practiceResults = await exp.run(practiceTrials);
  console.log(`Practice accuracy: ${practiceResults.summary.accuracy.toFixed(1)}%`);

  // Run main experiment
  console.log('Starting main experiment...');
  const mainResults = await exp.run(trials);

  // Display results
  console.log('\n=== Results ===');
  console.log(`Overall accuracy: ${mainResults.summary.accuracy.toFixed(1)}%`);
  console.log(`Mean RT: ${mainResults.summary.meanRT.toFixed(0)}ms`);

  // Calculate Stroop effect
  const congruent = mainResults.trials.filter(t => t.data.congruent);
  const incongruent = mainResults.trials.filter(t => !t.data.congruent);

  const congruentRT = congruent.reduce((sum, t) => sum + t.rt, 0) / congruent.length;
  const incongruentRT = incongruent.reduce((sum, t) => sum + t.rt, 0) / incongruent.length;

  console.log(`\nStroop Effect: ${(incongruentRT - congruentRT).toFixed(0)}ms`);
  console.log(`  Congruent RT: ${congruentRT.toFixed(0)}ms`);
  console.log(`  Incongruent RT: ${incongruentRT.toFixed(0)}ms`);

  // Clean up
  await exp.cleanup();
}

// Even simpler: Use the fluent API (once implemented)
async function runFluent() {
  const results = await exp
    .stroop()
    .colors(['red', 'green', 'blue', 'yellow'])
    .trials(80)
    .practice(10)
    .run();

  console.log(`Stroop effect: ${results.summary.stroopEffect}ms`);
}

// Run the experiment
if (import.meta.url === `file://${process.argv[1]}`) {
  run().catch(console.error);
}

