const practiceTrials = TrialList.fromFactors({
  factors: {
    word: ['RED', 'BLUE'],
    color: ['red', 'blue']
  },
  template: ({ word, color }) => new Trial({
    stimuli: [
      new FixationCross({ duration: 500 }),
      new Text({
        content: word,
        color: COLORS[color as keyof typeof COLORS],
        fontSize: 72,
        fontWeight: 'bold'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['r', 'b'],
      timeout: 3000,
      correct: color.charAt(0)
    }),
    data: {
      word,
      color,
      congruent: word.toLowerCase() === color,
      phase: 'practice'
    }
  }),
  repetitions: 2 // 8 practice trials
});

// Run the experiment
async function run() {
  // Show instructions
  await exp.run(instructions);

  // Run practice
  console.log('Starting practice trials...');
  const practiceResults = await exp.run(practiceTrials);
  console.log(`Practice accuracy: ${practiceResults.summary.accuracy.toFixed(1)}%`);

  // Run main experiment
  console.log('Starting main experiment...');
  const mainResults = await exp.run(trials);

  // Display results
  console.log('\n=== Results ===');
  console.log(`Overall accuracy: ${mainResults.summary.accuracy.toFixed(1)}%`);
  console.log(`Mean RT: ${mainResults.summary.meanRT.toFixed(0)}ms`);

  // Calculate Stroop effect
  const congruent = mainResults.trials.filter(t => t.data.congruent);
  const incongruent = mainResults.trials.filter(t => !t.data.congruent);

  const congruentRT = congruent.reduce((sum, t) => sum + t.rt, 0) / congruent.length;
  const incongruentRT = incongruent.reduce((sum, t) => sum + t.rt, 0) / incongruent.length;

  console.log(`\nStroop Effect: ${(incongruentRT - congruentRT).toFixed(0)}ms`);
  console.log(`  Congruent RT: ${congruentRT.toFixed(0)}ms`);
  console.log(`  Incongruent RT: ${incongruentRT.toFixed(0)}ms`);

  // Clean up
  await exp.cleanup();
}

// Even simpler: Use the fluent API (once implemented)
async function runFluent() {
  const results = await exp
    .stroop()
    .colors(['red', 'green', 'blue', 'yellow'])
    .trials(80)
    .practice(10)
    .run();

  console.log(`Stroop effect: ${results.summary.stroopEffect}ms`);
}

// Run the experiment
if (import.meta.url === `file://${process.argv[1]}`) {
  run().catch(console.error);
}

