/**
 * Stroop Task Template
 * 
 * Pre-built Stroop experiment with sensible defaults
 * Can be customized via fluent API
 */

import { Trial } from '../Trial';
import { TrialList } from '../TrialList';
import { Text, FixationCross, Blank } from '../Stimulus';
import { KeypressResponse } from '../Response';
import type { Experiment, ExperimentResults } from '../Experiment';

export interface StroopConfig {
  /**
   * Colors to use in the task
   * @default ['red', 'green', 'blue', 'yellow']
   */
  colors?: string[];

  /**
   * Color hex values
   * @default { red: '#FF0000', green: '#00FF00', blue: '#0000FF', yellow: '#FFFF00' }
   */
  colorValues?: Record<string, string>;

  /**
   * Response keys corresponding to colors
   * @default ['r', 'g', 'b', 'y']
   */
  responseKeys?: string[];

  /**
   * Number of main trials
   * @default 80
   */
  trials?: number;

  /**
   * Number of practice trials
   * @default 10
   */
  practice?: number;

  /**
   * Fixation duration in ms
   * @default 500
   */
  fixationDuration?: number;

  /**
   * Response timeout in ms
   * @default 3000
   */
  responseTimeout?: number;

  /**
   * Inter-trial interval in ms
   * @default 200
   */
  iti?: number;

  /**
   * Font size for word stimuli
   * @default 72
   */
  fontSize?: number;

  /**
   * Show instructions
   * @default true
   */
  showInstructions?: boolean;

  /**
   * Show feedback after practice
   * @default true
   */
  showPracticeFeedback?: boolean;

  /**
   * Show results summary
   * @default true
   */
  showResults?: boolean;
}

const DEFAULT_COLORS = ['red', 'green', 'blue', 'yellow'];
const DEFAULT_COLOR_VALUES = {
  red: '#FF0000',
  green: '#00FF00',
  blue: '#0000FF',
  yellow: '#FFFF00'
};
const DEFAULT_RESPONSE_KEYS = ['r', 'g', 'b', 'y'];

export class StroopBuilder {
  private config: StroopConfig;

  constructor(
    private experiment: Experiment,
    config: StroopConfig = {}
  ) {
    this.config = {
      colors: config.colors || DEFAULT_COLORS,
      colorValues: config.colorValues || DEFAULT_COLOR_VALUES,
      responseKeys: config.responseKeys || DEFAULT_RESPONSE_KEYS,
      trials: config.trials || 80,
      practice: config.practice || 10,
      fixationDuration: config.fixationDuration || 500,
      responseTimeout: config.responseTimeout || 3000,
      iti: config.iti || 200,
      fontSize: config.fontSize || 72,
      showInstructions: config.showInstructions !== false,
      showPracticeFeedback: config.showPracticeFeedback !== false,
      showResults: config.showResults !== false
    };
  }

  /**
   * Set colors to use
   */
  colors(colors: string[]): this {
    this.config.colors = colors;
    return this;
  }

  /**
   * Set number of trials
   */
  trials(count: number): this {
    this.config.trials = count;
    return this;
  }

  /**
   * Set number of practice trials
   */
  practice(count: number): this {
    this.config.practice = count;
    return this;
  }

  /**
   * Set response keys
   */
  responseKeys(keys: string[]): this {
    this.config.responseKeys = keys;
    return this;
  }

  /**
   * Set response timeout
   */
  timeout(ms: number): this {
    this.config.responseTimeout = ms;
    return this;
  }

  /**
   * Run the Stroop experiment
   */
  async run(): Promise<StroopResults> {
    const lists: TrialList[] = [];

    // Add instructions if enabled
    if (this.config.showInstructions) {
      lists.push(this.createInstructions());
    }

    // Add practice trials if requested
    if (this.config.practice! > 0) {
      lists.push(this.createPracticeTrials());

      if (this.config.showPracticeFeedback) {
        lists.push(this.createPracticeFeedback());
      }
    }

    // Add main trials
    lists.push(this.createMainTrials());

    // Add results screen if enabled
    if (this.config.showResults) {
      lists.push(this.createResultsScreen());
    }

    // Run all trial lists in sequence
    const results = await this.experiment.runSequence(...lists);

    // Calculate Stroop-specific metrics
    return this.calculateStroopMetrics(results);
  }

  /**
   * Create instruction trials
   */
  private createInstructions(): TrialList {
    const keyMapping = this.config.colors!
      .map((color, i) => `${this.config.responseKeys![i].toUpperCase()} = ${color.charAt(0).toUpperCase() + color.slice(1)}`)
      .join('    ');

    return new TrialList({
      trials: [
        new Trial({
          stimuli: new Text({
            content: `Stroop Task

You will see color words displayed in different colors.
Your task is to identify the COLOR of the text, not the word itself.

Press the corresponding key as quickly and accurately as possible:

${keyMapping}

Press SPACE to continue`,
            fontSize: 24,
            position: 'center'
          }),
          response: new KeypressResponse({
            validKeys: ['space']
          })
        })
      ],
      randomization: 'none'
    });
  }

  /**
   * Create practice trials
   */
  private createPracticeTrials(): TrialList {
    // Use subset of colors for practice
    const practiceColors = this.config.colors!.slice(0, 2);

    return TrialList.fromFactors({
      factors: {
        word: practiceColors.map(c => c.toUpperCase()),
        color: practiceColors
      },
      template: ({ word, color }) => this.createStroopTrial(word, color, 'practice'),
      repetitions: Math.ceil(this.config.practice! / (practiceColors.length * 2)),
      randomization: 'shuffle'
    });
  }

  /**
   * Create practice feedback screen
   */
  private createPracticeFeedback(): TrialList {
    return new TrialList({
      trials: [
        new Trial({
          stimuli: new Text({
            content: `Practice Complete!

Good job! Now let's begin the main experiment.

Press SPACE to continue`,
            fontSize: 24,
            position: 'center'
          }),
          response: new KeypressResponse({
            validKeys: ['space']
          })
        })
      ],
      randomization: 'none'
    });
  }

  /**
   * Create main experimental trials
   */
  private createMainTrials(): TrialList {
    const words = this.config.colors!.map(c => c.toUpperCase());
    const trialsPerCombination = Math.ceil(this.config.trials! / (this.config.colors!.length * this.config.colors!.length));

    return TrialList.fromFactors({
      factors: {
        word: words,
        color: this.config.colors!
      },
      template: ({ word, color }) => this.createStroopTrial(word, color, 'main'),
      repetitions: trialsPerCombination,
      randomization: 'shuffle'
    });
  }

  /**
   * Create a single Stroop trial
   */
  private createStroopTrial(word: string, color: string, phase: 'practice' | 'main'): Trial {
    const colorValue = this.config.colorValues![color] || color;
    const correctKey = this.config.responseKeys![this.config.colors!.indexOf(color)];

    return new Trial({
      stimuli: [
        new FixationCross({ 
          duration: this.config.fixationDuration,
          color: '#666666'
        }),
        new Text({
          content: word,
          color: colorValue,
          fontSize: this.config.fontSize,
          fontWeight: 'bold',
          position: 'center'
        })
      ],
      response: new KeypressResponse({
        validKeys: this.config.responseKeys!,
        timeout: this.config.responseTimeout,
        correct: correctKey
      }),
      data: {
        word,
        color,
        congruent: word.toLowerCase() === color,
        phase,
        expectedResponse: correctKey
      },
      iti: this.config.iti
    });
  }

  /**
   * Create results screen
   */
  private createResultsScreen(): TrialList {
    return new TrialList({
      trials: [
        new Trial({
          stimuli: new Text({
            content: `Task Complete!

Thank you for participating.

Your results have been saved.

Press SPACE to exit`,
            fontSize: 24,
            position: 'center'
          }),
          response: new KeypressResponse({
            validKeys: ['space']
          })
        })
      ],
      randomization: 'none'
    });
  }

  /**
   * Calculate Stroop-specific metrics
   */
  private calculateStroopMetrics(results: ExperimentResults): StroopResults {
    // Filter to only main trials
    const mainTrials = results.trials.filter(t => t.data.phase === 'main');
    const validTrials = mainTrials.filter(t => !t.timeout);

    // Separate congruent and incongruent
    const congruentTrials = validTrials.filter(t => t.data.congruent);
    const incongruentTrials = validTrials.filter(t => !t.data.congruent);

    // Calculate RTs
    const congruentRT = congruentTrials.length > 0
      ? congruentTrials.reduce((sum, t) => sum + t.rt, 0) / congruentTrials.length
      : 0;

    const incongruentRT = incongruentTrials.length > 0
      ? incongruentTrials.reduce((sum, t) => sum + t.rt, 0) / incongruentTrials.length
      : 0;

    // Calculate accuracies
    const congruentCorrect = congruentTrials.filter(t => t.correct).length;
    const incongruentCorrect = incongruentTrials.filter(t => t.correct).length;

    const congruentAccuracy = congruentTrials.length > 0
      ? (congruentCorrect / congruentTrials.length) * 100
      : 0;

    const incongruentAccuracy = incongruentTrials.length > 0
      ? (incongruentCorrect / incongruentTrials.length) * 100
      : 0;

    return {
      ...results,
      stroop: {
        congruentRT,
        incongruentRT,
        stroopEffect: incongruentRT - congruentRT,
        congruentAccuracy,
        incongruentAccuracy,
        congruentTrials: congruentTrials.length,
        incongruentTrials: incongruentTrials.length
      }
    };
  }
}

export interface StroopResults extends ExperimentResults {
  stroop: {
    congruentRT: number;
    incongruentRT: number;
    stroopEffect: number;
    congruentAccuracy: number;
    incongruentAccuracy: number;
    congruentTrials: number;
    incongruentTrials: number;
  };
}

/**
 * Create a Stroop experiment
 */
export function stroop(experiment: Experiment, config?: StroopConfig): StroopBuilder {
  return new StroopBuilder(experiment, config);
}

