/**
 * High-level Experiment API for ForgeScript
 * 
 * Provides a clean, simple interface that hides all complexity:
 * - No manual setup/teardown
 * - Automatic data collection
 * - Built-in timing and synchronization
 * - Smart defaults for everything
 */

import { Trial } from './Trial';
import { TrialList } from './TrialList';
import { ExperimentRunner } from './ExperimentRunner';

export interface ExperimentConfig {
  /**
   * Experiment title
   */
  title?: string;

  /**
   * Experiment ID
   */
  id?: string;

  /**
   * Screen configuration
   */
  screen?: {
    width?: number;
    height?: number;
    fullscreen?: boolean;
    backgroundColor?: string;
  };

  /**
   * Data configuration
   */
  data?: {
    /**
     * Output format
     * @default 'csv'
     */
    format?: 'csv' | 'json' | 'bids';

    /**
     * Filename pattern (can include {participant}, {date}, {time})
     * @default '{id}-{participant}-{date}.csv'
     */
    filename?: string;

    /**
     * Auto-save after each trial
     * @default true
     */
    autoSave?: boolean;
  };

  /**
   * Timing configuration
   */
  timing?: {
    /**
     * Target frame rate
     * @default 60
     */
    frameRate?: number;

    /**
     * Enable high precision timing
     * @default true
     */
    highPrecision?: boolean;
  };

  /**
   * Keyboard configuration
   */
  keyboard?: {
    /**
     * Prevent default browser shortcuts
     * @default true
     */
    preventDefault?: boolean;
  };
}

export class Experiment {
  private config: Required<ExperimentConfig>;
  private runner?: ExperimentRunner;

  constructor(config: ExperimentConfig = {}) {
    // Apply smart defaults
    this.config = {
      title: config.title || 'Untitled Experiment',
      id: config.id || `exp-${Date.now()}`,
      screen: {
        width: config.screen?.width || 800,
        height: config.screen?.height || 600,
        fullscreen: config.screen?.fullscreen ?? false,
        backgroundColor: config.screen?.backgroundColor || '#ffffff'
      },
      data: {
        format: config.data?.format || 'csv',
        filename: config.data?.filename || '{id}-{participant}-{date}.csv',
        autoSave: config.data?.autoSave ?? true
      },
      timing: {
        frameRate: config.timing?.frameRate || 60,
        highPrecision: config.timing?.highPrecision ?? true
      },
      keyboard: {
        preventDefault: config.keyboard?.preventDefault ?? true
      }
    };
  }

  /**
   * Run a single trial
   */
  async run(input: Trial | TrialList): Promise<ExperimentResults> {
    // Initialize runner if needed
    if (!this.runner) {
      this.runner = new ExperimentRunner(this.config);
      await this.runner.initialize();
    }

    // Run the experiment
    if (input instanceof Trial) {
      return await this.runner.runTrial(input);
    } else {
      return await this.runner.runTrialList(input);
    }
  }

  /**
   * Run multiple trial lists in sequence (e.g., practice then test)
   */
  async runSequence(...lists: TrialList[]): Promise<ExperimentResults> {
    if (!this.runner) {
      this.runner = new ExperimentRunner(this.config);
      await this.runner.initialize();
    }

    const allResults: TrialResult[] = [];

    for (const list of lists) {
      const results = await this.runner.runTrialList(list);
      allResults.push(...results.trials);
    }

    return {
      trials: allResults,
      summary: this.calculateSummary(allResults),
      metadata: {
        experimentId: this.config.id,
        experimentTitle: this.config.title,
        startTime: allResults[0]?.startTime,
        endTime: allResults[allResults.length - 1]?.endTime,
        totalDuration: allResults[allResults.length - 1]?.endTime - allResults[0]?.startTime
      }
    };
  }

  /**
   * Clean up resources
   */
  async cleanup(): Promise<void> {
    if (this.runner) {
      await this.runner.cleanup();
    }
  }

  /**
   * Calculate summary statistics
   */
  private calculateSummary(trials: TrialResult[]): ExperimentSummary {
    const validResponses = trials.filter(t => !t.timeout);
    const correctResponses = validResponses.filter(t => t.correct);

    return {
      totalTrials: trials.length,
      completedTrials: validResponses.length,
      timeouts: trials.length - validResponses.length,
      accuracy: validResponses.length > 0 
        ? (correctResponses.length / validResponses.length) * 100 
        : 0,
      meanRT: validResponses.length > 0
        ? validResponses.reduce((sum, t) => sum + t.rt, 0) / validResponses.length
        : 0,
      medianRT: validResponses.length > 0
        ? this.median(validResponses.map(t => t.rt))
        : 0
    };
  }

  private median(numbers: number[]): number {
    const sorted = [...numbers].sort((a, b) => a - b);
    const middle = Math.floor(sorted.length / 2);

    if (sorted.length % 2 === 0) {
      return (sorted[middle - 1] + sorted[middle]) / 2;
    }

    return sorted[middle];
  }

  // ===== Fluent Template Methods =====
  // These provide the one-liner experiment creation

  /**
   * Create a Stroop task
   */
  stroop(options?: StroopOptions): StroopBuilder {
    return new StroopBuilder(this, options);
  }

  /**
   * Create a Flanker task
   */
  flanker(options?: FlankerOptions): FlankerBuilder {
    return new FlankerBuilder(this, options);
  }

  /**
   * Create an N-back task
   */
  nback(options?: NBackOptions): NBackBuilder {
    return new NBackBuilder(this, options);
  }
}

// ===== Result Types =====

export interface TrialResult {
  trialId: string;
  trialIndex: number;
  startTime: number;
  endTime: number;
  rt: number;
  response: any;
  correct: boolean;
  timeout: boolean;
  data: Record<string, any>;
}

export interface ExperimentSummary {
  totalTrials: number;
  completedTrials: number;
  timeouts: number;
  accuracy: number;
  meanRT: number;
  medianRT: number;
}

export interface ExperimentResults {
  trials: TrialResult[];
  summary: ExperimentSummary;
  metadata: Record<string, any>;
}

