  response: new KeypressResponse({ validKeys: ['space'] })
});

// Generate trials automatically!
const trials = TrialList.fromFactors({
  factors: {
    word: ['RED', 'GREEN', 'BLUE', 'YELLOW'],
    color: ['red', 'green', 'blue', 'yellow']
  },
  template: ({ word, color }) => new Trial({
    stimuli: [
      new FixationCross({ duration: 500 }),
      new Text({
        content: word,
        color: COLORS[color],
        fontSize: 72,
        position: 'center'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['r', 'g', 'b', 'y'],
      timeout: 3000,
      correct: color.charAt(0)
    }),
    data: { word, color, congruent: word.toLowerCase() === color },
    iti: 200
  }),
  repetitions: 5,
  randomization: 'shuffle'
});

// Run it!
await exp.run(instructions);
const results = await exp.run(trials);
console.log(`Accuracy: ${results.summary.accuracy}%`);
```

### Even Simpler: Use the Template!
```typescript
await experiment()
  .stroop()
  .trials(80)
  .practice(10)
  .run();
```

## Migration Checklist

- [ ] Replace manual positioning with semantic positions
- [ ] Replace manual trial loops with `TrialList.fromFactors()`
- [ ] Replace stimulus builder chains with simple constructors
- [ ] Remove all PixiJS references
- [ ] Remove compilation/validation steps
- [ ] Replace manual RT recording with automatic responses
- [ ] Use templates for standard paradigms

## Common Gotchas

1. **Positioning**: The new API uses semantic positions. If you need pixel-perfect positioning, use the `style` property
2. **Trial IDs**: Are generated automatically if not specified
3. **Data Recording**: RT and accuracy are recorded automatically - don't duplicate
4. **Response Objects**: Must create Response objects, not pass config objects
5. **Async/Await**: The new `run()` methods are async - remember to await!

## Getting Help

- See `docs/new-api-guide.md` for comprehensive documentation
- Check `examples/` for working examples
- Use TypeScript for excellent autocomplete
- Start with templates, drop to primitives only when needed

The new API is designed to make the common case simple and the complex case possible!

