/**
 * Simple Reaction Time Task
 * 
 * This example demonstrates:
 * - Basic stimulus presentation
 * - Response timing measurement
 * - Random intervals
 * - Performance feedback
 */

import { ForgeScript, WaitEvent } from '../src/index.js';

// Create the experiment
const reactionTimeExperiment = ForgeScript.createExperiment('Simple Reaction Time')
  .title('Simple Reaction Time Task')
  .description('Measure basic reaction time to visual stimuli')
  .version('1.0.0')
  .author('Cognitive Lab')
  .tags(['reaction time', 'speed', 'motor response']);

// Welcome and instructions
const welcomeTimeline = ForgeScript.createTimeline('welcome')
  .add(ForgeScript.createTextStimulus('Simple Reaction Time Task', 3000)
    .fontSize(36)
    .color('navy'))
  .add(ForgeScript.createTextStimulus(
    'You will see a circle appear on the screen.\n\n' +
    'Press the SPACEBAR as quickly as possible when you see it.\n\n' +
    'Try to be both fast and accurate!\n\n' +
    'Press SPACE to start practice...'
  )
    .fontSize(18)
    .color('black'))
  .add(ForgeScript.createKeyboardResponse(['space']));

// Practice trials (5 trials)
const practiceTimeline = ForgeScript.createTimeline('practice')
  .repeat(5)
  .add(ForgeScript.createTextStimulus('Get Ready...', 1000)
    .fontSize(24)
    .color('orange'))
  .add(new WaitEvent('random-delay', Math.random() * 3000 + 1000)) // 1-4 second delay
  .add(ForgeScript.createTextStimulus('●', 0) // Circle stimulus
    .fontSize(72)
    .color('red')
    .position(0, 0)) // Center
  .add(ForgeScript.createKeyboardResponse(['space'], 2000)
    .message('Press SPACEBAR now!'))
  .add(ForgeScript.createTextStimulus((context: any) => {
    const response = context.data.responses[context.data.responses.length - 1];
    if (response.reactionTime > 2000) {
      return 'Too slow! Try to respond faster.';
    } else if (response.reactionTime < 100) {
      return 'Too fast! Wait for the circle to appear.';
    } else {
      return `Good! Reaction time: ${response.reactionTime}ms`;
    }
  }, 2000)
    .fontSize(20)
    .color((context: any) => {
      const response = context.data.responses[context.data.responses.length - 1];
      if (response.reactionTime > 2000 || response.reactionTime < 100) {
        return 'red';
      } else {
        return 'green';
      }
    }));

// Ready for main task
const readyTimeline = ForgeScript.createTimeline('ready')
  .add(ForgeScript.createTextStimulus(
    'Practice complete!\n\n' +
    'Now for the real task. You\'ll do 20 trials.\n\n' +
    'Press SPACE when ready to begin...'
  )
    .fontSize(18)
    .color('black'))
  .add(ForgeScript.createKeyboardResponse(['space']));

// Main experimental trials (20 trials)
const mainTimeline = ForgeScript.createTimeline('main-trials')
  .repeat(20)
  .add(ForgeScript.createTextStimulus('+', 1000) // Fixation cross
    .fontSize(36)
    .color('black'))
  .add(new WaitEvent('random-delay', Math.random() * 2500 + 500)) // 0.5-3 second delay
  .add(ForgeScript.createTextStimulus('●', 0) // Circle stimulus
    .fontSize(72)
    .color('red'))
  .add(ForgeScript.createKeyboardResponse(['space'], 3000))
  .add(ForgeScript.createWaitEvent(500)); // Inter-trial interval

// Results and completion
const resultsTimeline = ForgeScript.createTimeline('results')
  .add(ForgeScript.createTextStimulus('Calculating results...', 2000)
    .fontSize(24)
    .color('blue'))
  .add(ForgeScript.createTextStimulus((context: any) => {
    const responses = context.data.responses as any[];
    const validResponses = responses.filter((r: any) => 
      r.reactionTime >= 100 && r.reactionTime <= 3000 && r.key === 'space'
    );

    if (validResponses.length === 0) {
      return 'No valid responses recorded.';
    }

    const avgRT = validResponses.reduce((sum: number, r: any) => sum + r.reactionTime, 0) / validResponses.length;
    const minRT = Math.min(...validResponses.map((r: any) => r.reactionTime));
    const maxRT = Math.max(...validResponses.map((r: any) => r.reactionTime));

    return `Your Results:\n\n` +
           `Valid trials: ${validResponses.length}/20\n` +
           `Average reaction time: ${avgRT.toFixed(0)}ms\n` +
           `Fastest: ${minRT}ms\n` +
           `Slowest: ${maxRT}ms\n\n` +
           `${avgRT < 300 ? 'Excellent speed!' : 
             avgRT < 400 ? 'Good speed!' : 
             avgRT < 500 ? 'Average speed.' : 'Try to respond faster next time.'}`;
  }, 0)
    .fontSize(18)
    .color('black'))
  .add(ForgeScript.createWaitEvent(5000))
  .add(ForgeScript.createTextStimulus('Thank you for participating!', 3000)
    .fontSize(24)
    .color('green'));

// Assemble the complete experiment
reactionTimeExperiment.timeline([
  welcomeTimeline,
  practiceTimeline,
  readyTimeline,
  mainTimeline,
  resultsTimeline,
]);

// Add error handling
reactionTimeExperiment.onError((error, context) => {
  console.error('Experiment error:', error);
  alert('An error occurred during the experiment. Please contact the researcher.');
});

// Add completion callback
reactionTimeExperiment.onComplete((data) => {
  console.log('Reaction time experiment completed');

  // Analyze the data
  const responses = data.responses as any[];
  const validResponses = responses.filter((r: any) => 
    r.reactionTime >= 100 && r.reactionTime <= 3000 && r.key === 'space'
  );

  const analysis = {
    participantId: data.participantId,
    sessionId: data.sessionId,
    totalTrials: 20,
    validTrials: validResponses.length,
    averageRT: validResponses.reduce((sum: number, r: any) => sum + r.reactionTime, 0) / validResponses.length,
    medianRT: validResponses.map((r: any) => r.reactionTime).sort((a: number, b: number) => a - b)[Math.floor(validResponses.length / 2)],
    minRT: Math.min(...validResponses.map((r: any) => r.reactionTime)),
    maxRT: Math.max(...validResponses.map((r: any) => r.reactionTime)),
    standardDeviation: 0, // Would calculate properly in real implementation
  };

  console.log('Analysis:', analysis);

  // In a real experiment, you would save this data to a server
  // saveDataToServer(analysis);
});

export default reactionTimeExperiment;

// Example usage:
