/**
 * Simple Reaction Time Task - Clean API Version
 * 
 * This example demonstrates:
 * - Basic stimulus presentation
 * - Response timing measurement
 * - Random intervals
 * - Performance feedback
 */

import { 
  experiment, 
  Trial, 
  TrialList,
  Text, 
  FixationCross,
  Blank,
  KeypressResponse 
} from '../src/api';

// Create the experiment
const exp = experiment({
  title: 'Simple Reaction Time Task',
  screen: {
    backgroundColor: '#ffffff'
  }
});

// Instructions
const instructions = new Trial({
  stimuli: new Text({
    content: `Simple Reaction Time Task

You will see a circle appear on the screen.
Press the SPACEBAR as quickly as possible when you see it.

Try to be both fast and accurate!

Press SPACE to start practice...`,
    fontSize: 18,
    position: 'center'
  }),
  response: new KeypressResponse({
    validKeys: ['space']
  })
});

// Generate practice trials
const practiceTrials = new TrialList({
  trials: Array(5).fill(null).map((_, i) => new Trial({
    stimuli: [
      new Text({
        content: 'Get Ready...',
        fontSize: 24,
        color: '#FFA500',
        duration: 1000
      }),
      new Blank({
        duration: Math.random() * 3000 + 1000, // 1-4 second random delay
        backgroundColor: '#ffffff'
      }),
      new Text({
        content: '●',
        fontSize: 72,
        color: '#FF0000',
        position: 'center'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['space'],
      timeout: 2000
    }),
    data: {
      phase: 'practice',
      trialNumber: i + 1
    }
  })),
  randomization: 'none'
});

// Feedback after each practice trial
const practiceFeedback = (result: any) => new Trial({
  stimuli: new Text({
    content: result.timeout 
      ? 'Too slow! Try to respond faster.'
      : result.rt < 100 
      ? 'Too fast! Wait for the circle to appear.'
      : `Good! Reaction time: ${result.rt}ms`,
    fontSize: 20,
    color: result.timeout || result.rt < 100 ? '#FF0000' : '#00FF00',
    position: 'center'
  }),
  response: new KeypressResponse({
    validKeys: ['space'],
    timeout: 2000
  })
});

// Ready for main task
const readyScreen = new Trial({
  stimuli: new Text({
    content: `Practice complete!

Now for the real task. You'll do 20 trials.

Press SPACE when ready to begin...`,
    fontSize: 18,
    position: 'center'
  }),
  response: new KeypressResponse({
    validKeys: ['space']
  })
});

// Generate main experimental trials
const mainTrials = new TrialList({
  trials: Array(20).fill(null).map((_, i) => new Trial({
    stimuli: [
      new FixationCross({
        duration: 1000,
        size: 36
      }),
      new Blank({
        duration: Math.random() * 2500 + 500, // 0.5-3 second random delay
        backgroundColor: '#ffffff'
      }),
      new Text({
        content: '●',
        fontSize: 72,
        color: '#FF0000',
        position: 'center'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['space'],
      timeout: 3000
    }),
    data: {
      phase: 'main',
      trialNumber: i + 1
    },
    iti: 500
  })),
  randomization: 'none' // Keep order for RT task
});

// Results display
const createResultsScreen = (results: any) => {
  const mainResults = results.trials.filter((t: any) => t.data.phase === 'main');
  const validResults = mainResults.filter((t: any) => !t.timeout && t.rt >= 100);

  if (validResults.length === 0) {
    return new Trial({
      stimuli: new Text({
        content: 'No valid responses recorded.',
        fontSize: 18,
        position: 'center'
      }),
      response: new KeypressResponse({
        validKeys: ['space'],
        timeout: 5000
      })
    });
  }

  const avgRT = validResults.reduce((sum: number, t: any) => sum + t.rt, 0) / validResults.length;
  const minRT = Math.min(...validResults.map((t: any) => t.rt));
  const maxRT = Math.max(...validResults.map((t: any) => t.rt));

  const speedMessage = avgRT < 300 ? 'Excellent speed!' : 
                      avgRT < 400 ? 'Good speed!' : 
                      avgRT < 500 ? 'Average speed.' : 
                      'Try to respond faster next time.';

  return new Trial({
    stimuli: new Text({
      content: `Your Results:

Valid trials: ${validResults.length}/20
Average reaction time: ${avgRT.toFixed(0)}ms
Fastest: ${minRT}ms
Slowest: ${maxRT}ms

${speedMessage}

Thank you for participating!`,
      fontSize: 18,
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space'],
      timeout: 10000
    })
  });
};

// Run the experiment
async function runSimpleRT() {
  console.log('Starting Simple RT experiment...');

  // Show instructions
  await exp.run(instructions);

  // Run practice with feedback
  for (let i = 0; i < 5; i++) {
    const practiceResult = await exp.run(practiceTrials.trials[i]);
    await exp.run(practiceFeedback(practiceResult.trials[0]));
  }

  // Ready screen
  await exp.run(readyScreen);

  // Run main trials
  const mainResults = await exp.run(mainTrials);

  // Show results
  await exp.run(createResultsScreen(mainResults));

  // Clean up
  await exp.cleanup();

  // Return analysis
  const validResults = mainResults.trials.filter(t => !t.timeout && t.rt >= 100);
  return {
    totalTrials: 20,
    validTrials: validResults.length,
    averageRT: validResults.reduce((sum, t) => sum + t.rt, 0) / validResults.length,
    minRT: Math.min(...validResults.map(t => t.rt)),
    maxRT: Math.max(...validResults.map(t => t.rt))
  };
}

// Example usage
if (import.meta.url === `file://${process.argv[1]}`) {
  runSimpleRT()
    .then(analysis => {
      console.log('RT experiment completed:', analysis);
    })
    .catch(error => {
      console.error('RT experiment failed:', error);
    });
}

export { runSimpleRT };

