/**
 * Classic Stroop Color-Word Interference Task - Clean API Version
 * 
 * This example demonstrates:
 * - Timeline creation with the new API
 * - Dynamic stimulus content
 * - Response collection and validation
 * - Factorial design and randomization
 * - Data collection and analysis
 */

import { experiment } from '../src/api';

// Just use the fluent template!
async function runStroopTask() {
  const results = await experiment({
    title: 'Stroop Color-Word Interference Task'
  })
    .stroop()
    .colors(['red', 'green', 'blue', 'yellow'])
    .trials(80)
    .practice(3)
    .run();

  // Display results
  console.log('Experiment completed!');
  console.log(`Total trials: ${results.trials.length}`);
  console.log(`Accuracy: ${results.summary.accuracy.toFixed(1)}%`);
  console.log(`Average RT: ${results.summary.meanRT.toFixed(0)}ms`);
  console.log(`Stroop Effect: ${results.stroop.stroopEffect.toFixed(0)}ms`);
  console.log(`  Congruent RT: ${results.stroop.congruentRT.toFixed(0)}ms`);
  console.log(`  Incongruent RT: ${results.stroop.incongruentRT.toFixed(0)}ms`);

  return results;
}

// Alternative: Build it manually for more control
import { 
  Trial, 
  TrialList,
  Text, 
  FixationCross,
  KeypressResponse 
} from '../src/api';

async function runCustomStroopTask() {
  const exp = experiment({
    title: 'Custom Stroop Task'
  });

  // Define colors and mappings
  const COLORS = {
    red: '#FF0000',
    green: '#00FF00',
    blue: '#0000FF',
    yellow: '#FFFF00'
  };

  // Instructions
  const instructions = new Trial({
    stimuli: new Text({
      content: `Welcome to the Stroop Task!

You will see words displayed in different colors.
Your task is to identify the COLOR of the text, not the word itself.

Response Keys:
R = Red    G = Green    B = Blue    Y = Yellow

Remember: Respond to the COLOR, not the word!

Press SPACE to continue...`,
      fontSize: 20,
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space']
    })
  });

  // Practice trials - manually defined for feedback
  const practiceTrials = [
    { word: 'RED', color: 'red', congruent: true },
    { word: 'BLUE', color: 'green', congruent: false },
    { word: 'GREEN', color: 'blue', congruent: false },
  ].map((condition, i) => new Trial({
    stimuli: [
      new FixationCross({ duration: 500 }),
      new Text({
        content: condition.word,
        color: COLORS[condition.color as keyof typeof COLORS],
        fontSize: 48,
        position: 'center'
      })
    ],
    response: new KeypressResponse({
      validKeys: ['r', 'g', 'b', 'y'],
      timeout: 3000,
      correct: condition.color.charAt(0)
    }),
    data: {
      ...condition,
      phase: 'practice',
      trialNumber: i + 1
    }
  }));

  // Practice feedback
  const practiceFeedback = (result: any) => new Trial({
    stimuli: new Text({
      content: result.correct 
        ? 'Correct!' 
        : 'Incorrect. Remember to respond to the COLOR.',
      color: result.correct ? '#00FF00' : '#FF0000',
      fontSize: 20,
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space'],
      timeout: 1500
    })
  });

  // Main experimental trials using factorial design
  const mainTrials = TrialList.fromFactors({
    factors: {
      word: ['RED', 'GREEN', 'BLUE', 'YELLOW'],
      color: ['red', 'green', 'blue', 'yellow']
    },
    template: ({ word, color }) => new Trial({
      stimuli: [
        new FixationCross({ duration: 500 }),
        new Text({
          content: word,
          color: COLORS[color as keyof typeof COLORS],
          fontSize: 48,
          position: 'center'
        })
      ],
      response: new KeypressResponse({
        validKeys: ['r', 'g', 'b', 'y'],
        timeout: 5000,
        correct: color.charAt(0)
      }),
      data: {
        word,
        color,
        congruent: word.toLowerCase() === color,
        phase: 'main'
      },
      iti: 250
    }),
    repetitions: 5, // 5 × 4 × 4 = 80 trials
    randomization: 'shuffle'
  });

  // Add breaks every 20 trials
  const trialsWithBreaks = mainTrials.splitIntoBlocks(4).reduce((acc, block, i) => {
    if (i > 0) {
      acc.push(new TrialList({
        trials: [
          new Trial({
            stimuli: new Text({
              content: `Take a short break.

You've completed ${i * 20} of 80 trials.

Press SPACE when ready to continue...`,
              fontSize: 20,
              position: 'center'
            }),
            response: new KeypressResponse({
              validKeys: ['space']
            })
          })
        ],
        randomization: 'none'
      }));
    }
    acc.push(block);
    return acc;
  }, [] as TrialList[]);

  // Completion screen
  const completion = new Trial({
    stimuli: new Text({
      content: `Task Complete!

Thank you for participating!

Your data has been saved.`,
      fontSize: 20,
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space'],
      timeout: 3000
    })
  });

  // Run the experiment
  await exp.run(instructions);

  // Practice with feedback
  for (const trial of practiceTrials) {
    const result = await exp.run(trial);
    await exp.run(practiceFeedback(result.trials[0]));
  }

  // Main trials with breaks
  const allResults = await exp.runSequence(...trialsWithBreaks);

  // Show completion
  await exp.run(completion);

  // Clean up
  await exp.cleanup();

  // Calculate Stroop statistics
  const mainResults = allResults.trials.filter(t => t.data.phase === 'main');
  const congruent = mainResults.filter(t => t.data.congruent && !t.timeout);
  const incongruent = mainResults.filter(t => !t.data.congruent && !t.timeout);

  const congruentRT = congruent.reduce((sum, t) => sum + t.rt, 0) / congruent.length;
  const incongruentRT = incongruent.reduce((sum, t) => sum + t.rt, 0) / incongruent.length;

  return {
    accuracy: (mainResults.filter(t => t.correct).length / mainResults.length) * 100,
    congruentRT,
    incongruentRT,
    stroopEffect: incongruentRT - congruentRT
  };
}

// Example usage
if (import.meta.url === `file://${process.argv[1]}`) {
  // Choose which version to run
  const useTemplate = true;

  if (useTemplate) {
    runStroopTask()
      .then(results => console.log('Stroop task completed'))
      .catch(error => console.error('Stroop task failed:', error));
  } else {
    runCustomStroopTask()
      .then(stats => {
        console.log('Custom Stroop Results:');
        console.log(`  Accuracy: ${stats.accuracy.toFixed(1)}%`);
        console.log(`  Stroop Effect: ${stats.stroopEffect.toFixed(0)}ms`);
      })
      .catch(error => console.error('Custom Stroop failed:', error));
  }
}

export { runStroopTask, runCustomStroopTask };

/**
 * Comparison with old API:
 * - Old: 185 lines with complex timeline management
 * - New Template: 5 lines for complete Stroop!
 * - New Custom: ~150 lines but much clearer
 * - Automatic factorial design generation
 * - Built-in Stroop effect calculation
 * - No manual randomization needed
 */

