/**
 * Trail Making Test Implementation
 * 
 * This example demonstrates how to implement the classic neuropsychological
 * Trail Making Test (Parts A and B) using Psycho-Forge components.
 * 
 * Part A: Connect numbers 1-25 in sequential order
 * Part B: Alternate between numbers (1-12) and letters (A-L)
 */

import { ForgeBuilder } from '../src/ForgeBuilder.js';
import { TrailsAComponent, TrailsBComponent } from '../src/components/neuropsych/index.js';

// Trail Making Test Part A
const trailsAExperiment = ForgeBuilder.experiment('trails-a-test')
  .metadata({
    title: 'Trail Making Test - Part A',
    description: 'Connect numbered circles in sequential order',
    version: '1.0.0',
    authors: ['Psycho-Forge Team']
  })
  .sequence(seq => seq
    // Instructions
    .trial('instructions', trial => trial
      .addStimulus('text', {
        type: 'text',
        content: `
          Trail Making Test - Part A

          You will see circles with numbers inside them.
          Your task is to connect the circles in numerical order:
          1 → 2 → 3 → ... → 25

          Click on each circle in the correct order.
          Work as quickly and accurately as possible.

          Press SPACE to begin.
        `,
        position: { x: 400, y: 300 },
        fontSize: 24,
        align: 'center'
      })
      .waitFor('keyboard', { keys: [' '] })
    )

    // Trail Making Test A
    .trial('trails-a', trial => {
      const trailsA = new TrailsAComponent('trails-a-1', {
        npoints: 25,
        radius: 30,
        width: 800,
        height: 600
      });

      return trial
        .addComponent(trailsA)
        .onStart(({ context }) => {
          // Start the trails task
          trailsA.start(context);

          // Set up completion handler
          trailsA.onComplete((data) => {
            context.data.trailsA = {
              completionTime: data.time,
              errors: data.errors,
              timestamp: Date.now()
            };
          });
        })
        .waitFor('component-signal', { 
          componentId: 'trails-a-1',
          signal: 'trail_completed' 
        });
    })

    // Results
    .trial('results', trial => trial
      .addStimulus('text', {
        type: 'text',
        content: ({ context }) => {
          const results = context.data.trailsA;
          return `
            Trail Making Test A Complete!

            Time: ${(results.completionTime / 1000).toFixed(1)} seconds
            Errors: ${results.errors}

            Press SPACE to continue.
          `;
        },
        position: { x: 400, y: 300 },
        fontSize: 24,
        align: 'center'
      })
      .waitFor('keyboard', { keys: [' '] })
    )
  );

// Trail Making Test Part B
const trailsBExperiment = ForgeBuilder.experiment('trails-b-test')

