import { 
  experiment,
  Trial,
  Text,
  KeypressResponse
} from '../src/api';

// Import the neuropsych components (these would be part of the new API)
import { TrailsA, TrailsB } from '../src/api/components/neuropsych';

// Trail Making Test Part A
