/**
 * Psycho-Forge Hardware Timing Validation Example
 * 
 * This example demonstrates how to validate timing precision
 * on different hardware configurations.
 */

import { 
  HardwareTimingValidator, 
  PerformanceMonitor,
  type ValidationReport 
} from '@psyforge/forgescript';

async function runTimingValidation() {
  console.log('🔬 Starting Psycho-Forge Hardware Timing Validation...\n');

  // Create validator
  const validator = new HardwareTimingValidator();

  // Run validation for 5 seconds
  const report = await validator.validate(5000);

  // Display results
  console.log('📊 Validation Results:');
  console.log('====================\n');

  // Timing precision
  console.log(`⏱️  Timing Precision: ${report.timingPrecision.measured.toFixed(2)}ms`);
  console.log(`   Target: ${report.timingPrecision.target}ms`);
  console.log(`   Status: ${report.timingPrecision.meetsTarget ? '✅ PASS' : '❌ FAIL'}\n`);

  // Performance metrics
  console.log('📈 Performance Metrics:');
  console.log(`   FPS: ${report.metrics.fps.toFixed(2)}`);
  console.log(`   Frame Variance: ${report.metrics.frameVariance.toFixed(2)}ms`);
  console.log(`   Dropped Frames: ${report.metrics.droppedFrames}`);
  console.log(`   Memory Usage: ${report.metrics.heapUsage.toFixed(0)}MB\n`);

  // Hardware info
  console.log('💻 Hardware Information:');
  console.log(`   Platform: ${report.metrics.browserInfo.platform}`);
  console.log(`   CPU Cores: ${report.metrics.browserInfo.hardwareConcurrency}`);
  console.log(`   Display: ${report.metrics.displayInfo.width}x${report.metrics.displayInfo.height}`);
  console.log(`   Refresh Rate: ${report.metrics.displayInfo.refreshRate}Hz\n`);

  // WebGL info
  if (report.metrics.webGLInfo) {
    console.log('🎮 Graphics Information:');
    console.log(`   WebGL Version: ${report.metrics.webGLInfo.version}`);
    console.log(`   GPU: ${report.metrics.webGLInfo.renderer}\n`);
  }

  // Capabilities
  console.log('✅ Browser Capabilities:');
  Object.entries(report.capabilities).forEach(([key, value]) => {
    console.log(`   ${key}: ${value ? '✅' : '❌'}`);
  });
  console.log('');

  // Warnings
  if (report.warnings.length > 0) {
    console.log('⚠️  Warnings:');
    report.warnings.forEach(warning => {
      console.log(`   - ${warning}`);
    });
    console.log('');
  }

  // Recommendations
  if (report.recommendations.length > 0) {
    console.log('💡 Recommendations:');
    report.recommendations.forEach(rec => {
      console.log(`   - ${rec}`);
    });
    console.log('');
  }

  // Export report
  const exportedReport = await validator.exportReport(report);
  console.log('📄 Full report exported to: validation-report.json\n');

  return report;
}

async function runPerformanceMonitoring() {
  console.log('📊 Starting Performance Monitoring...\n');

  // Create performance monitor with custom thresholds
  const monitor = new PerformanceMonitor({
    minFPS: 55,
    maxFrameTime: 20,
    maxHeapUsage: 300,
    maxDroppedFrames: 5
  });

  // Listen for warnings
  monitor.on('warning', (warning) => {
    console.log(`⚠️  Performance Warning: ${warning.message}`);
  });

  // Listen for metrics updates
  monitor.on('metrics', (metrics) => {
    if (Math.random() < 0.1) { // Log 10% of metrics
      console.log(`📈 FPS: ${metrics.fps.toFixed(1)}, Memory: ${metrics.heapUsed.toFixed(0)}MB`);
    }
  });

  // Start monitoring
  monitor.start();

  // Simulate experiment workload
  console.log('🧪 Simulating experiment workload...');

  const canvas = document.createElement('canvas');
  canvas.width = 800;
  canvas.height = 600;
  document.body.appendChild(canvas);

  const ctx = canvas.getContext('2d');
  if (!ctx) {
    console.error('Failed to get canvas context');
    return;
  }

  let frame = 0;
  const animate = () => {
    // Record update time
    const updateStart = performance.now();

    // Simulate computation
    for (let i = 0; i < 1000; i++) {
      Math.sqrt(Math.random());
    }

    monitor.recordUpdateTime(performance.now() - updateStart);

    // Record render time
    const renderStart = performance.now();

    // Draw something
    ctx.fillStyle = `hsl(${frame % 360}, 50%, 50%)`;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = 'white';
    ctx.font = '48px Arial';
    ctx.textAlign = 'center';
    ctx.fillText(`Frame ${frame}`, canvas.width / 2, canvas.height / 2);

    monitor.recordRenderTime(performance.now() - renderStart);

    frame++;

    if (frame < 300) { // Run for 300 frames (~5 seconds)
      requestAnimationFrame(animate);
    } else {
      // Stop monitoring and show report
      monitor.stop();

      console.log('\n📊 Performance Summary:');
      console.log(monitor.createPerformanceReport());

      // Cleanup
      document.body.removeChild(canvas);
    }
  };

  requestAnimationFrame(animate);
}

// Determine which demo to run based on environment
if (typeof window !== 'undefined') {
  // Browser environment
  window.addEventListener('DOMContentLoaded', async () => {
    // Add UI for selecting demo
    const button1 = document.createElement('button');
    button1.textContent = 'Run Timing Validation';
    button1.onclick = runTimingValidation;
    document.body.appendChild(button1);

    const button2 = document.createElement('button');
    button2.textContent = 'Run Performance Monitoring';
    button2.onclick = runPerformanceMonitoring;
    document.body.appendChild(button2);

    // Auto-run validation
    await runTimingValidation();
  });
} else {
  // Node.js environment - run validation only
  runTimingValidation().catch(console.error);
}

// Export for use in other modules
export { runTimingValidation, runPerformanceMonitoring };

