/**
 * Hardware Timing Validation Example - Clean API Version
 * 
 * This example demonstrates how to validate timing precision
 * using the simplified ForgeScript API.
 */

import { 
  experiment,
  Trial,
  TrialList,
  Text,
  Rectangle,
  KeypressResponse,
  TimingValidator
} from '../src/api';

async function runTimingValidation() {
  console.log('🔬 Starting Hardware Timing Validation...\n');

  const exp = experiment({
    title: 'Timing Validation',
    performance: {
      monitoring: true,
      targetFPS: 60,
      maxFrameTime: 16.67
    }
  });

  // Welcome screen
  const welcome = new Trial({
    stimuli: new Text({
      content: `Timing Validation Test

This will test your hardware's timing precision.

Press SPACE to begin...`,
      fontSize: 24,
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space']
    })
  });

  // Create timing test trials
  const timingTrials = new TrialList({
    trials: Array(100).fill(null).map((_, i) => new Trial({
      stimuli: [
        // Flash a rectangle at precise intervals
        new Rectangle({
          width: 200,
          height: 200,
          color: i % 2 === 0 ? '#FF0000' : '#00FF00',
          position: 'center',
          duration: 16.67 // Exactly one frame at 60Hz
        })
      ],
      response: new KeypressResponse({
        validKeys: [],
        timeout: 16.67
      }),
      data: {
        trialNumber: i,
        targetDuration: 16.67
      }
    })),
    randomization: 'none'
  });

  // Run validation
  await exp.run(welcome);

  console.log('Running timing tests...');
  const startTime = performance.now();
  const results = await exp.run(timingTrials);
  const totalTime = performance.now() - startTime;

  // Get timing report from experiment
  const report = exp.getTimingReport();

  // Display results
  console.log('\n📊 Validation Results:');
  console.log('====================\n');

  // Timing precision
  const avgFrameTime = totalTime / 100;
  const precision = Math.abs(avgFrameTime - 16.67);
  console.log(`⏱️  Average Frame Time: ${avgFrameTime.toFixed(2)}ms`);
  console.log(`   Target: 16.67ms`);
  console.log(`   Precision: ±${precision.toFixed(2)}ms`);
  console.log(`   Status: ${precision < 2 ? '✅ PASS' : '❌ FAIL'}\n`);

  // Performance metrics
  console.log('📈 Performance Metrics:');
  console.log(`   Average FPS: ${report.metrics.fps.toFixed(2)}`);
  console.log(`   Frame Variance: ${report.metrics.frameVariance.toFixed(2)}ms`);
  console.log(`   Dropped Frames: ${report.metrics.droppedFrames}`);
  console.log(`   95th Percentile: ${report.metrics.p95.toFixed(2)}ms\n`);

  // Browser capabilities
  console.log('✅ Browser Capabilities:');
  console.log(`   WebGL: ${report.capabilities.webgl ? '✅' : '❌'}`);
  console.log(`   High Resolution Timer: ${report.capabilities.hrTime ? '✅' : '❌'}`);
  console.log(`   RequestAnimationFrame: ${report.capabilities.raf ? '✅' : '❌'}`);
  console.log(`   Display Refresh Rate: ${report.capabilities.refreshRate}Hz\n`);

  // Warnings and recommendations
  if (report.warnings.length > 0) {
    console.log('⚠️  Warnings:');
    report.warnings.forEach(warning => {
      console.log(`   - ${warning}`);
    });
    console.log('');
  }

  await exp.cleanup();
  return report;
}

async function runVisualTimingTest() {
  console.log('🎯 Starting Visual Timing Test...\n');

  const exp = experiment({
    title: 'Visual Timing Test',
    screen: {
      backgroundColor: '#333333'
    }
  });

  // Instructions
  const instructions = new Trial({
    stimuli: new Text({
      content: `Visual Timing Test

This test will flash colored squares to validate display timing.

You'll see 60 flashes over 1 second.

Press SPACE to start...`,
      fontSize: 20,
      color: '#FFFFFF',
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space']
    })
  });

  // Create rapid visual stimuli
  const visualTrials = new TrialList({
    trials: Array(60).fill(null).map((_, i) => new Trial({
      stimuli: new Rectangle({
        width: 400,
        height: 400,
        color: `hsl(${i * 6}, 70%, 50%)`,
        position: 'center',
        duration: 16.67 // One frame at 60Hz
      }),
      response: new KeypressResponse({
        validKeys: [],
        timeout: 16.67
      }),
      iti: 0 // No inter-trial interval
    })),
    randomization: 'none'
  });

  // Results screen
  const results = new Trial({
    stimuli: new Text({
      content: `Test Complete!

Check the console for detailed timing analysis.

Press SPACE to exit...`,
      fontSize: 20,
      color: '#FFFFFF',
      position: 'center'
    }),
    response: new KeypressResponse({
      validKeys: ['space']
    })
  });

  // Run test
  await exp.run(instructions);

  const startTime = performance.now();
  await exp.run(visualTrials);
  const duration = performance.now() - startTime;

  console.log(`\n✅ Visual Test Complete`);
  console.log(`   Expected duration: 1000ms`);
  console.log(`   Actual duration: ${duration.toFixed(2)}ms`);
  console.log(`   Deviation: ${Math.abs(duration - 1000).toFixed(2)}ms`);

  await exp.run(results);
  await exp.cleanup();
}

// Simplified timing validator using clean API
async function validateWithTemplate() {
  // Use built-in timing validation template
  const report = await experiment()
    .timingValidation()
    .trials(100)
    .targetPrecision(2) // ±2ms
    .run();

  console.log('Timing validation complete:', report);
  return report;
}

// Run appropriate test based on environment
if (typeof window !== 'undefined') {
  window.addEventListener('DOMContentLoaded', () => {
    const container = document.createElement('div');
    container.style.textAlign = 'center';
    container.style.marginTop = '50px';

    const btn1 = document.createElement('button');
    btn1.textContent = 'Run Timing Validation';
    btn1.style.margin = '10px';
    btn1.style.padding = '10px 20px';
    btn1.onclick = runTimingValidation;

    const btn2 = document.createElement('button');
    btn2.textContent = 'Run Visual Test';
    btn2.style.margin = '10px';
    btn2.style.padding = '10px 20px';
    btn2.onclick = runVisualTimingTest;

    const btn3 = document.createElement('button');
    btn3.textContent = 'Quick Validation';
    btn3.style.margin = '10px';
    btn3.style.padding = '10px 20px';
    btn3.onclick = validateWithTemplate;

    container.appendChild(btn1);
    container.appendChild(btn2);
    container.appendChild(btn3);
    document.body.appendChild(container);
  });
}

