import { 
  experiment,
  TextStimulusPixi,
  ImageStimulusPixi,
  ShapeStimulusPixi,
  rectangle,
  circle,
  star,
  StimulusRenderer
} from '../src/index.js';

// Create a demo experiment using PixiJS stimuli
async function createPixiDemo() {
  // Initialize the renderer
  const renderer = StimulusRenderer.getInstance();
  await renderer.initialize({
    backgroundColor: '#1a1a1a',
    antialias: true,
    powerPreference: 'high-performance'
  });

  // Create experiment with PixiJS stimuli
  const pixiExperiment = experiment('PixiJS Stimulus Demo')
    .description('Demonstrates high-performance rendering with PixiJS')
    .author('PsyForge Team')
    .requireConsent(true)
    .consent({
      purpose: 'Scientific research with visual stimuli',
      dataTypes: ['Response times', 'Accuracy', 'Visual stimulus data'],
      storageDuration: 'Until study completion'
    });

  // Welcome screen with animated text
  pixiExperiment.trial()
    .stimulus(() => {
      const text = new TextStimulusPixi(
        'welcome-text',
        'Welcome to the PixiJS Stimulus Demo!',
        {
          fontSize: 48,
          fontFamily: 'Arial, sans-serif',
          color: '#00FF88',
          dropShadow: true,
          dropShadowColor: '#000000',
          dropShadowBlur: 4,
          dropShadowDistance: 6,
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 - 100 }
        }
      );
      return text;
    })
    .stimulus(() => {
      const subtitle = new TextStimulusPixi(
        'subtitle',
        'Press SPACE to continue',
        {
          fontSize: 24,
          color: '#CCCCCC',
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
        }
      );
      return subtitle;
    })
    .response('keyboard', { keys: ['space'] });

  // Shape demonstration
  pixiExperiment.trial()
    .stimulus(() => {
      const title = new TextStimulusPixi(
        'shape-title',
        'Geometric Shapes with PixiJS',
        {
          fontSize: 36,
          color: '#FFFFFF',
          position: { x: window.innerWidth / 2, y: 100 }
        }
      );
      return title;
    })
    .stimulus(() => {
      // Red square
      return rectangle('red-square', 150, 150)
        .fill('#FF4444')
        .stroke('#FFFFFF', 3)
        .position(window.innerWidth / 2 - 200, window.innerHeight / 2);
    })
    .stimulus(() => {
      // Blue circle
      return circle('blue-circle', 75)
        .fill('#4444FF')
        .stroke('#FFFFFF', 3)
        .position(window.innerWidth / 2, window.innerHeight / 2);
    })
    .stimulus(() => {
      // Yellow star
      return star('yellow-star', 5, 30, 75)
        .fill('#FFFF44')
        .stroke('#FF8800', 3)
        .position(window.innerWidth / 2 + 200, window.innerHeight / 2);
    })
    .duration(3000);

  // Text styling demonstration
  pixiExperiment.trial()
    .stimulus(() => {
      const title = new TextStimulusPixi(
        'style-title',
        'Advanced Text Styling',
        {
          fontSize: 36,
          color: '#FFFFFF',
          position: { x: window.innerWidth / 2, y: 100 }
        }
      );
      return title;
    })
    .stimulus(() => {
      const strokedText = new TextStimulusPixi(
        'stroked-text',
        'Stroked Text',
        {
          fontSize: 48,
          color: '#FFFFFF',
          strokeColor: '#FF0000',
          strokeThickness: 4,
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 - 100 }
        }
      );
      return strokedText;
    })
    .stimulus(() => {
      const shadowText = new TextStimulusPixi(
        'shadow-text',
        'Drop Shadow Text',
        {
          fontSize: 48,
          color: '#00FFFF',
          dropShadow: true,
          dropShadowColor: '#0000FF',
          dropShadowBlur: 8,
          dropShadowDistance: 8,
          dropShadowAngle: Math.PI / 4,
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
        }
      );
      return shadowText;
    })
    .stimulus(() => {
      const gradientText = new TextStimulusPixi(
        'gradient-text',
        'Letter Spacing & Line Height',
        {
          fontSize: 32,
          color: '#FFFF00',
          letterSpacing: 5,
          lineHeight: 40,
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 + 100 }
        }
      );
      return gradientText;
    })
    .duration(3000);

  // Stroop-like task with PixiJS
  const colors = ['#FF0000', '#00FF00', '#0000FF', '#FFFF00'];
  const colorNames = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
  const colorKeys = ['r', 'g', 'b', 'y'];

  pixiExperiment.trial()
    .stimulus(() => {
      const instruction = new TextStimulusPixi(
        'stroop-instruction',
        'Name the COLOR of the word (R=Red, G=Green, B=Blue, Y=Yellow)',
        {
          fontSize: 24,
          color: '#FFFFFF',
          position: { x: window.innerWidth / 2, y: 100 }
        }
      );
      return instruction;
    })
    .duration(3000);

  // Generate 10 Stroop trials
  for (let i = 0; i < 10; i++) {
    const wordIndex = Math.floor(Math.random() * colorNames.length);
    const colorIndex = Math.floor(Math.random() * colors.length);

    pixiExperiment.trial()
      // Fixation cross
      .stimulus(() => {
        const fixation = new TextStimulusPixi(
          `fixation-${i}`,
          '+',
          {
            fontSize: 48,
            color: '#FFFFFF',
            position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
          }
        );
        return fixation;
      })
      .duration(500)

      // Stroop stimulus
      .stimulus(() => {
        const stroopWord = new TextStimulusPixi(
          `stroop-word-${i}`,
          colorNames[wordIndex],
          {
            fontSize: 72,
            fontWeight: 'bold',
            color: colors[colorIndex],
            position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
          }
        );
        return stroopWord;
      })
      .response('keyboard', { 
        keys: colorKeys,
        timeout: 3000,
        recordData: {
          word: colorNames[wordIndex],
          color: colorNames[colorIndex],
          congruent: wordIndex === colorIndex
        }
      });
  }

  // Thank you screen
  pixiExperiment.trial()
    .stimulus(() => {
      const thanks = new TextStimulusPixi(
        'thanks',
        'Thank you for participating!',
        {
          fontSize: 48,
          color: '#00FF88',
          dropShadow: true,
          position: { x: window.innerWidth / 2, y: window.innerHeight / 2 }
        }
      );
      return thanks;
    })
    .duration(3000);

  return pixiExperiment;
}

// Run the demo
async function runDemo() {
  try {
    const demo = await createPixiDemo();
    console.log('PixiJS Demo Experiment Created:', demo);

    // Compile and validate
    const compiled = await demo.compile();
    console.log('Compiled experiment:', compiled);

    // Run the experiment
    const results = await demo.run('demo-participant');
    console.log('Experiment results:', results);

  } catch (error) {
    console.error('Demo failed:', error);
  }
}

// Export for use
export { createPixiDemo, runDemo };

