 * 
 * This example demonstrates high-performance visual stimuli
 * using the simplified ForgeScript API with PixiJS rendering.
 */

import { 
  experiment,
  Trial,
  TrialList,
  Text,
  Rectangle,
  Circle,
  Polygon,
  KeypressResponse
} from '../src/api';

async function createPixiDemo() {
  const exp = experiment({
    title: 'PixiJS Stimulus Demo',
    screen: {
      backgroundColor: '#1a1a1a',
      antialias: true
    }
  });

  // Welcome screen with styled text
  const welcome = new Trial({
    stimuli: [
      new Text({
        content: 'Welcome to the PixiJS Stimulus Demo!',
        fontSize: 48,
        color: '#00FF88',
        position: 'center',
        style: {
          dropShadow: true,
          dropShadowColor: '#000000',
          dropShadowBlur: 4,
          dropShadowDistance: 6
        }
      }),
      new Text({
        content: 'Press SPACE to continue',
        fontSize: 24,
        color: '#CCCCCC',
        position: { x: 'center', y: 400 }
      })
    ],
    response: new KeypressResponse({
      validKeys: ['space']
    })
  });

  // Shape demonstration
  const shapesDemo = new Trial({
    stimuli: [
      new Text({
        content: 'Geometric Shapes with PixiJS',
        fontSize: 36,
        color: '#FFFFFF',
        position: { x: 'center', y: 100 }
      }),
      // Red square
      new Rectangle({
        width: 150,
        height: 150,
        color: '#FF4444',
        borderColor: '#FFFFFF',
        borderWidth: 3,
        position: { x: 200, y: 'center' }
      }),
      // Blue circle
      new Circle({
        radius: 75,
        color: '#4444FF',
        borderColor: '#FFFFFF',
        borderWidth: 3,
        position: 'center'
      }),
      // Yellow star
      new Polygon({
        points: createStarPoints(5, 30, 75),
        color: '#FFFF44',
        borderColor: '#FF8800',
        borderWidth: 3,
        position: { x: 600, y: 'center' }
      })
    ],
    response: new KeypressResponse({
      validKeys: [],
      timeout: 3000
    })
  });

  // Text styling demonstration
  const textStyleDemo = new Trial({
    stimuli: [
      new Text({
        content: 'Advanced Text Styling',
        fontSize: 36,
        color: '#FFFFFF',
        position: { x: 'center', y: 100 }
      }),
      new Text({
        content: 'Stroked Text',
        fontSize: 48,
        color: '#FFFFFF',
        position: { x: 'center', y: 250 },
        style: {
          stroke: '#FF0000',
          strokeThickness: 4
        }
      }),
      new Text({
        content: 'Drop Shadow Text',
        fontSize: 48,
        color: '#00FFFF',
        position: { x: 'center', y: 350 },
        style: {
          dropShadow: true,
          dropShadowColor: '#0000FF',
          dropShadowBlur: 8,
          dropShadowDistance: 8,
          dropShadowAngle: Math.PI / 4
        }
      }),
      new Text({
        content: 'Letter Spacing & Line Height',
        fontSize: 32,
        color: '#FFFF00',
        position: { x: 'center', y: 450 },
        style: {
          letterSpacing: 5,
          lineHeight: 40
        }
      })
    ],
    response: new KeypressResponse({
      validKeys: [],
      timeout: 3000
    })
  });

  // Stroop-like task with PixiJS
  const colors = {
    red: '#FF0000',
    green: '#00FF00', 
    blue: '#0000FF',
    yellow: '#FFFF00'
  };

  const colorNames = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
  const colorKeys = ['red', 'green', 'blue', 'yellow'];

  // Instructions
  const stroopInstructions = new Trial({
    stimuli: new Text({
      content: 'Name the COLOR of the word (R=Red, G=Green, B=Blue, Y=Yellow)',
      fontSize: 24,
      color: '#FFFFFF',
      position: { x: 'center', y: 100 }
    }),
    response: new KeypressResponse({
      validKeys: [],
      timeout: 3000
    })
  });

  // Generate Stroop trials using factorial design
  const stroopTrials = new TrialList({
    trials: Array(10).fill(null).map(() => {
      const word = colorNames[Math.floor(Math.random() * colorNames.length)];
      const colorKey = colorKeys[Math.floor(Math.random() * colorKeys.length)];
      const color = colors[colorKey as keyof typeof colors];

      return new Trial({
        stimuli: [
          new Text({
            content: '+',
            fontSize: 48,
            color: '#FFFFFF',
            position: 'center',
            duration: 500
          }),
          new Text({
            content: word,
            fontSize: 72,
            color: color,
            position: 'center',
            style: {
              fontWeight: 'bold'
            }
          })
        ],
        response: new KeypressResponse({
          validKeys: ['r', 'g', 'b', 'y'],
          correct: colorKey.charAt(0),
          timeout: 3000
        }),
        data: {
          word: word,
          color: colorKey,
          congruent: word.toLowerCase() === colorKey
        }
      });
    }),
    randomization: 'shuffle'
  });

  // Thank you screen
  const thanks = new Trial({
    stimuli: new Text({
      content: 'Thank you for participating!',
      fontSize: 48,
      color: '#00FF88',
      position: 'center',
      style: {
        dropShadow: true
      }
    }),
    response: new KeypressResponse({
      validKeys: [],
      timeout: 3000
    })
  });

  return { exp, trials: {
    welcome,
    shapesDemo,
    textStyleDemo,
    stroopInstructions,
    stroopTrials,
    thanks
  }};
}

// Helper function to create star points
function createStarPoints(points: number, innerRadius: number, outerRadius: number) {
  const result = [];
  const angleStep = (Math.PI * 2) / points;

  for (let i = 0; i < points * 2; i++) {
    const radius = i % 2 === 0 ? outerRadius : innerRadius;
    const angle = (i * angleStep) / 2 - Math.PI / 2;
    result.push({
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius
    });
  }

  return result;
}

// Run the demo
async function runPixiDemo() {
  console.log('Starting PixiJS Demo...');

  const { exp, trials } = await createPixiDemo();

  try {
    // Run each section
    await exp.run(trials.welcome);
    await exp.run(trials.shapesDemo);
    await exp.run(trials.textStyleDemo);
    await exp.run(trials.stroopInstructions);

    // Run Stroop trials and collect results
    const results = await exp.run(trials.stroopTrials);

    // Calculate accuracy
    const correct = results.trials.filter(t => t.correct).length;
    const accuracy = (correct / results.trials.length) * 100;

    console.log(`Stroop Task Results:`);
    console.log(`  Accuracy: ${accuracy.toFixed(1)}%`);
    console.log(`  Correct: ${correct}/${results.trials.length}`);

    await exp.run(trials.thanks);
    await exp.cleanup();

    return results;
  } catch (error) {
    console.error('Demo failed:', error);
    await exp.cleanup();
    throw error;
  }
}

// Alternative: Use visual demo template
async function runVisualDemoTemplate() {
  const results = await experiment()
    .visualDemo()
    .shapes(['rectangle', 'circle', 'star'])
    .textStyles(['stroke', 'shadow', 'spacing'])
    .includeStroop(10)
    .run();

  return results;
}

export { createPixiDemo, runPixiDemo, runVisualDemoTemplate };

/**
 * Comparison with old API:
 * - Old: Direct PixiJS manipulation with 270 lines
 * - New: Clean stimulus abstractions with ~200 lines
 * - Automatic rendering optimization
 * - Simplified shape and text creation
 * - Built-in style system
 * - Template for common visual demos
 */

