/**
 * Flanker Task Template
 * 
 * The Eriksen flanker task measures response inhibition and selective attention.
 * Participants respond to a central target arrow while ignoring flanking arrows.
 */

import { Experiment } from '../Experiment';
import { Trial } from '../Trial';
import { TrialList } from '../TrialList';
import { Text } from '../stimuli/Text';
import { FixationCross } from '../stimuli/FixationCross';
import { KeypressResponse } from '../responses/KeypressResponse';

export interface FlankerOptions {
  arrows?: string[];
  congruentTrials?: number;
  incongruentTrials?: number;
  neutralTrials?: number;
  practice?: number;
  fixationDuration?: number;
  stimulusDuration?: number;
  responseTimeout?: number;
  iti?: number;
  feedback?: boolean;
  keyMapping?: { left: string; right: string };
}

export class FlankerBuilder {
  private experiment: Experiment;
  private options: Required<FlankerOptions>;

  constructor(experiment: Experiment) {
    this.experiment = experiment;
    this.options = {
      arrows: ['←', '→'],
      congruentTrials: 40,
      incongruentTrials: 40,
      neutralTrials: 20,
      practice: 10,
      fixationDuration: 500,
      stimulusDuration: 0, // Until response
      responseTimeout: 1500,
      iti: 500,
      feedback: false,
      keyMapping: { left: 'z', right: '/' }
    };
  }

  arrows(arrows: string[]): this {
    this.options.arrows = arrows;
    return this;
  }

  congruent(trials: number): this {
    this.options.congruentTrials = trials;
    return this;
  }

  incongruent(trials: number): this {
    this.options.incongruentTrials = trials;
    return this;
  }

  neutral(trials: number): this {
    this.options.neutralTrials = trials;
    return this;
  }

  practice(trials: number): this {
    this.options.practice = trials;
    return this;
  }

  fixation(duration: number): this {
    this.options.fixationDuration = duration;
    return this;
  }

  timeout(ms: number): this {
    this.options.responseTimeout = ms;
    return this;
  }

  feedback(enabled: boolean = true): this {
    this.options.feedback = enabled;
    return this;
  }

  keyMapping(mapping: { left: string; right: string }): this {
    this.options.keyMapping = mapping;
    return this;
  }

  async run(): Promise<any> {
    const exp = this.experiment;

    // Instructions
    const instructions = new Trial({
      stimuli: new Text({
        content: `Flanker Task

You will see arrows pointing left or right.
Your task is to indicate the direction of the CENTRAL arrow.

${this.options.keyMapping.left.toUpperCase()} = Left Arrow
${this.options.keyMapping.right.toUpperCase()} = Right Arrow

Ignore the surrounding arrows and focus only on the center arrow.
Respond as quickly and accurately as possible.

Press SPACE to begin practice trials...`,
        fontSize: 20,
        position: 'center',
        lineHeight: 1.5
      }),
      response: new KeypressResponse({
        validKeys: ['space']
      })
    });

    // Generate trial conditions
    const conditions = this.generateConditions();

    // Practice trials
    if (this.options.practice > 0) {
      const practiceConditions = this.generatePracticeConditions();
      const practiceTrials = this.createTrials(practiceConditions, 'practice');

      const practiceStart = new Trial({
        stimuli: new Text({
          content: 'Practice Trials\n\nPress SPACE to start...',
          fontSize: 24,
          position: 'center'
        }),
        response: new KeypressResponse({
          validKeys: ['space']
        })
      });

      await exp.run(practiceStart);

      for (const trial of practiceTrials.trials) {
        const result = await exp.run(trial);
        if (this.options.feedback) {
          await exp.run(this.createFeedback(result.trials[0]));
        }
      }
    }

    // Main trials
    const mainTrials = this.createTrials(conditions, 'main');

    const mainStart = new Trial({
      stimuli: new Text({
        content: `Main Task

${conditions.length} trials

Press SPACE when ready...`,
        fontSize: 24,
        position: 'center'
      }),
      response: new KeypressResponse({
        validKeys: ['space']
      })
    });

    await exp.run(instructions);
    await exp.run(mainStart);

    const results = await exp.run(mainTrials);

    // Calculate flanker effects
    const analysis = this.analyzeResults(results.trials);

    // Show completion
    const completion = new Trial({
      stimuli: new Text({
        content: `Task Complete!

Accuracy: ${analysis.accuracy.toFixed(1)}%
Average RT: ${analysis.meanRT.toFixed(0)}ms

Flanker Effect: ${analysis.flankerEffect.toFixed(0)}ms
  Congruent: ${analysis.congruentRT.toFixed(0)}ms
  Incongruent: ${analysis.incongruentRT.toFixed(0)}ms

Thank you!`,
        fontSize: 20,
        position: 'center',
        lineHeight: 1.5
      }),
      response: new KeypressResponse({
        validKeys: ['space'],
        timeout: 10000
      })
    });

    await exp.run(completion);

    return {
      trials: results.trials,
      summary: analysis,
      flanker: {
        flankerEffect: analysis.flankerEffect,
        congruentRT: analysis.congruentRT,
        incongruentRT: analysis.incongruentRT,
        neutralRT: analysis.neutralRT
      }
    };
  }

  private generateConditions() {
    const conditions = [];

    // Congruent trials (e.g., →→→→→)
    for (let i = 0; i < this.options.congruentTrials; i++) {
      const direction = Math.random() < 0.5 ? 'left' : 'right';
      const arrow = direction === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      conditions.push({
        display: arrow.repeat(5),
        target: direction,
        congruency: 'congruent'
      });
    }

    // Incongruent trials (e.g., ←←→←←)
    for (let i = 0; i < this.options.incongruentTrials; i++) {
      const direction = Math.random() < 0.5 ? 'left' : 'right';
      const targetArrow = direction === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      const flankerArrow = direction === 'left' ? this.options.arrows[1] : this.options.arrows[0];
      conditions.push({
        display: flankerArrow + flankerArrow + targetArrow + flankerArrow + flankerArrow,
        target: direction,
        congruency: 'incongruent'
      });
    }

    // Neutral trials (e.g., ——→——)
    for (let i = 0; i < this.options.neutralTrials; i++) {
      const direction = Math.random() < 0.5 ? 'left' : 'right';
      const arrow = direction === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      conditions.push({
        display: '——' + arrow + '——',
        target: direction,
        congruency: 'neutral'
      });
    }

    return conditions;
  }

  private generatePracticeConditions() {
    const conditions = [];
    const trialsPerType = Math.floor(this.options.practice / 3);

    // Add equal numbers of each type
    for (let i = 0; i < trialsPerType; i++) {
      // Congruent
      const dir1 = i % 2 === 0 ? 'left' : 'right';
      const arrow1 = dir1 === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      conditions.push({
        display: arrow1.repeat(5),
        target: dir1,
        congruency: 'congruent'
      });

      // Incongruent
      const dir2 = i % 2 === 0 ? 'right' : 'left';
      const targetArrow = dir2 === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      const flankerArrow = dir2 === 'left' ? this.options.arrows[1] : this.options.arrows[0];
      conditions.push({
        display: flankerArrow + flankerArrow + targetArrow + flankerArrow + flankerArrow,
        target: dir2,
        congruency: 'incongruent'
      });

      // Neutral
      const dir3 = i % 2 === 0 ? 'left' : 'right';
      const arrow3 = dir3 === 'left' ? this.options.arrows[0] : this.options.arrows[1];
      conditions.push({
        display: '——' + arrow3 + '——',
        target: dir3,
        congruency: 'neutral'
      });
    }

    return conditions.slice(0, this.options.practice);
  }

  private createTrials(conditions: any[], phase: string): TrialList {
    return new TrialList({
      trials: conditions.map((condition, i) => new Trial({
        stimuli: [
          new FixationCross({ 
            duration: this.options.fixationDuration 
          }),
          new Text({
            content: condition.display,
            fontSize: 48,
            position: 'center',
            duration: this.options.stimulusDuration
          })
        ],
        response: new KeypressResponse({
          validKeys: [this.options.keyMapping.left, this.options.keyMapping.right],
          correct: this.options.keyMapping[condition.target as 'left' | 'right'],
          timeout: this.options.responseTimeout
        }),
        data: {
          ...condition,
          phase,
          trialNumber: i + 1
        },
        iti: this.options.iti
      })),
      randomization: 'shuffle'
    });
  }

  private createFeedback(result: any): Trial {
    let message: string;
    let color: string;

    if (result.timeout) {
      message = 'Too slow!';
      color = '#FF9900';
    } else if (result.correct) {
      message = `Correct! ${result.rt}ms`;
      color = '#00FF00';
    } else {
      message = 'Incorrect';
      color = '#FF0000';
    }

    return new Trial({
      stimuli: new Text({
        content: message,
        fontSize: 24,
        color,
        position: 'center'
      }),
      response: new KeypressResponse({
        validKeys: [],
        timeout: 1000
      })
    });
  }

  private analyzeResults(trials: any[]) {
    const mainTrials = trials.filter(t => t.data.phase === 'main' && !t.timeout);

    const correct = mainTrials.filter(t => t.correct);
    const accuracy = (correct.length / mainTrials.length) * 100;
    const meanRT = correct.reduce((sum, t) => sum + t.rt, 0) / correct.length;

    const congruent = correct.filter(t => t.data.congruency === 'congruent');
    const incongruent = correct.filter(t => t.data.congruency === 'incongruent');
    const neutral = correct.filter(t => t.data.congruency === 'neutral');

    const congruentRT = congruent.length > 0 
      ? congruent.reduce((sum, t) => sum + t.rt, 0) / congruent.length 
      : 0;
    const incongruentRT = incongruent.length > 0
      ? incongruent.reduce((sum, t) => sum + t.rt, 0) / incongruent.length
      : 0;
    const neutralRT = neutral.length > 0
      ? neutral.reduce((sum, t) => sum + t.rt, 0) / neutral.length
      : 0;

    return {
      accuracy,
      meanRT,
      congruentRT,
      incongruentRT,
      neutralRT,
      flankerEffect: incongruentRT - congruentRT
    };
  }
}

export function flanker(): FlankerBuilder {
  return new FlankerBuilder(this as any);
}

