/**
 * N-Back Task Template
 * 
 * The n-back task is a continuous performance task used to measure working memory.
 * Participants must indicate whether the current stimulus matches the one from n steps earlier.
 */

import { Experiment } from '../Experiment';
import { Trial } from '../Trial';
import { TrialList } from '../TrialList';
import { Text } from '../stimuli/Text';
import { FixationCross } from '../stimuli/FixationCross';
import { KeypressResponse } from '../responses/KeypressResponse';

export interface NBackOptions {
  n?: number;
  stimuli?: string[];
  trials?: number;
  targetRate?: number;
  practice?: number;
  stimulusDuration?: number;
  isi?: number;
  responseTimeout?: number;
  feedback?: boolean;
  keyMapping?: { match: string; noMatch: string };
}

export class NBackBuilder {
  private experiment: Experiment;
  private options: Required<NBackOptions>;

  constructor(experiment: Experiment) {
    this.experiment = experiment;
    this.options = {
      n: 2,
      stimuli: ['A', 'B', 'C', 'D', 'E', 'F', 'G', 'H'],
      trials: 60,
      targetRate: 0.3, // 30% match trials
      practice: 20,
      stimulusDuration: 500,
      isi: 2500,
      responseTimeout: 2000,
      feedback: false,
      keyMapping: { match: 'm', noMatch: 'n' }
    };
  }

  n(level: number): this {
    this.options.n = level;
    return this;
  }

  stimuli(items: string[]): this {
    this.options.stimuli = items;
    return this;
  }

  trials(count: number): this {
    this.options.trials = count;
    return this;
  }

  targetRate(rate: number): this {
    this.options.targetRate = Math.max(0, Math.min(1, rate));
    return this;
  }

  practice(trials: number): this {
    this.options.practice = trials;
    return this;
  }

  duration(ms: number): this {
    this.options.stimulusDuration = ms;
    return this;
  }

  isi(ms: number): this {
    this.options.isi = ms;
    return this;
  }

  timeout(ms: number): this {
    this.options.responseTimeout = ms;
    return this;
  }

  feedback(enabled: boolean = true): this {
    this.options.feedback = enabled;
    return this;
  }

  keyMapping(mapping: { match: string; noMatch: string }): this {
    this.options.keyMapping = mapping;
    return this;
  }

  async run(): Promise<any> {
    const exp = this.experiment;

    // Instructions
    const instructions = new Trial({
      stimuli: new Text({
        content: `${this.options.n}-Back Working Memory Task

You will see a sequence of letters.
Your task is to indicate whether the current letter matches
the one from ${this.options.n} positions back in the sequence.

${this.options.keyMapping.match.toUpperCase()} = Match (same as ${this.options.n} back)
${this.options.keyMapping.noMatch.toUpperCase()} = No Match (different from ${this.options.n} back)

For the first ${this.options.n} items, always press ${this.options.keyMapping.noMatch.toUpperCase()}.

Respond as quickly and accurately as possible.

Press SPACE to begin practice...`,
        fontSize: 18,
        position: 'center',
        lineHeight: 1.5
      }),
      response: new KeypressResponse({
        validKeys: ['space']
      })
    });

    await exp.run(instructions);

    // Practice trials
    if (this.options.practice > 0) {
      const practiceSequence = this.generateSequence(this.options.practice);
      const practiceTrials = this.createTrials(practiceSequence, 'practice');

      const practiceStart = new Trial({
        stimuli: new Text({
          content: `Practice: ${this.options.n}-Back

Remember:
- ${this.options.keyMapping.match.toUpperCase()} if the letter matches ${this.options.n} back
- ${this.options.keyMapping.noMatch.toUpperCase()} if it doesn't match

Press SPACE to start...`,
          fontSize: 20,
          position: 'center',
          lineHeight: 1.5
        }),
        response: new KeypressResponse({
          validKeys: ['space']
        })
      });

      await exp.run(practiceStart);

      // Run practice with feedback
      for (const trial of practiceTrials.trials) {
        const result = await exp.run(trial);
        if (this.options.feedback) {
          await exp.run(this.createFeedback(result.trials[0]));
        }
      }

      // Practice complete
      const practiceComplete = new Trial({
        stimuli: new Text({
          content: 'Practice complete!\n\nPress SPACE to begin the main task...',
          fontSize: 24,
          position: 'center'
        }),
        response: new KeypressResponse({
          validKeys: ['space']
        })
      });

      await exp.run(practiceComplete);
    }

    // Main trials
    const mainSequence = this.generateSequence(this.options.trials);
    const mainTrials = this.createTrials(mainSequence, 'main');

    const mainStart = new Trial({
      stimuli: new Text({
        content: `Main Task: ${this.options.n}-Back

${this.options.trials} trials

Press SPACE when ready...`,
        fontSize: 24,
        position: 'center'
      }),
      response: new KeypressResponse({
        validKeys: ['space']
      })
    });

    await exp.run(mainStart);

    const results = await exp.run(mainTrials);

    // Calculate n-back performance
    const analysis = this.analyzeResults(results.trials);

    // Show completion
    const completion = new Trial({
      stimuli: new Text({
        content: `${this.options.n}-Back Task Complete!

Overall Accuracy: ${analysis.accuracy.toFixed(1)}%
Hit Rate: ${analysis.hitRate.toFixed(1)}%
False Alarm Rate: ${analysis.falseAlarmRate.toFixed(1)}%
d' (sensitivity): ${analysis.dPrime.toFixed(2)}

Average RT: ${analysis.meanRT.toFixed(0)}ms

Thank you!`,
        fontSize: 20,
        position: 'center',
        lineHeight: 1.5
      }),
      response: new KeypressResponse({
        validKeys: ['space'],
        timeout: 10000
      })
    });

    await exp.run(completion);

    return {
      trials: results.trials,
      summary: analysis,
      nback: {
        n: this.options.n,
        dPrime: analysis.dPrime,
        hitRate: analysis.hitRate,
        falseAlarmRate: analysis.falseAlarmRate,
        accuracy: analysis.accuracy
      }
    };
  }

  private generateSequence(length: number): Array<{ stimulus: string; isTarget: boolean }> {
    const sequence: Array<{ stimulus: string; isTarget: boolean }> = [];
    const targetCount = Math.floor(length * this.options.targetRate);
    const targetPositions = new Set<number>();

    // Randomly select positions for targets (after n-back buffer)
    while (targetPositions.size < targetCount) {
      const pos = Math.floor(Math.random() * (length - this.options.n)) + this.options.n;
      targetPositions.add(pos);
    }

    // Generate sequence
    for (let i = 0; i < length; i++) {
      if (i < this.options.n) {
        // First n items can't be targets
        sequence.push({
          stimulus: this.randomStimulus(),
          isTarget: false
        });
      } else if (targetPositions.has(i)) {
        // This should be a target (match n-back)
        sequence.push({
          stimulus: sequence[i - this.options.n].stimulus,
          isTarget: true
        });
      } else {
        // This should not match n-back
        let stimulus: string;
        do {
          stimulus = this.randomStimulus();
        } while (stimulus === sequence[i - this.options.n].stimulus);

        sequence.push({
          stimulus,
          isTarget: false
        });
      }
    }

    return sequence;
  }

  private randomStimulus(): string {
    return this.options.stimuli[Math.floor(Math.random() * this.options.stimuli.length)];
  }

  private createTrials(sequence: Array<{ stimulus: string; isTarget: boolean }>, phase: string): TrialList {
    return new TrialList({
      trials: sequence.map((item, i) => new Trial({
        stimuli: [
          new FixationCross({ 
            duration: 250 
          }),
          new Text({
            content: item.stimulus,
            fontSize: 72,
            position: 'center',
            duration: this.options.stimulusDuration
          })
        ],
