        validKeys: [],
        timeout: 1000
      })
    });
  }

  private analyzeResults(trials: any[]) {
    const mainTrials = trials.filter(t => t.data.phase === 'main');
    const responded = mainTrials.filter(t => !t.timeout);

    // Overall accuracy
    const correct = responded.filter(t => t.correct);
    const accuracy = (correct.length / responded.length) * 100;
    const meanRT = correct.reduce((sum, t) => sum + t.rt, 0) / correct.length;

    // Signal detection theory metrics
    const targets = responded.filter(t => t.data.isTarget);
    const nonTargets = responded.filter(t => !t.data.isTarget);

    const hits = targets.filter(t => t.response === this.options.keyMapping.match);
    const misses = targets.filter(t => t.response === this.options.keyMapping.noMatch);
    const falseAlarms = nonTargets.filter(t => t.response === this.options.keyMapping.match);
    const correctRejections = nonTargets.filter(t => t.response === this.options.keyMapping.noMatch);

    const hitRate = targets.length > 0 ? hits.length / targets.length : 0;
    const falseAlarmRate = nonTargets.length > 0 ? falseAlarms.length / nonTargets.length : 0;

