        response: new KeypressResponse({
          validKeys: [this.options.keyMapping.match, this.options.keyMapping.noMatch],
          correct: item.isTarget ? this.options.keyMapping.match : this.options.keyMapping.noMatch,
          timeout: this.options.responseTimeout
        }),
        data: {
